          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          :title="`Add all ${(kanbanGroups[kanbanColMenu!.col] ?? []).length} card${(kanbanGroups[kanbanColMenu!.col] ?? []).length === 1 ? '' : 's'} in this column to selection`"
          @click="(() => { const ids = (kanbanGroups[kanbanColMenu!.col] ?? []).map(r => r.id); const next = new Set(selectedIds); ids.forEach(id => next.add(id)); selectedIds = next; kanbanColMenu = null; })() "
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
          </svg>
          Select all in column
        </button>
        <button
          v-if="kanbanField && kanbanColMenu!.col !== KANBAN_UNASSIGNED"
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          title="Filter view to records in this stage"
          @click="toggleFilter(kanbanField!.key, kanbanColMenu!.col); kanbanColMenu = null"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
          </svg>
          Filter to this stage
        </button>
        <!-- rename stage -->
        <template v-if="kanbanColMenu!.col !== KANBAN_UNASSIGNED">
          <template v-if="kanbanColRenaming">
            <div class="px-3 py-2 flex items-center gap-2">
              <input
                ref="kanbanColRenameInputEl"
                v-model="kanbanColRenameDraft"
                type="text"
                maxlength="60"
                class="flex-1 h-7 rounded-lg px-2 text-xs bg-slate-50 dark:bg-slate-800 border border-violet-400 dark:border-violet-600 text-slate-900 dark:text-slate-100 focus:outline-none"
                @keydown.enter.prevent="commitKanbanColRename"
                @keydown.escape.stop="kanbanColRenaming = false"
                @vue:mounted="($el as HTMLInputElement).select()"
              />
              <button type="button" class="shrink-0 h-6 px-2 rounded text-xs font-medium text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/30 hover:bg-sky-100 dark:hover:bg-sky-900/30 transition-colors" @click="commitKanbanColRename">Save</button>
            </div>
          </template>
          <template v-else>
            <button
              type="button"
              class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
              @click="kanbanColRenameDraft = kanbanColMenu!.col; kanbanColRenaming = true"
            >
              <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
              Rename stage
            </button>
          </template>
        </template>
        <!-- reorder stage left / right -->
        <template v-if="kanbanField && kanbanColMenu!.col !== KANBAN_UNASSIGNED">
          <button
            type="button"
            class="w-full flex items-center gap-2.5 px-3 py-2 text-sm transition-colors"
            :class="(kanbanField.select_options ?? []).indexOf(kanbanColMenu!.col) <= 0 ? 'text-slate-300 dark:text-slate-600 cursor-not-allowed' : 'text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800'"
            :disabled="(kanbanField.select_options ?? []).indexOf(kanbanColMenu!.col) <= 0"
            title="Move stage left (earlier in pipeline)"
            @click="(() => { if (!kanbanField) return; const opts = [...(kanbanField.select_options ?? [])]; const i = opts.indexOf(kanbanColMenu!.col); if (i <= 0) return; [opts[i-1], opts[i]] = [opts[i], opts[i-1]]; kanbanField.select_options = opts; showToast(`Stage moved left`); kanbanColMenu = null; })()"
          >
            <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M15 19l-7-7 7-7" /></svg>
            Move stage left
          </button>
          <button
            type="button"
            class="w-full flex items-center gap-2.5 px-3 py-2 text-sm transition-colors"
            :class="(kanbanField.select_options ?? []).indexOf(kanbanColMenu!.col) >= (kanbanField.select_options ?? []).length - 1 ? 'text-slate-300 dark:text-slate-600 cursor-not-allowed' : 'text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800'"
            :disabled="(kanbanField.select_options ?? []).indexOf(kanbanColMenu!.col) >= (kanbanField.select_options ?? []).length - 1"
            title="Move stage right (later in pipeline)"
            @click="(() => { if (!kanbanField) return; const opts = [...(kanbanField.select_options ?? [])]; const i = opts.indexOf(kanbanColMenu!.col); if (i >= opts.length - 1) return; [opts[i], opts[i+1]] = [opts[i+1], opts[i]]; kanbanField.select_options = opts; showToast(`Stage moved right`); kanbanColMenu = null; })()"
          >
            <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M9 5l7 7-7 7" /></svg>
            Move stage right
          </button>
        </template>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          :title="`Export ${(kanbanGroups[kanbanColMenu!.col] ?? []).length} record${(kanbanGroups[kanbanColMenu!.col] ?? []).length === 1 ? '' : 's'} in this column as CSV`"
          @click="exportCsv(kanbanGroups[kanbanColMenu!.col] ?? []); kanbanColMenu = null"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
          Export column as CSV
        </button>
        <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm transition-colors text-red-400 dark:text-red-500 hover:bg-red-50 dark:hover:bg-red-950/20 hover:text-red-600 dark:hover:text-red-400"
          @click="deleteGroupRecords(kanbanColMenu!.col === KANBAN_UNASSIGNED ? '__ungrouped__' : kanbanColMenu!.col); kanbanColMenu = null"
        >
          <svg class="h-3.5 w-3.5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
          Delete all in column
        </button>
      </div>
    </transition>

    <!-- table row context menu -->
    <transition
      enter-active-class="transition-all duration-100"
      enter-from-class="opacity-0 scale-95"
      enter-to-class="opacity-100 scale-100"
      leave-active-class="transition-all duration-75"
      leave-from-class="opacity-100 scale-100"
      leave-to-class="opacity-0 scale-95"
    >
      <div
        v-if="contextMenuRecord"
        class="fixed z-50 w-48 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-xl py-1"
        :style="{ top: `${contextMenuPos.y}px`, left: `${contextMenuPos.x}px` }"
        @click.stop
      >
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="openRecord(contextMenuRecord); closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
            <path stroke-linecap="round" stroke-linejoin="round" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
          </svg>
          Open
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="duplicateRecord(contextMenuRecord); closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
          </svg>
          Duplicate
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="copyRecordLink(contextMenuRecord); closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" />
          </svg>
          Copy link
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="(() => { quickNotePos = { top: contextMenuPos.y, left: Math.min(contextMenuPos.x, window.innerWidth - 300) }; quickNoteRecordId = contextMenuRecord!.id; closeContextMenu(); })()"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
          </svg>
          Log note
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="copyRecordAsText(contextMenuRecord); closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <rect x="9" y="9" width="13" height="13" rx="2" ry="2" stroke-linecap="round" stroke-linejoin="round" />
            <path stroke-linecap="round" stroke-linejoin="round" d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1" />
          </svg>
          Copy as text
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="openRecord(contextMenuRecord); nextTick(() => { detailTab = 'tasks'; }); closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" />
          </svg>
          Add task
        </button>
        <!-- move to stage — shown only when kanban field exists and there are other stages -->
        <template v-if="kanbanField && kanbanColumns.filter(c => c !== KANBAN_UNASSIGNED).length > 1">
          <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
          <p class="px-3 pt-1.5 pb-0.5 text-xs font-semibold uppercase tracking-wider text-slate-400 dark:text-slate-500">Move to stage</p>
          <button
            v-for="stage in kanbanColumns.filter(c => c !== KANBAN_UNASSIGNED && c !== String(contextMenuRecord.field_values[kanbanField!.key] ?? ''))"
            :key="stage"
            type="button"
            class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
            @click="(() => { if (kanbanField) { contextMenuRecord.field_values[kanbanField.key] = stage; showToast(`Stage: ${stage}`); } closeContextMenu(); })()"
          >
            <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M9 5l7 7-7 7" /></svg>
            {{ stage }}
          </button>
          <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
        </template>
        <button
          v-if="openedRecord && openedRecord.id !== contextMenuRecord.id"
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="openMergeModal(openedRecord!.id, contextMenuRecord.id); closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0z" />
          </svg>
          Merge into open record
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="mergeTargetPicker = { source: contextMenuRecord }; mergeTargetQuery = ''; closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
          </svg>
          Merge with...
        </button>
        <!-- convert type — only show when multiple record types exist -->
        <template v-if="schema.length > 1">
          <button
            type="button"
            class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
            @click="convertModal = { record: contextMenuRecord }; convertTargetTypeKey = schema.find(t => t.key !== contextMenuRecord.record_type_key)?.key ?? ''; closeContextMenu()"
          >
            <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
              <path stroke-linecap="round" stroke-linejoin="round" d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" />
            </svg>
            Convert to...
          </button>
        </template>
        <!-- compare with another record -->
        <template v-if="selectedIds.size === 2 && selectedIds.has(contextMenuRecord.id)">
          <button
            type="button"
            class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-violet-600 dark:text-violet-400 hover:bg-violet-50 dark:hover:bg-violet-950/20 transition-colors"
            @click="(() => { const other = filteredRecords.find(r => r.id !== contextMenuRecord.id && selectedIds.has(r.id)); if (other) { compareModal = { recordA: contextMenuRecord, recordB: other }; } closeContextMenu(); })()"
          >
            <svg class="h-3.5 w-3.5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
              <path stroke-linecap="round" stroke-linejoin="round" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h5.586a1 1 0 00.707-.293l5.414-5.414a1 1 0 00.293-.707V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
            </svg>
            Compare selected
          </button>
        </template>
        <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="archivedIds.has(contextMenuRecord.id) ? unarchiveRecord(contextMenuRecord.id) : archiveRecord(contextMenuRecord.id); closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8l1 12a2 2 0 002 2h8a2 2 0 002-2L19 8" />
          </svg>
          {{ archivedIds.has(contextMenuRecord.id) ? 'Unarchive' : 'Archive' }}
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="togglePin(contextMenuRecord.id); closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 shrink-0" :class="pinnedIds.has(contextMenuRecord.id) ? 'text-amber-500' : 'text-slate-400'" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z" />
          </svg>
          {{ pinnedIds.has(contextMenuRecord.id) ? 'Unpin' : 'Pin' }}
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="toggleWatch(contextMenuRecord.id); closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 shrink-0" :class="watchedIds.has(contextMenuRecord.id) ? 'text-sky-500' : 'text-slate-400'" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
            <path stroke-linecap="round" stroke-linejoin="round" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
          </svg>
          {{ watchedIds.has(contextMenuRecord.id) ? 'Unwatch' : 'Watch' }}
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="toggleRecordLock(contextMenuRecord.id); closeContextMenu()"
        >
          <svg class="h-3.5 w-3.5 shrink-0" :class="lockedRecordIds.has(contextMenuRecord.id) ? 'text-orange-500' : 'text-slate-400'" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
          </svg>
          {{ lockedRecordIds.has(contextMenuRecord.id) ? 'Unlock' : 'Lock' }}
        </button>
        <template v-if="contextMenuSelectFilters.length">
          <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
          <p class="px-3 pt-1.5 pb-0.5 text-xs font-semibold uppercase tracking-wider text-slate-400 dark:text-slate-500">Filter by</p>
          <button
            v-for="opt in contextMenuSelectFilters"
            :key="opt.fieldKey + ':' + opt.value"
            type="button"
            class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
            @click="toggleFilter(opt.fieldKey, opt.value); closeContextMenu()"
          >
            <svg
              v-if="activeFilters.some(f => f.fieldKey === opt.fieldKey && f.value === opt.value)"
              class="h-3.5 w-3.5 text-sky-500 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"
            >
              <path stroke-linecap="round" stroke-linejoin="round" d="M5 13l4 4L19 7" />
            </svg>
            <svg v-else class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
              <path stroke-linecap="round" stroke-linejoin="round" d="M3 4h18M7 9h10M11 14h2" />
            </svg>
            <span class="truncate"><span class="text-slate-400 dark:text-slate-500">{{ opt.label }}:</span> {{ opt.value }}</span>
          </button>
        </template>
        <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
        <div class="px-3 pt-1.5 pb-2">
          <p class="pb-1.5 text-xs font-semibold uppercase tracking-wider text-slate-400 dark:text-slate-500">Set reminder</p>
          <div class="flex items-center gap-1 flex-wrap">
            <button
              v-for="preset in [{ days: 1, label: '+1d' }, { days: 3, label: '+3d' }, { days: 7, label: '+1w' }, { days: 14, label: '+2w' }]"
              :key="preset.days"
              type="button"
              class="h-5 px-1.5 rounded text-[10px] font-medium transition-colors"
              :class="reminders[contextMenuRecord.id]?.date === dateOffset(preset.days)
                ? 'bg-amber-400 dark:bg-amber-500 text-white'
                : 'bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 hover:bg-amber-50 dark:hover:bg-amber-900/20 hover:text-amber-600 dark:hover:text-amber-400'"
              :title="`Remind in ${preset.days === 1 ? '1 day' : preset.days === 3 ? '3 days' : preset.days === 7 ? '1 week' : '2 weeks'}`"
              @click="reminders = { ...reminders, [contextMenuRecord.id]: { date: dateOffset(preset.days), note: '' } }; showToast(`Reminder set for ${dateOffset(preset.days)}`); closeContextMenu()"
            >{{ preset.label }}</button>
            <button
              v-if="reminders[contextMenuRecord.id]?.date"
              type="button"
              class="h-5 px-1.5 rounded text-[10px] font-medium bg-slate-100 dark:bg-slate-800 text-rose-400 dark:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-950/20 transition-colors"
              title="Clear reminder"
              @click="(() => { const r = { ...reminders }; delete r[contextMenuRecord.id]; reminders = r; showToast('Reminder cleared'); closeContextMenu(); })()"
            >Clear</button>
          </div>
        </div>
        <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
        <div class="px-3 pt-1.5 pb-2">
          <p class="pb-1.5 text-xs font-semibold uppercase tracking-wider text-slate-400 dark:text-slate-500">Color label</p>
          <div class="flex items-center gap-1.5">
            <button
              v-for="c in COLOR_LABEL_PALETTE"
              :key="c"
              type="button"
              class="h-4 w-4 rounded-full transition-transform hover:scale-125 focus:outline-none"
              :style="{ background: c, boxShadow: colorLabels[contextMenuRecord.id] === c ? `0 0 0 2px white, 0 0 0 3.5px ${c}` : 'none' }"
              @click="setColorLabel(contextMenuRecord.id, colorLabels[contextMenuRecord.id] === c ? '' : c)"
            />
            <button
              v-if="colorLabels[contextMenuRecord.id]"
              type="button"
              class="ml-1 h-4 w-4 rounded-full flex items-center justify-center text-slate-400 border border-slate-300 dark:border-slate-600 hover:text-slate-600 transition-colors"
              title="Clear label"
              @click="setColorLabel(contextMenuRecord.id, '')"
            >
              <svg class="h-2.5 w-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="3"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
        </div>
        <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm transition-colors text-red-400 dark:text-red-500 hover:bg-red-50 dark:hover:bg-red-950/20 hover:text-red-600 dark:hover:text-red-400"
          @click="deleteRecord(contextMenuRecord)"
        >
          <svg class="h-3.5 w-3.5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
          </svg>
          Delete
        </button>
      </div>
    </transition>

    <!-- cell context menu -->
    <transition enter-active-class="transition-all duration-100" enter-from-class="opacity-0 scale-95" enter-to-class="opacity-100 scale-100" leave-active-class="transition-all duration-75" leave-from-class="opacity-100 scale-100" leave-to-class="opacity-0 scale-95">
      <div
        v-if="cellContextMenu"
        class="fixed z-50 w-52 rounded-xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 shadow-xl overflow-hidden py-1"
        :style="{ top: `${cellContextMenu.y}px`, left: `${cellContextMenu.x}px` }"
        @click.stop
      >
        <p class="px-3 pt-2 pb-1 text-[10px] font-semibold uppercase tracking-wider text-slate-400 dark:text-slate-500 truncate">{{ cellContextMenu.col.label }}</p>
        <!-- copy value -->
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-left text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="copyFieldValue(cellContextMenu!.record.field_values[cellContextMenu!.col.key]); cellContextMenu = null"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
          Copy value
        </button>
        <!-- edit -->
        <button
          v-if="cellContextMenu.col.data_type !== 'formula' && !cellContextMenu.col.is_required"
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-left text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="startCellEdit(cellContextMenu!.record, cellContextMenu!.col); cellContextMenu = null"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
          Edit
        </button>
        <!-- filter by value (select fields) -->
        <button
          v-if="(cellContextMenu.col.data_type === 'select' || cellContextMenu.col.data_type === 'multi_select') && cellContextMenu.record.field_values[cellContextMenu.col.key]"
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-left text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="toggleFilter(cellContextMenu!.col.key, String(cellContextMenu!.record.field_values[cellContextMenu!.col.key])); cellContextMenu = null"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M3 4h18M7 9h10M11 14h2" /></svg>
          Filter by this value
        </button>
        <!-- copy row + group/hide -->
        <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-left text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="copyRecordAsText(cellContextMenu!.record); cellContextMenu = null"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
          Copy row as text
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-left text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="groupByField = groupByField === cellContextMenu!.col.key ? null : cellContextMenu!.col.key; cellContextMenu = null"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
          {{ groupByField === cellContextMenu?.col.key ? 'Clear grouping' : 'Group by this field' }}
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-left text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="toggleColumnVisibility(cellContextMenu!.col.key); cellContextMenu = null"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" /></svg>
          Hide this column
        </button>
        <!-- sort -->
        <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-left text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="sortField = cellContextMenu!.col.key; sortDir = 'asc'; cellContextMenu = null"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M3 4h13M3 8h9m-9 4h9m5-4v12m0 0l-4-4m4 4l4-4" /></svg>
          Sort A → Z
        </button>
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-left text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="sortField = cellContextMenu!.col.key; sortDir = 'desc'; cellContextMenu = null"
        >
          <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M3 4h13M3 8h9m-9 4h6m4 0l4-4m-4 4l-4-4" /></svg>
          Sort Z → A
        </button>
        <!-- clear -->
        <div v-if="cellContextMenu.record.field_values[cellContextMenu.col.key] != null" class="my-1 border-t border-slate-100 dark:border-slate-800" />
        <button
          v-if="cellContextMenu.record.field_values[cellContextMenu.col.key] != null"
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-left text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-950/20 transition-colors"
          @click="(() => { const rec = cellContextMenu!.record; const key = cellContextMenu!.col.key; const prev = rec.field_values[key]; rec.field_values[key] = null; cellContextMenu = null; showToast('Value cleared', { label: 'Undo', fn: () => { rec.field_values[key] = prev; } }); })()"
        >
          <svg class="h-3.5 w-3.5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
          Clear value
        </button>
      </div>
    </transition>

    <!-- conditional formatting panel -->
    <transition enter-active-class="transition-all duration-150" enter-from-class="opacity-0" enter-to-class="opacity-100" leave-active-class="transition-all duration-100" leave-from-class="opacity-100" leave-to-class="opacity-0">
      <div v-if="showFormatPanel" class="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm" @click.self="showFormatPanel = false">
        <div class="w-full max-w-xl rounded-2xl bg-white dark:bg-slate-900 shadow-2xl border border-slate-200 dark:border-slate-700 overflow-hidden flex flex-col max-h-[80vh]">
          <div class="flex items-center justify-between px-6 py-4 border-b border-slate-100 dark:border-slate-800">
            <div>
              <h3 class="text-base font-semibold text-slate-900 dark:text-white">Conditional row formatting</h3>
              <p class="text-xs text-slate-400 dark:text-slate-500 mt-0.5">Highlight rows automatically based on field values</p>
            </div>
            <button type="button" class="rounded-lg p-1.5 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showFormatPanel = false">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <div class="flex-1 overflow-auto p-6 space-y-3">
            <div
              v-for="(rule, ri) in conditionalRules"
              :key="rule.id"
              class="flex items-center gap-2 p-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50"
            >
              <span class="h-3.5 w-3.5 rounded-full shrink-0 border border-white/40 shadow-sm" :style="{ background: rule.color }" />
              <select v-model="rule.fieldKey" class="flex-1 h-7 rounded-lg px-2 text-xs bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-800 dark:text-slate-200 focus:outline-none focus:ring-1 focus:ring-purple-400">
                <option v-for="f in selectedType?.fields ?? []" :key="f.key" :value="f.key">{{ f.label }}</option>
              </select>
              <select v-model="rule.operator" class="w-32 h-7 rounded-lg px-2 text-xs bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-800 dark:text-slate-200 focus:outline-none focus:ring-1 focus:ring-purple-400">
                <option value="equals">equals</option>
                <option value="not_equals">not equals</option>
                <option value="contains">contains</option>
                <option value="gt">greater than</option>
                <option value="lt">less than</option>
                <option value="is_empty">is empty</option>
                <option value="is_not_empty">is not empty</option>
              </select>
              <template v-if="!['is_empty', 'is_not_empty'].includes(rule.operator)">
                <select
                  v-if="['equals', 'not_equals', 'contains'].includes(rule.operator) && (selectedType?.fields ?? []).find(f => f.key === rule.fieldKey)?.data_type === 'select'"
                  v-model="rule.value"
                  class="w-24 h-7 rounded-lg px-2 text-xs bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-800 dark:text-slate-200 focus:outline-none focus:ring-1 focus:ring-purple-400"
                >
                  <option value="">— any —</option>
                  <option v-for="opt in (selectedType?.fields ?? []).find(f => f.key === rule.fieldKey)?.select_options ?? []" :key="opt" :value="opt">{{ opt }}</option>
                </select>
                <input
                  v-else
                  v-model="rule.value"
                  type="text"
                  placeholder="value"
                  class="w-24 h-7 rounded-lg px-2 text-xs bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-800 dark:text-slate-200 placeholder-slate-400 focus:outline-none focus:ring-1 focus:ring-purple-400"
                >
              </template>
              <span v-else class="w-24" />
              <div class="flex items-center gap-0.5">
                <button
                  v-for="c in COLOR_LABEL_PALETTE"
                  :key="c"
                  type="button"
                  class="h-4 w-4 rounded-full transition-transform hover:scale-125"
                  :style="{ background: c, boxShadow: rule.color === c ? `0 0 0 1.5px white, 0 0 0 3px ${c}` : 'none' }"
                  @click="rule.color = c"
                />
              </div>
              <button type="button" class="h-6 w-6 rounded text-slate-400 hover:text-red-400 hover:bg-red-50 dark:hover:bg-red-950/20 transition-colors flex items-center justify-center shrink-0" @click="conditionalRules.splice(ri, 1)">
                <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <div v-if="!conditionalRules.length" class="text-center py-6 text-sm text-slate-400 dark:text-slate-500">
              No formatting rules yet. Add one below.
            </div>
          </div>
          <div class="px-6 py-4 border-t border-slate-100 dark:border-slate-800 flex items-center justify-between">
            <button
              type="button"
              class="flex items-center gap-1.5 h-8 px-3 rounded-lg text-sm font-medium text-purple-600 dark:text-purple-400 bg-purple-50 dark:bg-purple-950/30 hover:bg-purple-100 dark:hover:bg-purple-900/30 transition-colors"
              @click="conditionalRules.push({ id: String(Date.now()), fieldKey: selectedType?.fields[0]?.key ?? '', operator: 'equals', value: '', color: COLOR_LABEL_PALETTE[0] })"
            >
              <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4" /></svg>
              Add rule
            </button>
            <button type="button" class="h-8 px-4 rounded-xl text-sm font-medium text-white bg-purple-500 hover:bg-purple-600 transition-colors" @click="showFormatPanel = false">Done</button>
          </div>
        </div>
      </div>
    </transition>

    <!-- @mention peek card -->
    <Teleport to="body">
      <transition enter-active-class="transition-all duration-150" enter-from-class="opacity-0 scale-95" enter-to-class="opacity-100 scale-100" leave-active-class="transition-all duration-100" leave-from-class="opacity-100 scale-100" leave-to-class="opacity-0 scale-95">
        <div
          v-if="peekRecord"
          class="fixed z-[9999] w-64 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-2xl overflow-hidden pointer-events-auto"
          :style="peekAnchorEl ? { top: `${Math.min(peekAnchorEl.getBoundingClientRect().bottom + 6, window.innerHeight - 240)}px`, left: `${Math.max(4, Math.min(peekAnchorEl.getBoundingClientRect().left, window.innerWidth - 268))}px` } : {}"
          @mouseenter="peekCardHovered = true"
          @mouseleave="peekCardHovered = false; peekRecord = null"
        >
          <!-- header -->
          <div class="px-3 pt-3 pb-2 border-b border-slate-100 dark:border-slate-800 flex items-center gap-2">
            <span
              class="h-7 w-7 rounded-lg flex items-center justify-center shrink-0 text-white text-xs font-bold"
              :style="{ background: schema.find(s => s.key === peekRecord.record_type_key)?.color ?? '#6366f1' }"
            >{{ recordInitials(peekRecord.title) }}</span>
            <div class="flex-1 min-w-0">
              <p class="text-sm font-semibold text-slate-900 dark:text-white truncate">{{ peekRecord.title }}</p>
              <p class="text-xs text-slate-400 dark:text-slate-500 capitalize">{{ schema.find(s => s.key === peekRecord.record_type_key)?.label }}</p>
            </div>
          </div>
          <!-- key fields -->
          <div class="px-3 py-2 space-y-1">
            <div
              v-for="field in (schema.find(s => s.key === peekRecord.record_type_key)?.fields ?? []).filter(f => !f.is_title && peekRecord.field_values[f.key] && f.data_type !== 'formula').slice(0, 4)"
              :key="field.key"
              class="flex items-center gap-2"
            >
              <span class="text-[10px] text-slate-400 dark:text-slate-500 w-20 shrink-0 truncate">{{ field.label }}</span>
              <span class="text-xs text-slate-700 dark:text-slate-300 truncate">{{ String(peekRecord.field_values[field.key] ?? '') }}</span>
            </div>
          </div>
          <!-- activity count -->
          <div class="px-3 py-2 border-t border-slate-100 dark:border-slate-800 flex items-center justify-between">
            <span class="text-[10px] text-slate-400 dark:text-slate-500">{{ mockActivities.filter(a => a.record_id === peekRecord.id).length }} activit{{ mockActivities.filter(a => a.record_id === peekRecord.id).length === 1 ? 'y' : 'ies' }}</span>
            <button
              type="button"
              class="text-[10px] font-medium text-sky-500 hover:text-sky-600 dark:text-sky-400 transition-colors"
              @click="openRecord(peekRecord); peekRecord = null"
            >Open record</button>
          </div>
        </div>
      </transition>
    </Teleport>

    <!-- Scoring rules modal -->
    <transition enter-active-class="transition-all duration-200" enter-from-class="opacity-0" enter-to-class="opacity-100" leave-active-class="transition-all duration-150" leave-from-class="opacity-100" leave-to-class="opacity-0">
      <div v-if="showScoringModal" class="fixed inset-0 z-50 flex items-center justify-center p-4" @click.self="showScoringModal = false">
        <div class="relative bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 w-full max-w-xl max-h-[82vh] flex flex-col" @click.stop>
          <!-- header -->
          <div class="flex items-center justify-between px-6 py-4 border-b border-slate-200 dark:border-slate-700">
            <div class="flex items-center gap-2">
              <svg class="h-5 w-5 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="1.75">
                <path stroke-linecap="round" stroke-linejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
              <div>
                <h2 class="text-base font-semibold text-slate-900 dark:text-white">Scoring rules</h2>
                <p class="text-xs text-slate-400 dark:text-slate-500 mt-0.5">{{ selectedType?.label_plural }} · {{ scoringRulesForType.length }} rule{{ scoringRulesForType.length === 1 ? '' : 's' }} · scores 0–100</p>
              </div>
            </div>
            <button type="button" class="h-8 w-8 rounded-lg flex items-center justify-center text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showScoringModal = false">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <!-- rules list -->
          <div class="flex-1 overflow-y-auto divide-y divide-slate-100 dark:divide-slate-800">
            <div v-if="!scoringRulesForType.length" class="px-6 py-8 text-center text-sm text-slate-400 dark:text-slate-500">
              No scoring rules yet. Add one below to start scoring {{ selectedType?.label_plural }}.
            </div>
            <div v-for="rule in scoringRulesForType" :key="rule.id" class="group/srule px-6 py-3">
              <!-- inline edit form -->
              <template v-if="editingScoringRuleId === rule.id">
                <div class="space-y-2">
                  <div class="grid grid-cols-2 gap-2">
                    <div class="col-span-2">
                      <label class="block text-xs text-slate-500 dark:text-slate-400 mb-1">Condition</label>
                      <select v-model="editingScoringCondition" class="w-full text-sm px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-emerald-400/50">
                        <option value="field_filled">Field is filled</option>
                        <option value="field_eq">Field equals value</option>
                        <option value="field_contains">Field contains text</option>
                        <option value="field_gt">Field is greater than (number)</option>
                        <option value="field_lt">Field is less than (number)</option>
                        <option value="stage_is">Stage is</option>
                        <option value="activity_within_days">Activity within N days</option>
                      </select>
                    </div>
                    <div v-if="editingScoringCondition !== 'activity_within_days' && editingScoringCondition !== 'stage_is'">
                      <label class="block text-xs text-slate-500 dark:text-slate-400 mb-1">Field</label>
                      <select v-model="editingScoringFieldKey" class="w-full text-sm px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-emerald-400/50">
                        <option v-for="col in allColumns.filter(c => c.data_type !== 'formula')" :key="col.key" :value="col.key">{{ col.label }}</option>
                      </select>
                    </div>
                    <div v-if="editingScoringCondition !== 'field_filled'">
                      <label class="block text-xs text-slate-500 dark:text-slate-400 mb-1">
                        <template v-if="editingScoringCondition === 'activity_within_days'">Days</template>
                        <template v-else-if="editingScoringCondition === 'stage_is'">Stage</template>
                        <template v-else>Value</template>
                      </label>
                      <select
                        v-if="editingScoringCondition === 'stage_is' && kanbanField?.select_options?.length"
                        v-model="editingScoringValue"
                        class="w-full text-sm px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-emerald-400/50"
                      >
                        <option value="">— pick stage —</option>
                        <option v-for="opt in kanbanField.select_options" :key="opt" :value="opt">{{ opt }}</option>
                      </select>
                      <select
                        v-else-if="editingScoringCondition === 'field_eq' && allColumns.find(c => c.key === editingScoringFieldKey)?.data_type === 'select'"
                        v-model="editingScoringValue"
                        class="w-full text-sm px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-emerald-400/50"
                      >
                        <option value="">— pick option —</option>
                        <option v-for="opt in allColumns.find(c => c.key === editingScoringFieldKey)?.select_options ?? []" :key="opt" :value="opt">{{ opt }}</option>
                      </select>
                      <input
                        v-else
                        v-model="editingScoringValue"
                        :type="editingScoringCondition === 'activity_within_days' || editingScoringCondition === 'field_gt' || editingScoringCondition === 'field_lt' ? 'number' : 'text'"
                        class="w-full text-sm px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-emerald-400/50"
                      />
                    </div>
                    <div>
                      <label class="block text-xs text-slate-500 dark:text-slate-400 mb-1">Points (1–100)</label>
                      <input
                        v-model="editingScoringPoints"
                        type="number"
                        min="1"
                        max="100"
                        class="w-full text-sm px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-emerald-400/50"
                        @keydown.enter.prevent="commitEditScoringRule"
                        @keydown.esc.stop="editingScoringRuleId = null"
                      />
                    </div>
                  </div>
                  <div class="flex items-center justify-end gap-2 pt-0.5">
                    <button type="button" class="px-3 py-1 text-xs rounded-lg border border-slate-200 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors" @click="editingScoringRuleId = null">Cancel</button>
                    <button type="button" class="px-3 py-1 text-xs rounded-lg bg-emerald-600 hover:bg-emerald-500 text-white transition-colors" @click="commitEditScoringRule">Save</button>
                  </div>
                </div>
              </template>
              <!-- display mode -->
              <template v-else>
                <div class="flex items-center gap-3">
                  <div class="flex-1 min-w-0">
                    <p class="text-sm text-slate-800 dark:text-slate-200 truncate">
                      <template v-if="rule.condition === 'field_filled'">
                        <span class="font-medium">{{ allColumns.find(c => c.key === rule.fieldKey)?.label ?? rule.fieldKey }}</span>
                        <span class="text-slate-400 dark:text-slate-500"> is filled</span>
                      </template>
                      <template v-else-if="rule.condition === 'field_eq'">
                        <span class="font-medium">{{ allColumns.find(c => c.key === rule.fieldKey)?.label ?? rule.fieldKey }}</span>
                        <span class="text-slate-400 dark:text-slate-500"> equals </span>
                        <span class="font-medium">{{ rule.value }}</span>
                      </template>
                      <template v-else-if="rule.condition === 'field_contains'">
                        <span class="font-medium">{{ allColumns.find(c => c.key === rule.fieldKey)?.label ?? rule.fieldKey }}</span>
                        <span class="text-slate-400 dark:text-slate-500"> contains </span>
                        <span class="font-medium">{{ rule.value }}</span>
                      </template>
                      <template v-else-if="rule.condition === 'field_gt'">
                        <span class="font-medium">{{ allColumns.find(c => c.key === rule.fieldKey)?.label ?? rule.fieldKey }}</span>
                        <span class="text-slate-400 dark:text-slate-500"> &gt; </span>
                        <span class="font-medium">{{ rule.value }}</span>
                      </template>
                      <template v-else-if="rule.condition === 'field_lt'">
                        <span class="font-medium">{{ allColumns.find(c => c.key === rule.fieldKey)?.label ?? rule.fieldKey }}</span>
                        <span class="text-slate-400 dark:text-slate-500"> &lt; </span>
                        <span class="font-medium">{{ rule.value }}</span>
                      </template>
                      <template v-else-if="rule.condition === 'stage_is'">
                        <span class="text-slate-400 dark:text-slate-500">Stage is </span>
                        <span class="font-medium">{{ rule.value }}</span>
                      </template>
                      <template v-else-if="rule.condition === 'activity_within_days'">
                        <span class="text-slate-400 dark:text-slate-500">Activity within </span>
                        <span class="font-medium">{{ rule.value }} day{{ rule.value === '1' ? '' : 's' }}</span>
                      </template>
                    </p>
                  </div>
                  <span class="shrink-0 inline-flex items-center gap-0.5 rounded-full px-2 py-0.5 text-xs font-semibold bg-emerald-50 dark:bg-emerald-950/30 text-emerald-600 dark:text-emerald-400">+{{ rule.points }} pts</span>
                  <button
                    type="button"
                    class="shrink-0 h-6 w-6 rounded flex items-center justify-center text-slate-300 dark:text-slate-600 hover:text-sky-500 dark:hover:text-sky-400 opacity-0 group-hover/srule:opacity-100 transition-all"
                    title="Edit rule"
                    @click="startEditScoringRule(rule)"
                  >
                    <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                  </button>
                  <button
                    type="button"
                    class="shrink-0 h-6 w-6 rounded flex items-center justify-center text-slate-300 dark:text-slate-600 hover:text-violet-500 dark:hover:text-violet-400 opacity-0 group-hover/srule:opacity-100 transition-all"
                    title="Duplicate rule"
                    @click="(() => { const copy = { ...JSON.parse(JSON.stringify(rule)), id: 'sr_' + String(Date.now()).slice(-6) }; scoringRules.push(copy); showToast('Rule duplicated'); })()"
                  >
                    <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                  </button>
                  <button type="button" class="shrink-0 h-6 w-6 rounded flex items-center justify-center text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 opacity-0 group-hover/srule:opacity-100 transition-all" title="Delete rule" @click="deleteScoringRule(rule.id)">
                    <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
                </div>
              </template>
            </div>
          </div>
          <!-- add rule form -->
          <div class="border-t border-slate-200 dark:border-slate-700 px-6 py-4 space-y-3 bg-slate-50 dark:bg-slate-950/50 rounded-b-2xl">
            <p class="text-xs font-semibold uppercase tracking-wide text-slate-400 dark:text-slate-500">Add rule</p>
            <div class="grid grid-cols-2 gap-2">
              <div class="col-span-2">
                <label class="block text-xs text-slate-500 dark:text-slate-400 mb-1">Condition</label>
                <select v-model="scoringDraftCondition" class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-emerald-400/50">
                  <option value="field_filled">Field is filled</option>
                  <option value="field_eq">Field equals value</option>
                  <option value="field_contains">Field contains text</option>
                  <option value="field_gt">Field is greater than (number)</option>
                  <option value="field_lt">Field is less than (number)</option>
                  <option value="stage_is">Stage is</option>
                  <option value="activity_within_days">Activity within N days</option>
                </select>
              </div>
              <div v-if="scoringDraftCondition !== 'activity_within_days' && scoringDraftCondition !== 'stage_is'">
                <label class="block text-xs text-slate-500 dark:text-slate-400 mb-1">Field</label>
                <select v-model="scoringDraftFieldKey" class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-emerald-400/50">
                  <option v-for="col in allColumns.filter(c => c.data_type !== 'formula')" :key="col.key" :value="col.key">{{ col.label }}</option>
                </select>
              </div>
              <div v-if="scoringDraftCondition !== 'field_filled'">
                <label class="block text-xs text-slate-500 dark:text-slate-400 mb-1">
                  <template v-if="scoringDraftCondition === 'activity_within_days'">Days</template>
                  <template v-else-if="scoringDraftCondition === 'stage_is'">Stage</template>
                  <template v-else>Value</template>
                </label>
                <!-- stage_is: show kanban stages -->
                <select
                  v-if="scoringDraftCondition === 'stage_is' && kanbanField?.select_options?.length"
                  v-model="scoringDraftValue"
                  class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-emerald-400/50"
                >
                  <option value="">— pick stage —</option>
                  <option v-for="opt in kanbanField.select_options" :key="opt" :value="opt">{{ opt }}</option>
                </select>
                <!-- field_eq on a select field: show the field's options -->
                <select
                  v-else-if="scoringDraftCondition === 'field_eq' && allColumns.find(c => c.key === scoringDraftFieldKey)?.data_type === 'select'"
                  v-model="scoringDraftValue"
                  class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-emerald-400/50"
                >
                  <option value="">— pick option —</option>
                  <option v-for="opt in allColumns.find(c => c.key === scoringDraftFieldKey)?.select_options ?? []" :key="opt" :value="opt">{{ opt }}</option>
                </select>
                <input
                  v-else
                  v-model="scoringDraftValue"
                  :type="scoringDraftCondition === 'activity_within_days' || scoringDraftCondition === 'field_gt' || scoringDraftCondition === 'field_lt' ? 'number' : 'text'"
                  :placeholder="scoringDraftCondition === 'activity_within_days' ? 'e.g. 14' : 'value…'"
                  class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white placeholder-slate-300 dark:placeholder-slate-600 focus:outline-none focus:ring-2 focus:ring-emerald-400/50"
                />
              </div>
              <div>
                <label class="block text-xs text-slate-500 dark:text-slate-400 mb-1">Points (1–100)</label>
                <input
                  v-model="scoringDraftPoints"
                  type="number"
                  min="1"
                  max="100"
                  placeholder="10"
                  class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white placeholder-slate-300 dark:placeholder-slate-600 focus:outline-none focus:ring-2 focus:ring-emerald-400/50"
                />
              </div>
            </div>
            <button
              type="button"
              class="w-full h-9 rounded-lg text-sm font-medium text-white bg-emerald-600 hover:bg-emerald-500 transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
              :disabled="!scoringDraftPoints || parseInt(scoringDraftPoints) <= 0"
              @click="addScoringRule"
            >Add rule</button>
          </div>
        </div>
      </div>
    </transition>

    <!-- Upcoming Scheduled Activities panel -->
    <transition enter-active-class="transition-all duration-200" enter-from-class="opacity-0 scale-95" enter-to-class="opacity-100 scale-100" leave-active-class="transition-all duration-150" leave-from-class="opacity-100 scale-100" leave-to-class="opacity-0 scale-95">
      <div v-if="showUpcomingPanel" class="fixed inset-0 z-50 flex items-center justify-center p-4" @click.self="showUpcomingPanel = false">
        <div class="relative bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 w-full max-w-lg max-h-[80vh] flex flex-col" @click.stop>
          <!-- header -->
          <div class="flex items-center justify-between px-6 py-4 border-b border-slate-200 dark:border-slate-700">
            <div class="flex items-center gap-2">
              <svg class="h-5 w-5 text-sky-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="1.75">
                <path stroke-linecap="round" stroke-linejoin="round" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
              <h3 class="text-base font-semibold text-slate-900 dark:text-white">Upcoming Activities</h3>
              <span class="text-xs text-slate-400 dark:text-slate-500">
                <template v-if="upcomingActivities.length">— {{ upcomingActivities.length }} scheduled</template>
                <template v-else>— nothing scheduled</template>
              </span>
            </div>
            <button type="button" class="h-8 w-8 rounded-lg flex items-center justify-center text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showUpcomingPanel = false">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <!-- list -->
          <div class="flex-1 overflow-y-auto px-6 py-4">
            <p v-if="!upcomingActivities.length" class="text-sm text-slate-400 dark:text-slate-500 text-center py-6">No upcoming calls or meetings scheduled.</p>
            <template v-else>
              <template v-for="grp in upcomingGroups" :key="grp.label">
                <p class="text-xs font-semibold uppercase tracking-widest text-slate-400 dark:text-slate-500 pt-3 first:pt-0 pb-1">{{ grp.label }}</p>
                <div
                  v-for="act in grp.acts"
                  :key="act.id"
                  class="group/ua flex items-start gap-3 py-2.5 border-b border-slate-50 dark:border-slate-800/60 last:border-0"
                >
                  <!-- type icon -->
                  <span
                    class="mt-0.5 h-7 w-7 rounded-full flex items-center justify-center shrink-0"
                    :class="ACTIVITY_ICON_BG[act.type]"
                  >
                    <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="1.75">
                      <path stroke-linecap="round" stroke-linejoin="round" :d="ACTIVITY_ICONS[act.type]" />
                    </svg>
                  </span>
                  <!-- content -->
                  <div class="flex-1 min-w-0">
                    <div class="flex items-center gap-1.5 mb-0.5 flex-wrap">
                      <button
                        type="button"
                        class="text-xs font-semibold text-sky-600 dark:text-sky-400 hover:underline truncate text-left"
                        @click="(() => { const rec = mockRecords.find(r => r.id === act.record_id); if (rec) { openRecord(rec); nextTick(() => { detailTab = 'activity'; }); showUpcomingPanel = false; } })()"
                      >{{ mockRecords.find(r => r.id === act.record_id)?.title ?? act.record_id }}</button>
                      <span class="text-[10px] tabular-nums font-medium text-violet-600 dark:text-violet-400 bg-violet-50 dark:bg-violet-900/30 rounded-full px-1.5 py-0.5 shrink-0">{{ new Date(act.scheduled_at!).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }) }}</span>
                      <span class="text-[10px] text-slate-400 dark:text-slate-500 capitalize shrink-0">{{ act.type }}</span>
                    </div>
                    <p class="text-sm text-slate-600 dark:text-slate-300 leading-snug line-clamp-2">{{ act.content }}</p>
                    <p class="text-xs text-slate-400 dark:text-slate-500 mt-0.5">{{ act.author }}</p>
                  </div>
                  <!-- mark as held -->
                  <button
                    type="button"
                    class="invisible group-hover/ua:visible shrink-0 mt-0.5 h-7 px-2.5 rounded-lg text-[11px] font-medium border border-slate-200 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:border-emerald-300 dark:hover:border-emerald-700 hover:text-emerald-600 dark:hover:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-950/30 transition-all"
                    title="Mark this activity as held — clears the scheduled date"
                    @click.stop="markActivityHeld(act.id)"
                  >Held</button>
                </div>
              </template>
            </template>
          </div>
          <!-- footer -->
          <div class="px-6 py-3 border-t border-slate-100 dark:border-slate-800 flex items-center justify-between">
            <p class="text-xs text-slate-400 dark:text-slate-500">Calls &amp; meetings across all records</p>
            <button type="button" class="text-xs text-sky-500 dark:text-sky-400 hover:underline" @click="viewMode = 'feed'; feedTypeFilter = 'all'; showUpcomingPanel = false">Open activity feed</button>
          </div>
        </div>
      </div>
    </transition>

    <!-- Automations panel -->
    <transition enter-active-class="transition-all duration-200" enter-from-class="opacity-0" enter-to-class="opacity-100" leave-active-class="transition-all duration-150" leave-from-class="opacity-100" leave-to-class="opacity-0">
      <div v-if="showAutomationsPanel" class="fixed inset-0 z-50 flex items-center justify-center p-4" @click.self="showAutomationsPanel = false; newRuleDraft = null">
        <div class="relative bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 w-full max-w-lg max-h-[80vh] flex flex-col" @click.stop>
          <!-- header -->
          <div class="flex items-center justify-between px-6 py-4 border-b border-slate-200 dark:border-slate-700">
            <div class="flex items-center gap-2">
              <svg class="h-5 w-5 text-violet-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="1.75">
                <path stroke-linecap="round" stroke-linejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
              <h3 class="text-base font-semibold text-slate-900 dark:text-white">Automations</h3>
              <span class="text-xs text-slate-400 dark:text-slate-500">— run actions when fields change</span>
            </div>
            <button type="button" class="h-8 w-8 rounded-lg flex items-center justify-center text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showAutomationsPanel = false; newRuleDraft = null">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>

          <!-- rule list -->
          <div class="flex-1 overflow-y-auto px-6 py-4 space-y-2">
            <div
              v-for="rule in automationRules"
              :key="rule.id"
              class="group/arule rounded-xl border border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50 px-4 py-3 transition-colors"
              :class="!rule.enabled ? 'opacity-60' : ''"
            >
              <!-- inline edit form -->
              <template v-if="editingAutomationRuleId === rule.id && editingAutomationDraft">
                <div class="space-y-2">
                  <div>
                    <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Name</label>
                    <input v-model="editingAutomationDraft.name" type="text" class="w-full text-sm px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-violet-400/50" />
                  </div>
                  <div class="grid grid-cols-3 gap-2">
                    <div>
                      <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Record type</label>
                      <select v-model="editingAutomationDraft.trigger_type_key" class="w-full text-sm px-2 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none">
                        <option v-for="rt in schema" :key="rt.key" :value="rt.key">{{ rt.label }}</option>
                      </select>
                    </div>
                    <div>
                      <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Field</label>
                      <select v-model="editingAutomationDraft.trigger_field_key" class="w-full text-sm px-2 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none">
                        <option value="">— pick field —</option>
                        <option v-for="f in schema.find(rt => rt.key === editingAutomationDraft.trigger_type_key)?.fields ?? []" :key="f.key" :value="f.key">{{ f.label }}</option>
                      </select>
                    </div>
                    <div>
                      <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">= value</label>
                      <select
                        v-if="(schema.find(rt => rt.key === editingAutomationDraft.trigger_type_key)?.fields ?? []).find(f => f.key === editingAutomationDraft.trigger_field_key)?.data_type === 'select'"
                        v-model="editingAutomationDraft.trigger_value"
                        class="w-full text-sm px-2 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none"
                      >
                        <option value="">— any —</option>
                        <option v-for="opt in (schema.find(rt => rt.key === editingAutomationDraft.trigger_type_key)?.fields ?? []).find(f => f.key === editingAutomationDraft.trigger_field_key)?.select_options ?? []" :key="opt" :value="opt">{{ opt }}</option>
                      </select>
                      <input v-else v-model="editingAutomationDraft.trigger_value" type="text" class="w-full text-sm px-2 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none" />
                    </div>
                  </div>
                  <div>
                    <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Action</label>
                    <select v-model="editingAutomationDraft.action_type" class="w-full text-sm px-2 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none">
                      <option value="set_field">Set a field</option>
                      <option value="create_task">Create a task</option>
                      <option value="notify">Show notification</option>
                    </select>
                  </div>
                  <div v-if="editingAutomationDraft.action_type === 'set_field'" class="grid grid-cols-2 gap-2">
                    <div>
                      <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Field to set</label>
                      <select v-model="editingAutomationDraft.action_field_key" class="w-full text-sm px-2 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none">
                        <option value="">— pick field —</option>
                        <option v-for="f in schema.find(rt => rt.key === editingAutomationDraft.trigger_type_key)?.fields?.filter(f => f.data_type !== 'formula' && f.data_type !== 'rollup') ?? []" :key="f.key" :value="f.key">{{ f.label }}</option>
                      </select>
                    </div>
                    <div>
                      <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Value (__today__ = now)</label>
                      <select
                        v-if="(schema.find(rt => rt.key === editingAutomationDraft.trigger_type_key)?.fields ?? []).find(f => f.key === editingAutomationDraft.action_field_key)?.data_type === 'select'"
                        v-model="editingAutomationDraft.action_value"
                        class="w-full text-sm px-2 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none"
                      >
                        <option value="">— clear —</option>
                        <option v-for="opt in (schema.find(rt => rt.key === editingAutomationDraft.trigger_type_key)?.fields ?? []).find(f => f.key === editingAutomationDraft.action_field_key)?.select_options ?? []" :key="opt" :value="opt">{{ opt }}</option>
                      </select>
                      <input v-else v-model="editingAutomationDraft.action_value" type="text" class="w-full text-sm px-2 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none" />
                    </div>
                  </div>
                  <div v-else-if="editingAutomationDraft.action_type === 'create_task'">
                    <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Task text</label>
                    <input v-model="editingAutomationDraft.action_task_text" type="text" class="w-full text-sm px-2 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none" />
                  </div>
                  <div v-else-if="editingAutomationDraft.action_type === 'notify'">
                    <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Message</label>
                    <input v-model="editingAutomationDraft.action_message" type="text" class="w-full text-sm px-2 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none" />
                  </div>
                  <div class="flex items-center justify-end gap-2 pt-0.5">
                    <button type="button" class="px-3 py-1 text-xs rounded-lg border border-slate-200 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors" @click="editingAutomationRuleId = null; editingAutomationDraft = null">Cancel</button>
                    <button
                      type="button"
                      class="px-3 py-1 text-xs rounded-lg bg-violet-600 hover:bg-violet-500 text-white transition-colors"
                      @click="(() => {
                        const idx = automationRules.findIndex(r => r.id === editingAutomationRuleId);
                        if (idx >= 0 && editingAutomationDraft) {
                          const d = editingAutomationDraft;
                          automationRules[idx].name = d.name.trim() || automationRules[idx].name;
                          automationRules[idx].trigger_type_key = d.trigger_type_key;
                          automationRules[idx].trigger_field_key = d.trigger_field_key.trim();
                          automationRules[idx].trigger_value = d.trigger_value.trim();
                          automationRules[idx].action_type = d.action_type;
                          automationRules[idx].action_field_key = d.action_field_key.trim() || undefined;
                          automationRules[idx].action_value = d.action_value.trim() || undefined;
                          automationRules[idx].action_task_text = d.action_task_text.trim() || undefined;
                          automationRules[idx].action_message = d.action_message.trim() || undefined;
                        }
                        editingAutomationRuleId = null;
                        editingAutomationDraft = null;
                      })()"
                    >Save</button>
                  </div>
                </div>
              </template>
              <!-- display mode -->
              <template v-else>
                <div class="flex items-start gap-3">
                  <!-- toggle -->
                  <button
                    type="button"
                    class="mt-0.5 shrink-0 h-5 w-9 rounded-full transition-colors relative"
                    :class="rule.enabled ? 'bg-violet-500' : 'bg-slate-300 dark:bg-slate-600'"
                    @click="rule.enabled = !rule.enabled"
                  >
                    <span class="absolute top-0.5 h-4 w-4 rounded-full bg-white shadow transition-all" :class="rule.enabled ? 'left-4' : 'left-0.5'" />
                  </button>
                  <!-- details -->
                  <div class="flex-1 min-w-0">
                    <p class="text-sm font-medium text-slate-700 dark:text-slate-300">{{ rule.name }}</p>
                    <p class="text-xs text-slate-400 dark:text-slate-500 mt-0.5">
                      When <span class="font-medium text-slate-600 dark:text-slate-400">{{ schema.find(rt => rt.key === rule.trigger_type_key)?.label ?? rule.trigger_type_key }}</span>
                      · <span class="font-medium text-slate-500 dark:text-slate-400">{{ (schema.find(rt => rt.key === rule.trigger_type_key)?.fields ?? []).find(f => f.key === rule.trigger_field_key)?.label ?? rule.trigger_field_key }}</span>
                      = "<span class="font-medium text-slate-600 dark:text-slate-300">{{ rule.trigger_value || 'any' }}</span>"
                    </p>
                    <p class="text-xs mt-0.5">
                      <span v-if="rule.action_type === 'set_field'" class="text-sky-600 dark:text-sky-400">Set <span class="font-medium">{{ (schema.find(rt => rt.key === rule.trigger_type_key)?.fields ?? []).find(f => f.key === rule.action_field_key)?.label ?? rule.action_field_key }}</span> → {{ rule.action_value === '__today__' ? 'today' : (rule.action_value || '—') }}</span>
                      <span v-else-if="rule.action_type === 'create_task'" class="text-emerald-600 dark:text-emerald-400">Create task: "{{ rule.action_task_text }}"</span>
                      <span v-else-if="rule.action_type === 'notify'" class="text-amber-600 dark:text-amber-400">Notify: "{{ rule.action_message }}"</span>
                    </p>
                  </div>
                  <!-- edit -->
                  <button
                    type="button"
                    class="shrink-0 h-6 w-6 rounded flex items-center justify-center text-slate-300 dark:text-slate-600 hover:text-sky-500 dark:hover:text-sky-400 opacity-0 group-hover/arule:opacity-100 transition-all"
                    title="Edit rule"
                    @click="editingAutomationRuleId = rule.id; editingAutomationDraft = { name: rule.name, enabled: rule.enabled, trigger_type_key: rule.trigger_type_key, trigger_field_key: rule.trigger_field_key, trigger_value: rule.trigger_value, action_type: rule.action_type, action_field_key: rule.action_field_key ?? '', action_value: rule.action_value ?? '', action_task_text: rule.action_task_text ?? '', action_message: rule.action_message ?? '' }"
                  >
                    <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                  </button>
                  <!-- duplicate -->
                  <button
                    type="button"
                    class="shrink-0 h-6 w-6 rounded flex items-center justify-center text-slate-300 dark:text-slate-600 hover:text-violet-500 dark:hover:text-violet-400 opacity-0 group-hover/arule:opacity-100 transition-all"
                    title="Duplicate rule"
                    @click="(() => { const copy = { ...JSON.parse(JSON.stringify(rule)), id: 'ar_' + String(Date.now()).slice(-6), name: rule.name + ' (copy)', enabled: false }; automationRules.push(copy); showToast('Automation duplicated (disabled by default)'); })()"
                  >
                    <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                  </button>
                  <!-- delete -->
                  <button
                    type="button"
                    class="shrink-0 h-6 w-6 rounded flex items-center justify-center text-slate-300 dark:text-slate-600 hover:text-rose-400 dark:hover:text-rose-500 opacity-0 group-hover/arule:opacity-100 transition-all"
                    title="Delete rule"
                    @click="automationRules.splice(automationRules.indexOf(rule), 1); if (editingAutomationRuleId === rule.id) { editingAutomationRuleId = null; editingAutomationDraft = null; }"
                  >
                    <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
              </template>
            </div>

            <!-- empty state -->
            <p v-if="!automationRules.length && !newRuleDraft" class="text-sm text-slate-400 dark:text-slate-500 text-center py-6">No automation rules yet</p>

            <!-- new rule form -->
            <div v-if="newRuleDraft" class="rounded-xl border-2 border-violet-300 dark:border-violet-700 bg-violet-50/40 dark:bg-violet-950/10 px-4 py-4 space-y-3">
              <p class="text-xs font-semibold uppercase tracking-widest text-violet-500 dark:text-violet-400">New rule</p>
              <div>
                <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Name</label>
                <input v-model="newRuleDraft.name" type="text" placeholder="e.g. Won deal → task" class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-violet-400/50" />
              </div>
              <div class="grid grid-cols-3 gap-2">
                <div>
                  <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Record type</label>
                  <select v-model="newRuleDraft.trigger_type_key" class="w-full text-sm px-2 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none">
                    <option v-for="rt in schema" :key="rt.key" :value="rt.key">{{ rt.label }}</option>
                  </select>
                </div>
                <div>
                  <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Field</label>
                  <select v-model="newRuleDraft.trigger_field_key" class="w-full text-sm px-2 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none">
                    <option value="">— pick field —</option>
                    <option v-for="f in schema.find(rt => rt.key === newRuleDraft.trigger_type_key)?.fields ?? []" :key="f.key" :value="f.key">{{ f.label }}</option>
                  </select>
                </div>
                <div>
                  <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">= value</label>
                  <select
                    v-if="(schema.find(rt => rt.key === newRuleDraft.trigger_type_key)?.fields ?? []).find(f => f.key === newRuleDraft.trigger_field_key)?.data_type === 'select'"
                    v-model="newRuleDraft.trigger_value"
                    class="w-full text-sm px-2 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none"
                  >
                    <option value="">— any —</option>
                    <option v-for="opt in (schema.find(rt => rt.key === newRuleDraft.trigger_type_key)?.fields ?? []).find(f => f.key === newRuleDraft.trigger_field_key)?.select_options ?? []" :key="opt" :value="opt">{{ opt }}</option>
                  </select>
                  <input v-else v-model="newRuleDraft.trigger_value" type="text" placeholder="Closed Won" class="w-full text-sm px-2 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none" />
                </div>
              </div>
              <div>
                <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Action</label>
                <select v-model="newRuleDraft.action_type" class="w-full text-sm px-2 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none">
                  <option value="set_field">Set a field</option>
                  <option value="create_task">Create a task</option>
                  <option value="notify">Show notification</option>
                </select>
              </div>
              <div v-if="newRuleDraft.action_type === 'set_field'" class="grid grid-cols-2 gap-2">
                <div>
                  <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Field to set</label>
                  <select v-model="newRuleDraft.action_field_key" class="w-full text-sm px-2 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none">
                    <option value="">— pick field —</option>
                    <option v-for="f in schema.find(rt => rt.key === newRuleDraft.trigger_type_key)?.fields?.filter(f => f.data_type !== 'formula' && f.data_type !== 'rollup') ?? []" :key="f.key" :value="f.key">{{ f.label }}</option>
                  </select>
                </div>
                <div>
                  <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Value (__today__ = now)</label>
                  <select
                    v-if="(schema.find(rt => rt.key === newRuleDraft.trigger_type_key)?.fields ?? []).find(f => f.key === newRuleDraft.action_field_key)?.data_type === 'select'"
                    v-model="newRuleDraft.action_value"
                    class="w-full text-sm px-2 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none"
                  >
                    <option value="">— clear —</option>
                    <option v-for="opt in (schema.find(rt => rt.key === newRuleDraft.trigger_type_key)?.fields ?? []).find(f => f.key === newRuleDraft.action_field_key)?.select_options ?? []" :key="opt" :value="opt">{{ opt }}</option>
                  </select>
                  <input v-else v-model="newRuleDraft.action_value" type="text" placeholder="__today__" class="w-full text-sm px-2 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none" />
                </div>
              </div>
              <div v-else-if="newRuleDraft.action_type === 'create_task'">
                <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Task text</label>
                <input v-model="newRuleDraft.action_task_text" type="text" placeholder="Send welcome email" class="w-full text-sm px-2 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none" />
              </div>
              <div v-else-if="newRuleDraft.action_type === 'notify'">
                <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Message</label>
                <input v-model="newRuleDraft.action_message" type="text" placeholder="Deal closed — follow up!" class="w-full text-sm px-2 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none" />
              </div>
              <div class="flex gap-2 justify-end pt-1">
                <button type="button" class="px-3 py-1.5 text-xs rounded-lg border border-slate-200 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors" @click="newRuleDraft = null">Cancel</button>
                <button
                  type="button"
                  class="px-3 py-1.5 text-xs rounded-lg bg-violet-600 hover:bg-violet-500 text-white transition-colors disabled:opacity-40"
                  :disabled="!newRuleDraft.name.trim() || !newRuleDraft.trigger_field_key.trim() || !newRuleDraft.trigger_value.trim()"
                  @click="(() => {
                    if (!newRuleDraft) return;
                    automationRules.push({
                      id: 'ar-' + String(Date.now()).slice(-6),
                      name: newRuleDraft.name.trim(),
                      enabled: true,
                      trigger_type_key: newRuleDraft.trigger_type_key,
                      trigger_field_key: newRuleDraft.trigger_field_key.trim(),
                      trigger_value: newRuleDraft.trigger_value.trim(),
                      action_type: newRuleDraft.action_type,
                      action_field_key: newRuleDraft.action_field_key.trim() || undefined,
                      action_value: newRuleDraft.action_value.trim() || undefined,
                      action_task_text: newRuleDraft.action_task_text.trim() || undefined,
                      action_message: newRuleDraft.action_message.trim() || undefined,
                    });
                    newRuleDraft = null;
                  })()"
                >Save rule</button>
              </div>
            </div>
          </div>

          <!-- footer -->
          <div class="px-6 py-4 border-t border-slate-200 dark:border-slate-700 flex items-center justify-between">
            <p class="text-xs text-slate-400 dark:text-slate-500">{{ automationRules.filter(r => r.enabled).length }} of {{ automationRules.length }} enabled</p>
            <button
              type="button"
              class="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-violet-600 hover:bg-violet-500 text-white transition-colors"
              @click="newRuleDraft = { name: '', enabled: true, trigger_type_key: schema[0]?.key ?? '', trigger_field_key: '', trigger_value: '', action_type: 'set_field', action_field_key: '', action_value: '', action_task_text: '', action_message: '' }"
            >
              <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4" /></svg>
              Add rule
            </button>
          </div>
        </div>
      </div>
    </transition>

    <!-- CSV import modal -->
    <transition enter-active-class="transition-all duration-150" enter-from-class="opacity-0" enter-to-class="opacity-100" leave-active-class="transition-all duration-100" leave-from-class="opacity-100" leave-to-class="opacity-0">
      <div v-if="showImportModal" class="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm" @click.self="showImportModal = false">
        <div class="w-full max-w-2xl rounded-2xl bg-white dark:bg-slate-900 shadow-2xl border border-slate-200 dark:border-slate-700 overflow-hidden flex flex-col max-h-[85vh]">
          <!-- header -->
          <div class="flex items-center justify-between px-6 py-4 border-b border-slate-100 dark:border-slate-800">
            <div>
              <h3 class="text-base font-semibold text-slate-900 dark:text-white">Import {{ selectedType?.label ?? 'records' }}</h3>
              <p class="text-xs text-slate-400 dark:text-slate-500 mt-0.5">Step {{ importStep === 'paste' ? '1' : importStep === 'map' ? '2' : '3' }} of 3 — {{ importStep === 'paste' ? 'Paste CSV data' : importStep === 'map' ? 'Map columns to fields' : 'Preview & confirm' }}</p>
            </div>
            <button type="button" class="rounded-lg p-1.5 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showImportModal = false">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>

          <!-- step 1: paste CSV -->
          <div v-if="importStep === 'paste'" class="flex-1 overflow-auto p-6 space-y-4">
            <div class="flex items-center gap-3">
              <label class="flex items-center gap-2 text-sm text-slate-600 dark:text-slate-300 cursor-pointer select-none">
                <input v-model="importHeaderRow" type="checkbox" class="h-4 w-4 rounded border-slate-300 dark:border-slate-600 text-sky-600 cursor-pointer">
                First row is a header
              </label>
            </div>
            <textarea
              v-model="importCsvText"
              class="w-full h-64 rounded-xl px-4 py-3 text-sm font-mono bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-900 dark:text-slate-100 placeholder-slate-400 resize-none focus:outline-none focus:ring-2 focus:ring-sky-400/40"
              placeholder="Paste CSV data here&#10;e.g.:&#10;Name,Email,Company&#10;John Smith,john@acme.com,Acme Corp&#10;Jane Doe,jane@startup.io,Startup Inc"
            />
          </div>

          <!-- step 2: column mapping -->
          <div v-else-if="importStep === 'map'" class="flex-1 overflow-auto p-6">
            <p class="text-sm text-slate-500 dark:text-slate-400 mb-4">Map each CSV column to a record field, or leave as "Skip" to ignore.</p>
            <div class="space-y-2">
              <div v-for="(header, i) in (importHeaderRow ? importParsed[0] : importParsed[0]?.map((_, j) => `Column ${j + 1}`))" :key="i" class="flex items-center gap-3">
                <span class="w-40 text-sm font-medium text-slate-700 dark:text-slate-300 truncate shrink-0">{{ importHeaderRow ? importParsed[0][i] : `Column ${i + 1}` }}</span>
                <span class="text-slate-300 dark:text-slate-600">→</span>
                <select
                  v-model="importMapping[i]"
                  class="flex-1 h-8 rounded-lg px-2 text-sm bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-sky-400/40"
                >
                  <option value="">Skip</option>
                  <option v-for="f in selectedType?.fields ?? []" :key="f.key" :value="f.key">{{ f.label }}</option>
                  <option value="__title__">Title (record name)</option>
                </select>
              </div>
            </div>
          </div>

          <!-- step 3: preview -->
          <div v-else class="flex-1 overflow-auto p-6">
            <p class="text-sm text-slate-500 dark:text-slate-400 mb-4">
              Ready to import <strong class="text-slate-700 dark:text-slate-300">{{ importPreviewRows.length }}</strong> record{{ importPreviewRows.length === 1 ? '' : 's' }}. Here is a preview of the first {{ Math.min(5, importPreviewRows.length) }}:
            </p>
            <div class="space-y-2">
              <div
                v-for="(row, ri) in importPreviewRows.slice(0, 5)"
                :key="ri"
                class="rounded-lg border border-slate-200 dark:border-slate-700 px-4 py-2.5 bg-slate-50 dark:bg-slate-800/50"
              >
                <p class="text-sm font-medium text-slate-800 dark:text-slate-200 truncate">{{ row.__title__ ?? `Record ${ri + 1}` }}</p>
                <div class="flex flex-wrap gap-2 mt-1">
                  <span v-for="(val, key) in row" :key="key" class="text-xs text-slate-500 dark:text-slate-400">
                    <span class="font-medium text-slate-600 dark:text-slate-300">{{ selectedType?.fields.find(f => f.key === key)?.label ?? key }}:</span> {{ val }}
                  </span>
                </div>
              </div>
            </div>
          </div>

          <!-- footer actions -->
          <div class="px-6 py-4 border-t border-slate-100 dark:border-slate-800 flex items-center justify-between gap-3">
            <button v-if="importStep !== 'paste'" type="button" class="text-sm text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 transition-colors" @click="importStep = importStep === 'preview' ? 'map' : 'paste'">
              Back
            </button>
            <span v-else />
            <div class="flex items-center gap-2">
              <button type="button" class="h-9 px-4 rounded-xl text-sm font-medium text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showImportModal = false">Cancel</button>
              <button
                v-if="importStep === 'paste'"
                type="button"
                class="h-9 px-4 rounded-xl text-sm font-semibold bg-sky-500 hover:bg-sky-600 text-white transition-colors disabled:opacity-40 disabled:pointer-events-none"
                :disabled="!importCsvText.trim()"
                @click="parseImportCsv"
              >Next: Map fields</button>
              <button
                v-else-if="importStep === 'map'"
                type="button"
                class="h-9 px-4 rounded-xl text-sm font-semibold bg-sky-500 hover:bg-sky-600 text-white transition-colors"
                @click="importStep = 'preview'"
              >Next: Preview</button>
              <button
                v-else
                type="button"
                class="h-9 px-4 rounded-xl text-sm font-semibold bg-sky-500 hover:bg-sky-600 text-white transition-colors"
                @click="commitImport"
              >Import {{ importPreviewRows.length }} record{{ importPreviewRows.length === 1 ? '' : 's' }}</button>
            </div>
          </div>
        </div>
      </div>
    </transition>

    <!-- bulk field fill modal -->
    <transition
      enter-active-class="transition-all duration-150"
      enter-from-class="opacity-0"
      enter-to-class="opacity-100"
      leave-active-class="transition-all duration-100"
      leave-from-class="opacity-100"
      leave-to-class="opacity-0"
    >
      <div
        v-if="showBulkFieldModal"
        class="fixed inset-0 z-50 flex items-center justify-center bg-black/40"
        @click.self="showBulkFieldModal = false"
      >
        <div class="w-full max-w-sm rounded-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 shadow-2xl p-5 space-y-3">
          <div class="flex items-center justify-between">
            <p class="text-sm font-semibold text-slate-900 dark:text-white">
              Set field for {{ selectedIds.size }} record{{ selectedIds.size === 1 ? '' : 's' }}
            </p>
            <button type="button" class="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors" @click="showBulkFieldModal = false">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <!-- step 1: field picker -->
          <template v-if="!bulkFieldKey">
            <p class="text-xs text-slate-400 dark:text-slate-500">Pick a field to update:</p>
            <div class="space-y-1 max-h-52 overflow-y-auto">
              <button
                v-for="col in allColumns.filter(c => !c.is_title)"
                :key="col.key"
                type="button"
                class="w-full flex items-center gap-2 px-3 py-2 text-sm text-left text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-lg transition-colors"
                @click="bulkFieldKey = col.key; bulkFieldValue = null"
              >
                <svg class="h-3.5 w-3.5 text-slate-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="1.75">
                  <path stroke-linecap="round" stroke-linejoin="round" :d="DATA_TYPE_ICONS[col.data_type] ?? DATA_TYPE_ICONS['text']" />
                </svg>
                {{ col.label }}
              </button>
            </div>
          </template>
          <!-- step 2: value editor -->
          <template v-else>
            <div class="flex items-center gap-2">
              <button type="button" class="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors" @click="bulkFieldKey = null; bulkFieldValue = null">
                <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M15 19l-7-7 7-7" /></svg>
              </button>
              <p class="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
                {{ allColumns.find(c => c.key === bulkFieldKey)?.label }}
              </p>
            </div>
            <CrmFieldInput
              :data-type="allColumns.find(c => c.key === bulkFieldKey)?.data_type ?? 'text'"
              :value="bulkFieldValue"
              :read-only="false"
              :select-options="allColumns.find(c => c.key === bulkFieldKey)?.select_options ?? []"
              :option-colors="allColumns.find(c => c.key === bulkFieldKey)?.select_option_colors ?? {}"
              :format="allColumns.find(c => c.key === bulkFieldKey)?.format"
              @update:value="bulkFieldValue = $event"
            />
            <div class="flex gap-2 justify-end">
              <button type="button" class="h-8 px-3 rounded-lg text-sm text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showBulkFieldModal = false">
                Cancel
              </button>
              <button type="button" class="h-8 px-4 rounded-lg text-sm font-medium text-white bg-sky-600 hover:bg-sky-500 transition-colors" @click="submitBulkFieldFill">
                Apply to {{ selectedIds.size }} record{{ selectedIds.size === 1 ? '' : 's' }}
              </button>
            </div>
          </template>
        </div>
      </div>
    </transition>

    <!-- column header context menu -->
    <transition
      enter-active-class="transition-all duration-100"
      enter-from-class="opacity-0 scale-95"
      enter-to-class="opacity-100 scale-100"
      leave-active-class="transition-all duration-75"
      leave-from-class="opacity-100 scale-100"
      leave-to-class="opacity-0 scale-95"
    >
      <div
        v-if="colHeaderMenu"
        class="fixed z-50 w-44 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-xl py-1"
        :style="{ top: `${colHeaderMenu.y}px`, left: `${colHeaderMenu.x}px` }"
        @click.stop
      >
        <p class="px-3 pt-2 pb-1 text-xs font-semibold text-slate-400 dark:text-slate-500 uppercase tracking-wider truncate">
          {{ allColumns.find(c => c.key === colHeaderMenu?.fieldKey)?.label ?? colHeaderMenu.fieldKey }}
        </p>
        <button type="button" class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="sortField = colHeaderMenu!.fieldKey; sortDir = 'asc'; sortField2 = null; sortDir2 = 'asc'; colHeaderMenu = null">
          <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M5 15l7-7 7 7" />
          </svg>
          Sort A → Z
        </button>
        <button type="button" class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="sortField = colHeaderMenu!.fieldKey; sortDir = 'desc'; sortField2 = null; sortDir2 = 'asc'; colHeaderMenu = null">
          <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M19 9l-7 7-7-7" />
          </svg>
          Sort Z → A
        </button>
        <!-- secondary sort — only when a primary sort is already active and this column isn't already primary -->
        <template v-if="sortField && colHeaderMenu && sortField !== colHeaderMenu.fieldKey">
          <button type="button" class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
            @click="sortField2 = colHeaderMenu!.fieldKey; sortDir2 = 'asc'; colHeaderMenu = null">
            <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
              <path stroke-linecap="round" stroke-linejoin="round" d="M5 15l7-7 7 7" />
              <path stroke-linecap="round" stroke-linejoin="round" d="M8 4h13M8 9h7" stroke-opacity="0.5" />
            </svg>
            Add as secondary sort ↑
          </button>
          <button type="button" class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
            @click="sortField2 = colHeaderMenu!.fieldKey; sortDir2 = 'desc'; colHeaderMenu = null">
            <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
              <path stroke-linecap="round" stroke-linejoin="round" d="M19 9l-7 7-7-7" />
              <path stroke-linecap="round" stroke-linejoin="round" d="M8 4h13M8 9h7" stroke-opacity="0.5" />
            </svg>
            Add as secondary sort ↓
          </button>
        </template>
        <template v-if="allColumns.find(c => c.key === colHeaderMenu?.fieldKey)?.data_type === 'select'">
          <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
          <button type="button" class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
            @click="filterPickerField = colHeaderMenu!.fieldKey; showFilterDropdown = true; colHeaderMenu = null">
            <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
              <path stroke-linecap="round" stroke-linejoin="round" d="M3 4h18M7 9h10M11 14h2" />
            </svg>
            Filter by this field
          </button>
          <button type="button" class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
            @click="groupByField = groupByField === colHeaderMenu!.fieldKey ? null : colHeaderMenu!.fieldKey; colHeaderMenu = null">
            <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
              <path stroke-linecap="round" stroke-linejoin="round" d="M4 6h16M4 12h8m-8 6h16" />
            </svg>
            {{ groupByField === colHeaderMenu?.fieldKey ? 'Clear grouping' : 'Group by this field' }}
          </button>
        </template>
        <template v-if="['text', 'email', 'phone', 'url'].includes(allColumns.find(c => c.key === colHeaderMenu?.fieldKey)?.data_type ?? '')">
          <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
          <div class="px-3 py-2 space-y-1">
            <p class="text-xs text-slate-400 dark:text-slate-500 font-medium">Contains text:</p>
            <div class="relative">
              <input
                type="text"
                :value="fieldTextFilters[colHeaderMenu?.fieldKey ?? ''] ?? ''"
                placeholder="Filter…"
                class="h-7 w-full rounded-lg px-2.5 text-xs bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-900 dark:text-slate-100 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-sky-400/40"
                @input="fieldTextFilters = { ...fieldTextFilters, [colHeaderMenu!.fieldKey]: ($event.target as HTMLInputElement).value }"
                @keydown.enter.stop="colHeaderMenu = null"
                @keydown.esc.stop="fieldTextFilters = { ...fieldTextFilters, [colHeaderMenu!.fieldKey]: '' }; colHeaderMenu = null"
                @click.stop
              />
            </div>
          </div>
        </template>
        <template v-if="allColumns.find(c => c.key === colHeaderMenu?.fieldKey)?.data_type === 'number'">
          <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
          <div class="px-3 py-2 space-y-1.5">
            <p class="text-xs text-slate-400 dark:text-slate-500 font-medium">Number range:</p>
            <div class="flex items-center gap-1.5">
              <input
                type="number"
                placeholder="Min"
                :value="numberMinFilters[colHeaderMenu?.fieldKey ?? ''] ?? ''"
                class="h-7 w-full rounded-lg px-2 text-xs bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-900 dark:text-slate-100 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-sky-400/40"
                @input="numberMinFilters = { ...numberMinFilters, [colHeaderMenu!.fieldKey]: ($event.target as HTMLInputElement).value ? Number(($event.target as HTMLInputElement).value) : null }"
                @keydown.enter.stop="colHeaderMenu = null"
                @click.stop
              />
              <span class="text-xs text-slate-400 shrink-0">–</span>
              <input
                type="number"
                placeholder="Max"
                :value="numberMaxFilters[colHeaderMenu?.fieldKey ?? ''] ?? ''"
                class="h-7 w-full rounded-lg px-2 text-xs bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-900 dark:text-slate-100 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-sky-400/40"
                @input="numberMaxFilters = { ...numberMaxFilters, [colHeaderMenu!.fieldKey]: ($event.target as HTMLInputElement).value ? Number(($event.target as HTMLInputElement).value) : null }"
                @keydown.enter.stop="colHeaderMenu = null"
                @click.stop
              />
            </div>
          </div>
        </template>
        <template v-if="allColumns.find(c => c.key === colHeaderMenu?.fieldKey)?.data_type === 'date'">
          <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
          <div class="px-3 py-2 space-y-2">
            <p class="text-xs text-slate-400 dark:text-slate-500 font-medium">Date range:</p>
            <!-- quick preset chips -->
            <div class="flex flex-wrap gap-1">
              <button
                v-for="preset in [
                  { label: 'Today', after: DUE_TODAY_STR, before: DUE_TODAY_STR },
                  { label: 'This week', after: (() => { const d = new Date(DUE_TODAY_STR); d.setDate(d.getDate() - d.getDay()); return d.toISOString().slice(0,10); })(), before: (() => { const d = new Date(DUE_TODAY_STR); d.setDate(d.getDate() - d.getDay() + 6); return d.toISOString().slice(0,10); })() },
                  { label: 'This month', after: DUE_TODAY_STR.slice(0,7) + '-01', before: (() => { const d = new Date(DUE_TODAY_STR); d.setMonth(d.getMonth() + 1, 0); return d.toISOString().slice(0,10); })() },
                  { label: 'Last 30 days', after: (() => { const d = new Date(DUE_TODAY_STR); d.setDate(d.getDate() - 30); return d.toISOString().slice(0,10); })(), before: DUE_TODAY_STR },
                  { label: 'Last 90 days', after: (() => { const d = new Date(DUE_TODAY_STR); d.setDate(d.getDate() - 90); return d.toISOString().slice(0,10); })(), before: DUE_TODAY_STR },
                  { label: 'This year', after: DUE_TODAY_STR.slice(0,4) + '-01-01', before: DUE_TODAY_STR.slice(0,4) + '-12-31' },
                ]"
                :key="preset.label"
                type="button"
                class="px-2 py-0.5 rounded-full text-[10px] font-medium border transition-colors"
                :class="dateAfterFilters[colHeaderMenu?.fieldKey ?? ''] === preset.after && dateBeforeFilters[colHeaderMenu?.fieldKey ?? ''] === preset.before
                  ? 'bg-sky-100 dark:bg-sky-900/40 border-sky-300 dark:border-sky-700 text-sky-700 dark:text-sky-300'
                  : 'border-slate-200 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800'"
                @click.stop="dateAfterFilters = { ...dateAfterFilters, [colHeaderMenu!.fieldKey]: preset.after }; dateBeforeFilters = { ...dateBeforeFilters, [colHeaderMenu!.fieldKey]: preset.before }"
              >{{ preset.label }}</button>
            </div>
            <div class="space-y-1">
              <div class="flex items-center gap-1.5">
                <span class="text-xs text-slate-400 dark:text-slate-500 w-10 shrink-0">After</span>
                <input
                  type="date"
                  :value="dateAfterFilters[colHeaderMenu?.fieldKey ?? ''] ?? ''"
                  class="h-7 flex-1 rounded-lg px-2 text-xs bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-sky-400/40"
                  @input="dateAfterFilters = { ...dateAfterFilters, [colHeaderMenu!.fieldKey]: ($event.target as HTMLInputElement).value || null }"
                  @click.stop
                />
              </div>
              <div class="flex items-center gap-1.5">
                <span class="text-xs text-slate-400 dark:text-slate-500 w-10 shrink-0">Before</span>
                <input
                  type="date"
                  :value="dateBeforeFilters[colHeaderMenu?.fieldKey ?? ''] ?? ''"
                  class="h-7 flex-1 rounded-lg px-2 text-xs bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-sky-400/40"
                  @input="dateBeforeFilters = { ...dateBeforeFilters, [colHeaderMenu!.fieldKey]: ($event.target as HTMLInputElement).value || null }"
                  @click.stop
                />
              </div>
            </div>
          </div>
        </template>
        <div class="my-1 border-t border-slate-100 dark:border-slate-800" />
        <button
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="(() => { const col = allColumns.find(c => c.key === colHeaderMenu!.fieldKey); if (col) startColRename(col); colHeaderMenu = null; })()"
        >
          <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
          </svg>
          Rename column
        </button>
        <button type="button" class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="togglePinColumn(colHeaderMenu!.fieldKey); colHeaderMenu = null"
        >
          <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z" />
          </svg>
          {{ pinnedColumnKeys.has(colHeaderMenu?.fieldKey ?? '') ? 'Unpin column' : 'Pin column to left' }}
        </button>
        <button type="button" class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="colStatsFieldKey = colHeaderMenu!.fieldKey; showColStatsModal = true; colHeaderMenu = null">
          <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M3 3v18h18M7 16l4-4 4 4 4-4" />
          </svg>
          Column stats
        </button>
        <button
          v-if="colHeaderMenu && (fieldTextFilters[colHeaderMenu.fieldKey] || numberMinFilters[colHeaderMenu.fieldKey] != null || numberMaxFilters[colHeaderMenu.fieldKey] != null || dateAfterFilters[colHeaderMenu.fieldKey] || dateBeforeFilters[colHeaderMenu.fieldKey] || activeFilters.some(f => f.fieldKey === colHeaderMenu!.fieldKey))"
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-rose-500 dark:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-950/20 transition-colors"
          @click="(() => { const k = colHeaderMenu!.fieldKey; fieldTextFilters = { ...fieldTextFilters, [k]: '' }; numberMinFilters = { ...numberMinFilters, [k]: null }; numberMaxFilters = { ...numberMaxFilters, [k]: null }; dateAfterFilters = { ...dateAfterFilters, [k]: '' }; dateBeforeFilters = { ...dateBeforeFilters, [k]: '' }; activeFilters = activeFilters.filter(f => f.fieldKey !== k); colHeaderMenu = null; })()"
        >
          <svg class="h-3.5 w-3.5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M3 4h18M7 9h10M11 14h2" />
            <path stroke-linecap="round" stroke-linejoin="round" d="M18 18l-4-4m0 4l4-4" />
          </svg>
          Clear column filter
        </button>
        <button
          v-if="colHeaderMenu && columnWidths[colHeaderMenu.fieldKey]"
          type="button"
          class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="(() => { const w = { ...columnWidths }; delete w[colHeaderMenu!.fieldKey]; columnWidths = w; colHeaderMenu = null; })()"
        >
          <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
          </svg>
          Reset column width
        </button>
        <button type="button" class="w-full flex items-center gap-2.5 px-3 py-2 text-sm text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          @click="hiddenColumnKeys = new Set([...hiddenColumnKeys, colHeaderMenu!.fieldKey]); colHeaderMenu = null">
          <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
            <path stroke-linecap="round" stroke-linejoin="round" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" />
          </svg>
          Hide column
        </button>
      </div>
    </transition>

    <!-- win / loss reason capture modal -->
    <transition enter-active-class="transition-all duration-150" enter-from-class="opacity-0" enter-to-class="opacity-100" leave-active-class="transition-all duration-100" leave-from-class="opacity-100" leave-to-class="opacity-0">
      <div
        v-if="winLossModal"
        class="fixed inset-0 z-[300] flex items-center justify-center bg-black/50 backdrop-blur-sm"
        @click.self="winLossModal = null"
      >
        <div class="w-full max-w-sm mx-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-2xl overflow-hidden">
          <!-- header -->
          <div
            class="flex items-start gap-3 px-5 py-4 border-b border-slate-100 dark:border-slate-800"
            :class="winLossModal.stage === 'Closed Won' ? 'bg-emerald-50 dark:bg-emerald-950/20' : 'bg-rose-50 dark:bg-rose-950/20'"
          >
            <div
              class="shrink-0 h-8 w-8 rounded-full flex items-center justify-center"
              :class="winLossModal.stage === 'Closed Won' ? 'bg-emerald-100 dark:bg-emerald-900/40 text-emerald-600 dark:text-emerald-400' : 'bg-rose-100 dark:bg-rose-900/40 text-rose-500 dark:text-rose-400'"
            >
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
                <path v-if="winLossModal.stage === 'Closed Won'" stroke-linecap="round" stroke-linejoin="round" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                <path v-else stroke-linecap="round" stroke-linejoin="round" d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <div class="flex-1 min-w-0">
              <h3
                class="text-sm font-semibold"
                :class="winLossModal.stage === 'Closed Won' ? 'text-emerald-800 dark:text-emerald-300' : 'text-rose-700 dark:text-rose-300'"
              >{{ winLossModal.stage === 'Closed Won' ? 'Congrats — deal won!' : 'Deal marked lost' }}</h3>
              <p class="text-xs text-slate-400 dark:text-slate-500 mt-0.5 truncate">{{ winLossModal.record.title }}</p>
            </div>
            <button type="button" class="shrink-0 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 rounded p-1" @click="winLossModal = null">
              <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5">
                <path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
          <!-- body -->
          <div class="px-5 py-4 space-y-3">
            <div class="space-y-1">
              <label class="block text-xs font-medium text-slate-500 dark:text-slate-400">
                {{ winLossModal.stage === 'Closed Won' ? 'Win reason' : 'Loss reason' }}
                <span class="text-slate-300 dark:text-slate-600 font-normal">(optional)</span>
              </label>
              <select
                v-model="winLossReason"
                class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-sky-500"
              >
                <option value="">Select a reason…</option>
                <option
                  v-for="r in (winLossModal.stage === 'Closed Won' ? WIN_LOSS_REASONS.won : WIN_LOSS_REASONS.lost)"
                  :key="r"
                  :value="r"
                >{{ r }}</option>
              </select>
            </div>
            <div class="space-y-1">
              <label class="block text-xs font-medium text-slate-500 dark:text-slate-400">Note <span class="text-slate-300 dark:text-slate-600 font-normal">(optional)</span></label>
              <textarea
                v-model="winLossNote"
                rows="2"
                placeholder="Any additional context…"
                class="w-full resize-none text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-sky-500"
                @keydown.meta.enter.prevent="submitWinLoss"
                @keydown.ctrl.enter.prevent="submitWinLoss"
                @keydown.escape.prevent="winLossModal = null"
              />
            </div>
          </div>
          <!-- footer -->
          <div class="px-5 py-3.5 border-t border-slate-100 dark:border-slate-800 flex items-center gap-2">
            <button
              type="button"
              class="flex-1 rounded-lg py-2 text-sm font-medium text-white transition-colors"
              :class="winLossModal.stage === 'Closed Won' ? 'bg-emerald-600 hover:bg-emerald-500' : 'bg-rose-600 hover:bg-rose-500'"
              @click="submitWinLoss"
            >Mark {{ winLossModal.stage }}</button>
            <button type="button" class="rounded-lg py-2 px-4 text-sm font-medium text-slate-600 dark:text-slate-300 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors" @click="winLossModal = null">Cancel</button>
          </div>
        </div>
      </div>
    </transition>

    <!-- convert record type modal -->
    <transition enter-active-class="transition-all duration-150" enter-from-class="opacity-0" enter-to-class="opacity-100" leave-active-class="transition-all duration-100" leave-from-class="opacity-100" leave-to-class="opacity-0">
      <div
        v-if="convertModal"
        class="fixed inset-0 z-[300] flex items-center justify-center bg-black/50 backdrop-blur-sm"
        @click.self="convertModal = null"
      >
        <div class="w-full max-w-md mx-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-2xl overflow-hidden">
          <div class="flex items-center gap-3 px-5 py-4 border-b border-slate-100 dark:border-slate-800">
            <div class="h-8 w-8 rounded-full bg-sky-100 dark:bg-sky-900/40 flex items-center justify-center text-sky-600 dark:text-sky-400 shrink-0">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
                <path stroke-linecap="round" stroke-linejoin="round" d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" />
              </svg>
            </div>
            <div class="flex-1 min-w-0">
              <h3 class="text-sm font-semibold text-slate-900 dark:text-white">Convert record type</h3>
              <p class="text-xs text-slate-400 dark:text-slate-500 mt-0.5 truncate">{{ convertModal.record.title }}</p>
            </div>
            <button type="button" class="shrink-0 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 rounded p-1" @click="convertModal = null">
              <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <div class="px-5 py-4 space-y-4">
            <div class="space-y-1">
              <label class="text-xs font-medium text-slate-500 dark:text-slate-400">Convert to</label>
              <select
                v-model="convertTargetTypeKey"
                class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-sky-500"
              >
                <option v-for="rt in schema.filter(s => s.key !== convertModal!.record.record_type_key)" :key="rt.key" :value="rt.key">{{ rt.label }}</option>
              </select>
            </div>
            <template v-if="convertTargetTypeKey">
              <div class="space-y-1">
                <p class="text-xs font-medium text-slate-500 dark:text-slate-400">Field mapping</p>
                <p class="text-[10px] text-slate-400 dark:text-slate-500">Values from matching fields will be copied to the new record. Fields with no match are left empty.</p>
              </div>
              <div class="rounded-lg border border-slate-200 dark:border-slate-700 overflow-hidden text-xs">
                <div class="grid grid-cols-2 bg-slate-50 dark:bg-slate-800/60 px-3 py-1.5 text-[10px] font-semibold uppercase tracking-wider text-slate-400 dark:text-slate-500 border-b border-slate-200 dark:border-slate-700">
                  <span>{{ schema.find(s => s.key === convertModal!.record.record_type_key)?.label ?? 'Source' }} field</span>
                  <span>Maps to</span>
                </div>
                <div
                  v-for="srcField in (schema.find(s => s.key === convertModal!.record.record_type_key)?.fields ?? []).slice().sort((a, b) => a.position - b.position)"
                  :key="srcField.key"
                  class="grid grid-cols-2 items-center px-3 py-1.5 border-b border-slate-100 dark:border-slate-800 last:border-b-0"
                >
                  <div>
                    <span class="font-medium text-slate-700 dark:text-slate-300">{{ srcField.label }}</span>
                    <span v-if="convertModal!.record.field_values[srcField.key] != null && String(convertModal!.record.field_values[srcField.key]).trim()" class="ml-1.5 text-slate-400 dark:text-slate-500 truncate">{{ String(convertModal!.record.field_values[srcField.key]).slice(0, 24) }}</span>
                  </div>
                  <div>
                    <select
                      class="w-full text-xs px-2 py-1 rounded border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 focus:outline-none focus:ring-1 focus:ring-sky-400"
                      :value="convertMappings[srcField.key] ?? ''"
                      @change="convertMappings = { ...convertMappings, [srcField.key]: ($event.target as HTMLSelectElement).value }"
                    >
                      <option value="">(skip)</option>
                      <option
                        v-for="tgtField in (schema.find(s => s.key === convertTargetTypeKey)?.fields ?? []).filter(f => f.data_type === srcField.data_type)"
                        :key="tgtField.key"
                        :value="tgtField.key"
                      >{{ tgtField.label }}</option>
                    </select>
                  </div>
                </div>
              </div>
            </template>
          </div>
          <div class="px-5 py-3.5 border-t border-slate-100 dark:border-slate-800 flex items-center gap-2">
            <button
              type="button"
              class="flex-1 rounded-lg py-2 text-sm font-medium text-white bg-sky-600 hover:bg-sky-500 transition-colors disabled:opacity-40"
              :disabled="!convertTargetTypeKey"
              @click="executeConvert"
            >Convert &amp; open</button>
            <button type="button" class="rounded-lg py-2 px-4 text-sm font-medium text-slate-600 dark:text-slate-300 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors" @click="convertModal = null">Cancel</button>
          </div>
        </div>
      </div>
    </transition>

    <!-- merge target picker (from kanban card context menu) -->
    <transition enter-active-class="transition-all duration-100" enter-from-class="opacity-0 scale-95" enter-to-class="opacity-100 scale-100" leave-active-class="transition-all duration-75" leave-from-class="opacity-100 scale-100" leave-to-class="opacity-0 scale-95">
      <div
        v-if="mergeTargetPicker"
        class="fixed z-[290] w-72 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-2xl overflow-hidden"
        style="top: 50%; left: 50%; transform: translate(-50%, -50%)"
        @click.stop
      >
        <div class="px-3 py-2.5 border-b border-slate-100 dark:border-slate-800 flex items-center gap-2">
          <svg class="h-3.5 w-3.5 shrink-0 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><circle cx="11" cy="11" r="8" /><path stroke-linecap="round" stroke-linejoin="round" d="M21 21l-4.35-4.35" /></svg>
          <input
            ref="mergeTargetInputEl"
            v-model="mergeTargetQuery"
            type="text"
            placeholder="Search records to merge into…"
            class="flex-1 text-sm bg-transparent text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none"
          />
          <button type="button" class="shrink-0 text-slate-300 dark:text-slate-600 hover:text-slate-500 dark:hover:text-slate-400" @click="mergeTargetPicker = null">
            <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <p class="px-3 pt-2 pb-0.5 text-[10px] font-semibold uppercase tracking-wider text-slate-400 dark:text-slate-500">Merge "{{ mergeTargetPicker.source.title }}" into…</p>
        <ul class="py-1 max-h-48 overflow-y-auto">
          <li v-if="!mergeTargetResults.length" class="px-3 py-3 text-xs text-slate-400 dark:text-slate-500 text-center">No matching records</li>
          <li
            v-for="rec in mergeTargetResults"
            :key="rec.id"
            class="flex items-center gap-2.5 px-3 py-2 cursor-pointer text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
            @mousedown.prevent="openMergeWith(rec, mergeTargetPicker!.source); mergeTargetPicker = null"
          >
            <span class="shrink-0 h-5 w-5 rounded-full flex items-center justify-center text-white text-[9px] font-bold" :style="{ background: selectedType?.color ?? '#6366f1' }">{{ rec.title.slice(0, 1).toUpperCase() }}</span>
            <span class="flex-1 truncate">{{ rec.title }}</span>
          </li>
        </ul>
      </div>
    </transition>

    <!-- merge records comparison modal -->
    <transition enter-active-class="transition-all duration-150" enter-from-class="opacity-0" enter-to-class="opacity-100" leave-active-class="transition-all duration-100" leave-from-class="opacity-100" leave-to-class="opacity-0">
      <div
        v-if="mergeModal"
        class="fixed inset-0 z-[300] flex items-center justify-center bg-black/50 backdrop-blur-sm"
        @click.self="mergeModal = null"
      >
        <div class="w-full max-w-2xl mx-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
          <!-- header -->
          <div class="flex items-center gap-3 px-5 py-4 border-b border-slate-100 dark:border-slate-800 shrink-0">
            <div class="h-8 w-8 rounded-full bg-violet-100 dark:bg-violet-900/40 flex items-center justify-center text-violet-600 dark:text-violet-400 shrink-0">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
            </div>
            <div class="flex-1 min-w-0">
              <h3 class="text-sm font-semibold text-slate-900 dark:text-white">Merge records</h3>
              <p class="text-xs text-slate-400 dark:text-slate-500 mt-0.5">Choose which value to keep for each field. The secondary record will be removed.</p>
            </div>
            <button type="button" class="shrink-0 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 rounded p-1" @click="mergeModal = null">
              <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <!-- column headers -->
          <div class="grid grid-cols-[1fr_1fr] gap-px px-5 pt-3 pb-2 shrink-0 border-b border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50">
            <div class="flex items-center gap-2">
              <span class="inline-flex items-center gap-1 rounded-full bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300 text-[10px] font-semibold px-2 py-0.5">Keep</span>
              <span class="text-xs font-medium text-slate-700 dark:text-slate-300 truncate">{{ mergeModal.primary.title }}</span>
            </div>
            <div class="flex items-center gap-2">
              <span class="inline-flex items-center gap-1 rounded-full bg-rose-100 dark:bg-rose-900/40 text-rose-600 dark:text-rose-400 text-[10px] font-semibold px-2 py-0.5">Remove</span>
              <span class="text-xs font-medium text-slate-700 dark:text-slate-300 truncate">{{ mergeModal.secondary.title }}</span>
            </div>
          </div>
          <!-- field rows -->
          <div class="flex-1 overflow-y-auto divide-y divide-slate-100 dark:divide-slate-800">
            <div
              v-for="field in (schema.find(s => s.key === mergeModal!.primary.record_type_key)?.fields ?? []).slice().sort((a, b) => a.position - b.position)"
              :key="field.key"
              class="grid grid-cols-[1fr_1fr] gap-px"
              :class="field.is_title ? 'bg-slate-50/60 dark:bg-slate-800/30' : ''"
            >
              <!-- primary value cell -->
              <label
                class="flex items-start gap-2.5 px-4 py-2.5 cursor-pointer group transition-colors"
                :class="mergeModal!.choices[field.key] === 'primary' ? 'bg-emerald-50/60 dark:bg-emerald-950/10' : 'hover:bg-slate-50 dark:hover:bg-slate-800/40'"
              >
                <input
                  type="radio"
                  :name="`merge-field-${field.key}`"
                  value="primary"
                  :checked="mergeModal!.choices[field.key] === 'primary'"
                  class="mt-0.5 shrink-0 accent-emerald-500"
                  @change="mergeModal!.choices[field.key] = 'primary'"
                />
                <div class="flex-1 min-w-0">
                  <p class="text-[10px] font-medium text-slate-400 dark:text-slate-500 truncate mb-0.5">{{ field.label }}</p>
                  <p class="text-xs text-slate-700 dark:text-slate-300 break-words">
                    <span v-if="mergeModal!.primary.field_values[field.key] != null && String(mergeModal!.primary.field_values[field.key]).trim()">
                      {{ String(mergeModal!.primary.field_values[field.key]) }}
                    </span>
                    <span v-else class="text-slate-300 dark:text-slate-600 italic">Empty</span>
                  </p>
                </div>
              </label>
              <!-- secondary value cell -->
              <label
                class="flex items-start gap-2.5 px-4 py-2.5 cursor-pointer group transition-colors border-l border-slate-100 dark:border-slate-800"
                :class="mergeModal!.choices[field.key] === 'secondary' ? 'bg-rose-50/40 dark:bg-rose-950/10' : 'hover:bg-slate-50 dark:hover:bg-slate-800/40'"
              >
                <input
                  type="radio"
                  :name="`merge-field-${field.key}`"
                  value="secondary"
                  :checked="mergeModal!.choices[field.key] === 'secondary'"
                  class="mt-0.5 shrink-0 accent-rose-500"
                  @change="mergeModal!.choices[field.key] = 'secondary'"
                />
                <div class="flex-1 min-w-0">
                  <p class="text-[10px] font-medium text-slate-400 dark:text-slate-500 truncate mb-0.5">
                    {{ field.label }}
                    <span
                      v-if="String(mergeModal!.primary.field_values[field.key] ?? '').trim() === String(mergeModal!.secondary.field_values[field.key] ?? '').trim() && String(mergeModal!.primary.field_values[field.key] ?? '').trim()"
                      class="ml-1 text-[9px] font-semibold rounded-full px-1 py-px bg-slate-100 dark:bg-slate-800 text-slate-400 dark:text-slate-500"
                    >same</span>
                  </p>
                  <p class="text-xs text-slate-700 dark:text-slate-300 break-words">
                    <span v-if="mergeModal!.secondary.field_values[field.key] != null && String(mergeModal!.secondary.field_values[field.key]).trim()">
                      {{ String(mergeModal!.secondary.field_values[field.key]) }}
                    </span>
                    <span v-else class="text-slate-300 dark:text-slate-600 italic">Empty</span>
                  </p>
                </div>
              </label>
            </div>
          </div>
          <!-- footer -->
          <div class="px-5 py-3.5 border-t border-slate-100 dark:border-slate-800 flex items-center gap-2 shrink-0 bg-white dark:bg-slate-900">
            <button
              type="button"
              class="flex-1 rounded-lg py-2 text-sm font-medium text-white bg-violet-600 hover:bg-violet-500 transition-colors"
              @click="executeMerge"
            >
              <svg class="h-3.5 w-3.5 inline mr-1.5 -mt-px" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
              Merge records
            </button>
            <button type="button" class="rounded-lg py-2 px-4 text-sm font-medium text-slate-600 dark:text-slate-300 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors" @click="mergeModal = null">Cancel</button>
          </div>
        </div>
      </div>
    </transition>

    <!-- compare modal — side-by-side record comparison -->
    <transition
      enter-active-class="transition-all duration-150"
      enter-from-class="opacity-0"
      enter-to-class="opacity-100"
      leave-active-class="transition-all duration-100"
      leave-from-class="opacity-100"
      leave-to-class="opacity-0"
    >
      <div
        v-if="compareModal"
        class="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm px-4"
        @click.self="compareModal = null"
      >
        <div class="relative w-full max-w-4xl max-h-[88vh] flex flex-col rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-2xl overflow-hidden">
          <!-- header -->
          <div class="flex items-center gap-3 px-5 py-3.5 border-b border-slate-100 dark:border-slate-800 shrink-0 bg-white dark:bg-slate-900">
            <svg class="h-4 w-4 text-violet-500 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
              <path stroke-linecap="round" stroke-linejoin="round" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h5.586a1 1 0 00.707-.293l5.414-5.414a1 1 0 00.293-.707V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
            </svg>
            <h3 class="text-sm font-semibold text-slate-900 dark:text-white flex-1">Compare records</h3>
            <!-- swap -->
            <button
              type="button"
              class="flex items-center gap-1.5 h-7 px-2.5 rounded-lg text-xs text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 border border-slate-200 dark:border-slate-700 transition-colors"
              title="Swap A / B"
              @click="compareModal = { recordA: compareModal!.recordB, recordB: compareModal!.recordA }"
            >
              <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5">
                <path stroke-linecap="round" stroke-linejoin="round" d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12m0 0l4-4m-4 4l-4-4" />
              </svg>
              Swap
            </button>
            <button type="button" class="rounded-lg p-1.5 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="compareModal = null">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>

          <!-- column headers: field label | A | B -->
          <div class="grid grid-cols-[minmax(140px,1fr)_2fr_2fr] gap-0 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50 shrink-0">
            <div class="px-4 py-2.5 text-[10px] font-semibold uppercase tracking-widest text-slate-400 dark:text-slate-500">Field</div>
            <div class="px-4 py-2.5 border-l border-slate-200 dark:border-slate-700">
              <button
                type="button"
                class="text-xs font-semibold text-sky-600 dark:text-sky-400 hover:underline truncate max-w-full text-left"
                @click="openRecord(compareModal!.recordA); compareModal = null"
              >{{ compareModal.recordA.title }}</button>
              <p class="text-[10px] text-slate-400 dark:text-slate-500 mt-0.5">A</p>
            </div>
            <div class="px-4 py-2.5 border-l border-slate-200 dark:border-slate-700">
              <button
                type="button"
                class="text-xs font-semibold text-sky-600 dark:text-sky-400 hover:underline truncate max-w-full text-left"
                @click="openRecord(compareModal!.recordB); compareModal = null"
              >{{ compareModal.recordB.title }}</button>
              <p class="text-[10px] text-slate-400 dark:text-slate-500 mt-0.5">B</p>
            </div>
          </div>

          <!-- field rows -->
          <div class="flex-1 overflow-y-auto divide-y divide-slate-100 dark:divide-slate-800">
            <template v-for="field in (schema.find(s => s.key === compareModal!.recordA.record_type_key)?.fields ?? []).slice().sort((a, b) => a.position - b.position)" :key="field.key">
              <div
                class="grid grid-cols-[minmax(140px,1fr)_2fr_2fr] gap-0 text-sm transition-colors"
                :class="String(compareModal!.recordA.field_values[field.key] ?? '') !== String(compareModal!.recordB.field_values[field.key] ?? '')
                  ? 'bg-amber-50/60 dark:bg-amber-950/10'
                  : ''"
              >
                <div class="px-4 py-2.5 flex items-center gap-1.5">
                  <span class="text-xs font-medium text-slate-500 dark:text-slate-400 truncate">{{ field.label }}</span>
                  <span
                    v-if="String(compareModal!.recordA.field_values[field.key] ?? '') !== String(compareModal!.recordB.field_values[field.key] ?? '')"
                    class="shrink-0 h-1.5 w-1.5 rounded-full bg-amber-400 dark:bg-amber-500"
                    title="Values differ"
                  />
                </div>
                <div class="px-4 py-2.5 border-l border-slate-100 dark:border-slate-800">
                  <CrmCellValue
                    :value="field.data_type === 'formula' ? evaluateFormula(compareModal!.recordA, field) as (string | number) : field.data_type === 'rollup' ? evaluateRollup(compareModal!.recordA, field) as (string | number) : compareModal!.recordA.field_values[field.key]"
                    :data-type="field.data_type === 'formula' ? (typeof evaluateFormula(compareModal!.recordA, field) === 'string' ? 'text' : 'number') : field.data_type"
                    :format="field.format"
                  />
                  <span v-if="compareModal!.recordA.field_values[field.key] == null || compareModal!.recordA.field_values[field.key] === ''" class="text-xs text-slate-300 dark:text-slate-600 italic">—</span>
                </div>
                <div class="px-4 py-2.5 border-l border-slate-100 dark:border-slate-800">
                  <CrmCellValue
                    :value="field.data_type === 'formula' ? evaluateFormula(compareModal!.recordB, field) as (string | number) : field.data_type === 'rollup' ? evaluateRollup(compareModal!.recordB, field) as (string | number) : compareModal!.recordB.field_values[field.key]"
                    :data-type="field.data_type === 'formula' ? (typeof evaluateFormula(compareModal!.recordB, field) === 'string' ? 'text' : 'number') : field.data_type"
                    :format="field.format"
                  />
                  <span v-if="compareModal!.recordB.field_values[field.key] == null || compareModal!.recordB.field_values[field.key] === ''" class="text-xs text-slate-300 dark:text-slate-600 italic">—</span>
                </div>
              </div>
            </template>
          </div>

          <!-- footer -->
          <div class="px-5 py-3.5 border-t border-slate-100 dark:border-slate-800 flex items-center gap-2 shrink-0 bg-white dark:bg-slate-900">
            <button
              type="button"
              class="flex-1 rounded-lg py-2 text-sm font-medium text-slate-700 dark:text-slate-200 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
              @click="openRecord(compareModal!.recordA); compareModal = null"
            >Open A</button>
            <button
              type="button"
              class="flex-1 rounded-lg py-2 text-sm font-medium text-slate-700 dark:text-slate-200 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
              @click="openRecord(compareModal!.recordB); compareModal = null"
            >Open B</button>
            <button
              v-if="compareModal.recordA.record_type_key === compareModal.recordB.record_type_key"
              type="button"
              class="flex-1 rounded-lg py-2 text-sm font-medium text-white bg-violet-600 hover:bg-violet-500 transition-colors"
              @click="mergeModal = { primary: compareModal!.recordA, secondary: compareModal!.recordB, choices: {} }; compareModal = null"
            >
              <svg class="h-3.5 w-3.5 inline mr-1.5 -mt-px" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
              Merge these
            </button>
            <button type="button" class="rounded-lg py-2 px-4 text-sm font-medium text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="compareModal = null">Close</button>
          </div>
        </div>
      </div>
    </transition>

    <!-- bulk note modal -->
    <transition
      enter-active-class="transition-all duration-150"
      enter-from-class="opacity-0"
      enter-to-class="opacity-100"
      leave-active-class="transition-all duration-100"
      leave-from-class="opacity-100"
      leave-to-class="opacity-0"
    >
      <div
        v-if="showBulkNoteModal"
        class="fixed inset-0 z-50 flex items-center justify-center bg-black/40"
        @click.self="showBulkNoteModal = false"
      >
        <div class="w-full max-w-md rounded-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 shadow-2xl p-5 space-y-3">
          <div class="flex items-center justify-between">
            <p class="text-sm font-semibold text-slate-900 dark:text-white">
              Log note for {{ selectedIds.size }} record{{ selectedIds.size === 1 ? '' : 's' }}
            </p>
            <button
              type="button"
              class="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors"
              @click="showBulkNoteModal = false"
            >
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
                <path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
          <textarea
            ref="bulkNoteInputEl"
            v-model="bulkNoteText"
            rows="4"
            placeholder="Write a note that will be logged for all selected records…"
            class="w-full rounded-lg px-3 py-2 text-sm bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-900 dark:text-slate-100 placeholder-slate-400 resize-none focus:outline-none focus:ring-2 focus:ring-sky-400/40"
            @keydown.meta.enter.prevent="submitBulkNote"
            @keydown.ctrl.enter.prevent="submitBulkNote"
            @keydown.esc.stop="showBulkNoteModal = false"
          />
          <div class="flex items-center justify-between">
            <span class="text-xs text-slate-400 dark:text-slate-500">⌘ Enter to save</span>
            <div class="flex gap-2">
              <button
                type="button"
                class="h-8 px-3 rounded-lg text-sm text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
                @click="showBulkNoteModal = false"
              >
                Cancel
              </button>
              <button
                type="button"
                class="h-8 px-4 rounded-lg text-sm font-medium text-white bg-sky-600 hover:bg-sky-500 transition-colors disabled:opacity-40"
                :disabled="!bulkNoteText.trim()"
                @click="submitBulkNote"
              >
                Log note
              </button>
            </div>
          </div>
        </div>
      </div>
    </transition>

    <!-- bulk add task modal -->
    <transition enter-active-class="transition duration-150 ease-out" enter-from-class="opacity-0 scale-95" enter-to-class="opacity-100 scale-100" leave-active-class="transition duration-100 ease-in" leave-from-class="opacity-100 scale-100" leave-to-class="opacity-0 scale-95">
      <div
        v-if="showBulkTaskModal"
        class="fixed inset-0 z-50 flex items-center justify-center bg-black/40"
        @click.self="showBulkTaskModal = false"
      >
        <div class="w-full max-w-md rounded-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 shadow-2xl p-5 space-y-4">
          <div class="flex items-center justify-between">
            <p class="text-sm font-semibold text-slate-900 dark:text-white">
              Add task to {{ selectedIds.size }} record{{ selectedIds.size === 1 ? '' : 's' }}
            </p>
            <button type="button" class="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors" @click="showBulkTaskModal = false">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
                <path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
          <input
            ref="bulkTaskInputEl"
            v-model="bulkTaskText"
            type="text"
            placeholder="Task description…"
            class="w-full rounded-lg px-3 py-2 text-sm bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-900 dark:text-slate-100 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-sky-400/40"
            @keydown.enter.prevent="submitBulkTask"
            @keydown.esc.stop="showBulkTaskModal = false"
          />
          <div class="flex items-center gap-3 flex-wrap">
            <div class="flex items-center gap-2">
              <span class="text-xs text-slate-400 dark:text-slate-500 shrink-0">Due date</span>
              <input
                v-model="bulkTaskDue"
                type="date"
                class="text-xs px-2 py-1 rounded-md border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-300 focus:outline-none focus:ring-2 focus:ring-sky-400/50"
              />
            </div>
            <div class="flex items-center gap-1.5">
              <span class="text-xs text-slate-400 dark:text-slate-500 shrink-0">Priority</span>
              <button
                v-for="p in (['high', 'medium', 'low'] as const)"
                :key="p"
                type="button"
                class="h-5 px-1.5 rounded text-[10px] font-semibold uppercase tracking-wide transition-colors"
                :class="bulkTaskPriority === p
                  ? p === 'high'   ? 'bg-rose-500 text-white'
                  : p === 'medium' ? 'bg-amber-400 text-white'
                  :                  'bg-slate-400 text-white'
                  : 'bg-slate-100 dark:bg-slate-800 text-slate-400 dark:text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700'"
                @click="bulkTaskPriority = bulkTaskPriority === p ? '' : p"
              >{{ p === 'high' ? 'H' : p === 'medium' ? 'M' : 'L' }}</button>
            </div>
          </div>
          <div class="flex items-center justify-end gap-2">
            <button type="button" class="h-8 px-3 rounded-lg text-sm text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showBulkTaskModal = false">Cancel</button>
            <button
              type="button"
              class="h-8 px-4 rounded-lg text-sm font-medium text-white bg-sky-600 hover:bg-sky-500 transition-colors disabled:opacity-40"
              :disabled="!bulkTaskText.trim()"
              @click="submitBulkTask"
            >Add task</button>
          </div>
        </div>
      </div>
    </transition>

    <!-- column stats modal -->
    <Teleport to="body">
      <div
        v-if="showColStatsModal && colStats"
        class="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm"
        @click.self="showColStatsModal = false"
      >
        <div class="bg-white dark:bg-slate-900 rounded-2xl shadow-2xl w-[420px] max-h-[80vh] flex flex-col overflow-hidden border border-slate-200 dark:border-slate-700">
          <!-- header -->
          <div class="flex items-center justify-between px-5 py-4 border-b border-slate-200 dark:border-slate-700">
            <div>
              <h3 class="text-base font-semibold text-slate-900 dark:text-white">{{ colStats.label }}</h3>
              <p class="text-xs text-slate-400 dark:text-slate-500 mt-0.5">{{ colStats.dataType }}</p>
            </div>
            <button type="button" class="rounded-lg p-1.5 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showColStatsModal = false">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <div class="overflow-y-auto flex-1 px-5 py-4 space-y-4">
            <!-- fill rate -->
            <div>
              <div class="flex items-center justify-between text-xs mb-1.5">
                <span class="text-slate-500 dark:text-slate-400">Fill rate</span>
                <span class="font-semibold text-slate-700 dark:text-slate-200">{{ colStats.filled }} / {{ colStats.total }} ({{ colStats.fillRate }}%)</span>
              </div>
              <div class="h-2 rounded-full bg-slate-100 dark:bg-slate-800 overflow-hidden">
                <div class="h-full rounded-full bg-sky-500 transition-all" :style="`width:${colStats.fillRate}%`" />
              </div>
            </div>
            <!-- number stats -->
            <div v-if="colStats.numMin !== undefined" class="grid grid-cols-3 gap-3">
              <div v-for="stat in [['Min', colStats.numMin], ['Avg', colStats.numAvg], ['Max', colStats.numMax]]" :key="stat[0]" class="rounded-xl bg-slate-50 dark:bg-slate-800 p-3 text-center">
                <div class="text-xs text-slate-400 dark:text-slate-500 mb-1">{{ stat[0] }}</div>
                <div class="text-base font-semibold text-slate-800 dark:text-slate-100 tabular-nums">{{ stat[1] }}</div>
              </div>
            </div>
            <div v-if="colStats.numSum !== undefined" class="flex items-center justify-between rounded-xl bg-slate-50 dark:bg-slate-800 px-4 py-2.5">
              <span class="text-xs text-slate-400 dark:text-slate-500">Sum</span>
              <span class="text-sm font-semibold tabular-nums text-slate-800 dark:text-slate-100">{{ colStats.numSum?.toLocaleString() }}</span>
            </div>
            <!-- distribution chart -->
            <div v-if="colStats.distribution && colStats.distribution.length">
              <div class="flex items-center justify-between mb-2">
                <p class="text-xs font-semibold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Distribution</p>
                <span class="text-[10px] text-slate-300 dark:text-slate-600">click to filter</span>
              </div>
              <div class="space-y-1.5">
                <div
                  v-for="item in colStats.distribution"
                  :key="item.label"
                  class="group/csd flex items-center gap-2 cursor-pointer rounded-md px-1 -mx-1 hover:bg-slate-50 dark:hover:bg-slate-800/60 transition-colors"
                  :title="`Filter to ${item.label} (${item.count} records)`"
                  @click="toggleFilter(colStatsFieldKey, item.label); showColStatsModal = false; showToast(`Filtered to ${item.label}`)"
                >
                  <span class="text-xs text-slate-600 dark:text-slate-300 group-hover/csd:text-sky-600 dark:group-hover/csd:text-sky-400 w-28 shrink-0 truncate transition-colors">{{ item.label }}</span>
                  <div class="flex-1 h-5 rounded-md bg-slate-100 dark:bg-slate-800 overflow-hidden relative">
                    <div
                      class="h-full rounded-md bg-sky-400 dark:bg-sky-600 transition-all"
                      :style="`width:${colStats.distribution && colStats.distribution.length ? Math.round((item.count / Math.max(...colStats.distribution.map(x => x.count))) * 100) : 0}%`"
                    />
                    <span class="absolute inset-0 flex items-center justify-end pr-2 text-xs font-medium text-slate-600 dark:text-slate-300">{{ item.count }}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </Teleport>

    <!-- merge records modal -->
    <Teleport to="body">
      <div v-if="showMergeModal && mergeSourceId && mergeTargetId" class="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm" @click.self="showMergeModal = false">
        <div class="bg-white dark:bg-slate-900 rounded-2xl shadow-2xl w-[560px] max-h-[80vh] flex flex-col overflow-hidden border border-slate-200 dark:border-slate-700">
          <div class="flex items-center justify-between px-5 py-4 border-b border-slate-200 dark:border-slate-700">
            <h3 class="text-base font-semibold text-slate-900 dark:text-white">Merge records</h3>
            <button type="button" class="rounded-lg p-1.5 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showMergeModal = false">
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <div class="overflow-y-auto flex-1 px-5 py-4 space-y-1">
            <div class="grid grid-cols-[1fr_auto_1fr] gap-2 text-xs font-semibold text-slate-400 uppercase tracking-wide mb-3">
              <span class="text-sky-600 dark:text-sky-400">Primary (keep)</span>
              <span />
              <span class="text-right text-rose-500 dark:text-rose-400">Secondary (discard)</span>
            </div>
            <div
              v-for="field in (selectedType?.fields ?? []).slice().sort((a,b) => a.position - b.position)"
              :key="field.key"
              class="grid grid-cols-[1fr_auto_1fr] gap-2 items-center py-1.5 rounded-lg px-1 cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
              @click="mergeFieldChoices[field.key] = mergeFieldChoices[field.key] === 'primary' ? 'secondary' : 'primary'"
            >
              <div :class="mergeFieldChoices[field.key] === 'primary' ? 'text-slate-800 dark:text-slate-100 font-medium' : 'text-slate-300 dark:text-slate-600 line-through'" class="text-sm truncate">
                {{ mockRecords.find(r => r.id === mergeSourceId)?.field_values[field.key] ?? '' }}
              </div>
              <div class="flex flex-col items-center gap-0.5">
                <span class="text-[10px] text-slate-400 dark:text-slate-500 font-medium">{{ field.label }}</span>
                <svg v-if="mergeFieldChoices[field.key] === 'primary'" class="h-3 w-3 text-sky-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                <svg v-else class="h-3 w-3 text-rose-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </div>
              <div :class="mergeFieldChoices[field.key] === 'secondary' ? 'text-slate-800 dark:text-slate-100 font-medium' : 'text-slate-300 dark:text-slate-600 line-through'" class="text-sm truncate text-right">
                {{ mockRecords.find(r => r.id === mergeTargetId)?.field_values[field.key] ?? '' }}
              </div>
            </div>
          </div>
          <div class="flex items-center justify-between px-5 py-4 border-t border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50">
            <p class="text-xs text-slate-500 dark:text-slate-400">Click a row to toggle which value to keep. Secondary record will be deleted.</p>
            <div class="flex items-center gap-2">
              <button type="button" class="h-9 px-4 rounded-xl text-sm font-medium text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors" @click="showMergeModal = false">Cancel</button>
              <button type="button" class="h-9 px-4 rounded-xl text-sm font-semibold bg-rose-500 hover:bg-rose-600 text-white transition-colors" @click="commitMerge">Merge &amp; Delete Secondary</button>
            </div>
          </div>
        </div>
      </div>
    </Teleport>

    <!-- ============ SCHEMA EDITOR PANEL ============ -->
    <Teleport to="body">
      <transition
        enter-active-class="transition-all duration-200 ease-out"
        enter-from-class="opacity-0"
        enter-to-class="opacity-100"
        leave-active-class="transition-all duration-150 ease-in"
        leave-from-class="opacity-100"
        leave-to-class="opacity-0"
      >
        <div v-if="showSchemaEditor" class="fixed inset-0 z-50 flex">
          <!-- backdrop -->
          <div class="absolute inset-0 bg-black/40 backdrop-blur-[1px]" @click="showSchemaEditor = false" />
          <!-- slide-over panel -->
          <transition
            enter-active-class="transition-transform duration-200 ease-out"
            enter-from-class="translate-x-full"
            enter-to-class="translate-x-0"
            leave-active-class="transition-transform duration-150 ease-in"
            leave-from-class="translate-x-0"
            leave-to-class="translate-x-full"
          >
            <div v-if="showSchemaEditor" class="ml-auto relative w-[480px] h-full bg-white dark:bg-slate-900 border-l border-slate-200 dark:border-slate-700 flex flex-col shadow-2xl overflow-hidden">

              <!-- FIELDS MODE -->
              <template v-if="schemaEditorMode === 'fields'">
                <div class="px-5 py-4 border-b border-slate-200 dark:border-slate-700 flex items-center gap-3">
                  <div class="relative shrink-0">
                    <button
                      type="button"
                      class="flex h-8 w-8 items-center justify-center rounded-lg ring-2 ring-transparent hover:ring-slate-300 dark:hover:ring-slate-600 transition-all"
                      :style="{ background: (selectedType?.color ?? '#6366f1') + '22', color: selectedType?.color ?? '#6366f1' }"
                      title="Change type icon &amp; color"
                      @click.stop="showTypeIconColorPicker = !showTypeIconColorPicker"
                    >
                      <component :is="ICON_COMPONENTS[selectedType?.icon ?? 'folder']" class="h-4 w-4" />
                    </button>
                    <!-- icon + color picker popover -->
                    <div
                      v-if="showTypeIconColorPicker && selectedType"
                      class="absolute top-full left-0 mt-1.5 z-50 w-56 rounded-xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 shadow-xl p-3 space-y-3"
                    >
                      <div>
                        <p class="text-[10px] font-semibold uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-1.5">Color</p>
                        <div class="flex flex-wrap gap-1.5">
                          <button
                            v-for="c in SCHEMA_COLOR_PRESETS"
                            :key="c"
                            type="button"
                            class="h-5 w-5 rounded-full transition-transform hover:scale-125 focus:outline-none"
                            :style="{ background: c, boxShadow: selectedType.color === c ? `0 0 0 2px white, 0 0 0 3.5px ${c}` : undefined }"
                            :aria-label="`Set type color: ${c}`"
                            @click.stop="selectedType.color = c"
                          />
                        </div>
                      </div>
                      <div>
                        <p class="text-[10px] font-semibold uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-1.5">Icon</p>
                        <div class="flex flex-wrap gap-1.5">
                          <button
                            v-for="ico in SCHEMA_ICON_OPTIONS"
                            :key="ico"
                            type="button"
                            class="h-7 w-7 rounded-lg flex items-center justify-center transition-colors"
                            :class="selectedType.icon === ico
                              ? 'ring-2 ring-offset-1 ring-violet-400'
                              : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'"
                            :style="selectedType.icon === ico ? { background: (selectedType.color ?? '#6366f1') + '22', color: selectedType.color ?? '#6366f1' } : undefined"
                            :aria-label="`Set icon: ${ico}`"
                            @click.stop="selectedType.icon = ico as IconKey"
                          >
                            <component :is="ICON_COMPONENTS[ico]" class="h-3.5 w-3.5" />
                          </button>
                        </div>
                      </div>
                      <button type="button" class="w-full text-xs text-center text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors py-0.5" @click.stop="showTypeIconColorPicker = false">Done</button>
                    </div>
                  </div>
                  <div class="flex-1 min-w-0">
                    <template v-if="schemaTypeLabelDraft !== null">
                      <input
                        ref="schemaTypeLabelInputEl"
                        v-model="schemaTypeLabelDraft"
                        type="text"
                        class="w-full text-sm font-semibold rounded px-1 py-0.5 bg-white dark:bg-slate-800 border border-violet-400 text-slate-900 dark:text-white focus:outline-none"
                        @keydown.enter.prevent="commitSchemaTypeRename"
                        @keydown.esc.stop="schemaTypeLabelDraft = null"
                        @blur="commitSchemaTypeRename"
                        @click.stop
                      />
                    </template>
                    <template v-else>
                      <h3
                        class="text-sm font-semibold text-slate-900 dark:text-white truncate cursor-text hover:text-violet-600 dark:hover:text-violet-400 transition-colors"
                        title="Double-click to rename type"
                        @dblclick.stop="startSchemaTypeRename"
                      >{{ selectedType?.label ?? 'Type' }} — Fields</h3>
                    </template>
                    <p class="text-xs text-slate-400 dark:text-slate-500 mt-0.5">{{ selectedType?.fields.length ?? 0 }} fields · {{ recordCountByType[selectedTypeKey] ?? 0 }} records</p>
                  </div>
                  <button type="button" class="h-7 w-7 rounded-lg flex items-center justify-center text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showSchemaEditor = false">
                    <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>

                <!-- field list -->
                <div class="flex-1 overflow-y-auto">
                  <div class="divide-y divide-slate-100 dark:divide-slate-800">
                    <div
                      v-for="field in (selectedType?.fields ?? []).slice().sort((a, b) => a.position - b.position)"
                      :key="field.id"
                      draggable="true"
                      class="flex items-center gap-3 px-5 py-3 group/field cursor-grab active:cursor-grabbing transition-colors"
                      :class="[
                        schemaDragOver === field.id && schemaDragSrc !== field.id ? 'border-t-2 border-t-sky-400' : '',
                        schemaDragSrc === field.id ? 'opacity-40' : '',
                      ]"
                      @dragstart.stop="(e) => { schemaDragSrc = field.id; e.dataTransfer && (e.dataTransfer.effectAllowed = 'move'); }"
                      @dragover.prevent="schemaDragOver = field.id"
                      @dragleave="schemaDragOver = null"
                      @drop.prevent="dropSchemaReorder(field.id)"
                      @dragend="() => { schemaDragSrc = null; schemaDragOver = null; }"
                    >
                      <!-- drag handle -->
                      <span class="shrink-0 text-slate-200 dark:text-slate-700 group-hover/field:text-slate-300 dark:group-hover/field:text-slate-600 transition-colors cursor-grab">
                        <svg class="h-3.5 w-3.5" fill="currentColor" viewBox="0 0 24 24"><circle cx="9" cy="6" r="1.5"/><circle cx="15" cy="6" r="1.5"/><circle cx="9" cy="12" r="1.5"/><circle cx="15" cy="12" r="1.5"/><circle cx="9" cy="18" r="1.5"/><circle cx="15" cy="18" r="1.5"/></svg>
                      </span>
                      <!-- data_type icon -->
                      <span class="shrink-0 h-7 w-7 rounded-md flex items-center justify-center bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400">
                        <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
                          <path stroke-linecap="round" stroke-linejoin="round" :d="DATA_TYPE_ICONS[field.data_type]" />
                        </svg>
                      </span>
                      <div class="flex-1 min-w-0">
                        <div class="flex items-center gap-1.5">
                          <input
                            v-if="fieldLabelDraftId === field.id"
                            ref="fieldLabelInputEl"
                            v-model="fieldLabelDraft"
                            type="text"
                            class="text-sm font-medium rounded px-1 py-0.5 bg-white dark:bg-slate-800 border border-violet-400 text-slate-900 dark:text-white focus:outline-none w-36"
                            @keydown.enter.prevent="commitFieldLabelRename"
                            @keydown.esc.stop="fieldLabelDraftId = null"
                            @blur="commitFieldLabelRename"
                            @click.stop
                          />
                          <span
                            v-else
                            class="text-sm font-medium text-slate-900 dark:text-white truncate cursor-text hover:text-violet-600 dark:hover:text-violet-400 transition-colors"
                            title="Double-click to rename field"
                            @dblclick.stop="startFieldLabelRename(field)"
                          >{{ field.label }}</span>
                          <span v-if="field.is_title" class="text-[10px] font-semibold px-1.5 py-0.5 rounded-full bg-sky-50 dark:bg-sky-950/40 text-sky-600 dark:text-sky-400 whitespace-nowrap">Title</span>
                          <button
                            v-if="field.is_required && !field.is_title"
                            type="button"
                            class="text-[10px] font-semibold px-1.5 py-0.5 rounded-full bg-amber-50 dark:bg-amber-950/30 text-amber-600 dark:text-amber-400 whitespace-nowrap hover:bg-amber-100 dark:hover:bg-amber-900/40 transition-colors"
                            title="Click to make optional"
                            @click.stop="field.is_required = false"
                          >Required</button>
                          <button
                            v-else-if="!field.is_required && !field.is_title"
                            type="button"
                            class="text-[10px] font-semibold px-1.5 py-0.5 rounded-full opacity-0 group-hover/field:opacity-100 bg-slate-100 dark:bg-slate-700 text-slate-400 dark:text-slate-500 whitespace-nowrap hover:bg-amber-50 dark:hover:bg-amber-950/30 hover:text-amber-600 dark:hover:text-amber-400 transition-all"
                            title="Click to make required"
                            @click.stop="field.is_required = true"
                          >Optional</button>
                        </div>
                        <div class="text-xs text-slate-400 dark:text-slate-500 mt-0.5 font-mono truncate">
                          {{ field.key }} · {{ field.data_type }}
                          <template v-if="field.select_options?.length"> ·
                            <span
                              v-for="opt in field.select_options"
                              :key="opt"
                              class="inline-flex items-center gap-0.5 mr-0.5"
                            >
                              <span
                                class="inline-block h-2 w-2 rounded-full border border-white/40"
                                :style="field.select_option_colors?.[opt] ? { background: field.select_option_colors[opt] } : { background: '#94a3b8' }"
                              />
                            </span>
                            <button
                              type="button"
                              class="ml-0.5 opacity-0 group-hover/field:opacity-100 text-slate-400 hover:text-violet-500 dark:hover:text-violet-400 transition-all"
                              title="Edit option colors"
                              @click.stop="editOptionColorsFieldId = editOptionColorsFieldId === field.id ? null : field.id"
                            >
                              <svg class="h-3 w-3 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01" /></svg>
                            </button>
                          </template>
                          <template v-if="field.default_value"> · <span class="text-violet-400 dark:text-violet-500">default: {{ field.default_value }}</span></template>
                          <template v-if="field.visible_when"> · <span class="text-sky-400 dark:text-sky-500">if {{ (selectedType?.fields.find(f => f.key === field.visible_when!.fieldKey)?.label ?? field.visible_when.fieldKey) }} {{ field.visible_when.operator === 'eq' ? '=' : field.visible_when.operator === 'neq' ? '≠' : field.visible_when.operator === 'empty' ? 'empty' : '≠ empty' }}{{ field.visible_when.value ? ' ' + field.visible_when.value : '' }}</span></template>
                        </div>
                      </div>
                      <!-- visibility rule button -->
                      <button
                        v-if="!field.is_title"
                        type="button"
                        class="shrink-0 h-7 w-7 rounded-md flex items-center justify-center transition-all opacity-0 group-hover/field:opacity-100"
                        :class="field.visible_when
                          ? 'text-sky-400 dark:text-sky-500 bg-sky-50 dark:bg-sky-950/30'
                          : 'text-slate-300 dark:text-slate-600 hover:text-sky-500 dark:hover:text-sky-400 hover:bg-sky-50 dark:hover:bg-sky-950/20'"
                        :title="field.visible_when ? 'Edit visibility rule' : 'Add visibility rule'"
                        @click.stop="visibilityRuleFieldId = visibilityRuleFieldId === field.id ? null : field.id"
                      >
                        <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path stroke-linecap="round" stroke-linejoin="round" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                      </button>
                      <!-- duplicate field button -->
                      <button
                        v-if="!field.is_title"
                        type="button"
                        class="shrink-0 h-7 w-7 rounded-md flex items-center justify-center text-slate-300 dark:text-slate-600 hover:text-violet-500 dark:hover:text-violet-400 hover:bg-violet-50 dark:hover:bg-violet-950/20 opacity-0 group-hover/field:opacity-100 transition-all"
                        title="Duplicate field"
                        @click.stop="(() => { const type = selectedType; if (!type) return; const newKey = field.key + '_copy'; const newId = field.id + '_dup' + Date.now().toString().slice(-4); type.fields.push({ ...field, id: newId, key: newKey, label: field.label + ' (copy)', is_title: false, is_required: false, position: Math.max(...type.fields.map(f => f.position)) + 1 }); showToast(`Field duplicated`); })()"
                      >
                        <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2" ry="2" /><path stroke-linecap="round" stroke-linejoin="round" d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1" /></svg>
                      </button>
                      <!-- delete button — hidden for title/required fields -->
                      <button
                        v-if="!field.is_title && !field.is_required"
                        type="button"
                        class="shrink-0 h-7 w-7 rounded-md flex items-center justify-center text-slate-300 dark:text-slate-600 hover:text-red-500 dark:hover:text-red-400 hover:bg-red-50 dark:hover:bg-red-950/30 opacity-0 group-hover/field:opacity-100 transition-all"
                        title="Remove field"
                        @click="removeFieldFromType(selectedTypeKey, field.id)"
                      >
                        <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                      <span v-else-if="field.is_title" class="shrink-0 h-7 w-7" />
                    </div>
                    <!-- visibility rule editor — shown inline below field row -->
                    <div
                      v-if="visibilityRuleFieldId === field.id && !field.is_title"
                      class="mx-5 mb-2 rounded-lg border border-sky-200 dark:border-sky-900/60 bg-sky-50/60 dark:bg-sky-950/20 p-3 space-y-2"
                      @click.stop
                    >
                      <p class="text-[10px] font-semibold uppercase tracking-widest text-sky-500 dark:text-sky-400">Visibility rule</p>
                      <div class="flex items-center gap-1.5 flex-wrap">
                        <span class="text-xs text-slate-500 dark:text-slate-400 whitespace-nowrap">Show when</span>
                        <select
                          :value="field.visible_when?.fieldKey ?? ''"
                          class="text-xs px-2 py-1 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-1 focus:ring-sky-400/40"
                          @change="(e) => { const fk = (e.target as HTMLSelectElement).value; if (!fk) { field.visible_when = undefined; return; } field.visible_when = { fieldKey: fk, operator: field.visible_when?.operator ?? 'eq', value: field.visible_when?.value ?? '' }; }"
                        >
                          <option value="">— pick field —</option>
                          <option
                            v-for="f2 in (selectedType?.fields ?? []).filter(f2 => f2.id !== field.id)"
                            :key="f2.key"
                            :value="f2.key"
                          >{{ f2.label }}</option>
                        </select>
                        <select
                          v-if="field.visible_when"
                          :value="field.visible_when.operator"
                          class="text-xs px-2 py-1 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-1 focus:ring-sky-400/40"
                          @change="(e) => { if (field.visible_when) field.visible_when = { ...field.visible_when, operator: (e.target as HTMLSelectElement).value as 'eq' | 'neq' | 'empty' | 'not_empty' }; }"
                        >
                          <option value="eq">= equals</option>
                          <option value="neq">≠ not equals</option>
                          <option value="empty">is empty</option>
                          <option value="not_empty">is not empty</option>
                        </select>
                        <template v-if="field.visible_when && (field.visible_when.operator === 'eq' || field.visible_when.operator === 'neq')">
                          <select
                            v-if="(selectedType?.fields ?? []).find(f2 => f2.key === field.visible_when!.fieldKey)?.data_type === 'select'"
                            :value="field.visible_when.value"
                            class="flex-1 min-w-0 text-xs px-2 py-1 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-1 focus:ring-sky-400/40"
                            @change="(e) => { if (field.visible_when) field.visible_when = { ...field.visible_when, value: (e.target as HTMLSelectElement).value }; }"
                          >
                            <option value="">— any —</option>
                            <option v-for="opt in (selectedType?.fields ?? []).find(f2 => f2.key === field.visible_when!.fieldKey)?.select_options ?? []" :key="opt" :value="opt">{{ opt }}</option>
                          </select>
                          <input
                            v-else
                            :value="field.visible_when.value"
                            type="text"
                            placeholder="value"
                            class="flex-1 min-w-0 text-xs px-2 py-1 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-1 focus:ring-sky-400/40"
                            @input="(e) => { if (field.visible_when) field.visible_when = { ...field.visible_when, value: (e.target as HTMLInputElement).value }; }"
                          />
                        </template>
                      </div>
                      <div class="flex items-center gap-2">
                        <button v-if="field.visible_when" type="button" class="text-xs text-rose-400 hover:text-rose-500 transition-colors" @click="field.visible_when = undefined">Clear rule</button>
                        <button type="button" class="ml-auto text-xs text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors" @click="visibilityRuleFieldId = null">Done</button>
                      </div>
                    </div>
                  </div>

                  <!-- option manager (colors + rename + add/remove) -->
                  <div
                    v-if="editOptionColorsFieldId && selectedType?.fields.find(f => f.id === editOptionColorsFieldId)"
                    class="mx-5 mb-3 px-3 py-3 rounded-lg border border-violet-200 dark:border-violet-800/50 bg-violet-50 dark:bg-violet-950/20 space-y-2"
                    @click.stop
                  >
                    <p class="text-[10px] font-semibold uppercase tracking-wide text-violet-500 dark:text-violet-400">Options</p>
                    <div
                      v-for="(opt, optIdx) in selectedType.fields.find(f => f.id === editOptionColorsFieldId)?.select_options ?? []"
                      :key="opt"
                      class="group/sopt flex items-center gap-2"
                    >
                      <!-- color swatch -->
                      <span
                        class="h-4 w-4 rounded-full border border-white/40 shrink-0"
                        :style="{ background: selectedType.fields.find(f => f.id === editOptionColorsFieldId)?.select_option_colors?.[opt] ?? '#94a3b8' }"
                      />
                      <!-- option name: inline edit or display -->
                      <template v-if="editingSelectOptionKey === editOptionColorsFieldId + ':' + opt">
                        <input
                          :value="editingSelectOptionDraft"
                          type="text"
                          class="flex-1 min-w-0 text-xs px-1.5 py-0.5 rounded border border-violet-400 bg-white dark:bg-slate-900 text-slate-900 dark:text-white outline-none"
                          @input="editingSelectOptionDraft = ($event.target as HTMLInputElement).value"
                          @keydown.enter.prevent="commitRenameSelectOption(editOptionColorsFieldId!, opt)"
                          @keydown.esc.stop="editingSelectOptionKey = null"
                          @blur="commitRenameSelectOption(editOptionColorsFieldId!, opt)"
                          @click.stop
                        />
                      </template>
                      <span
                        v-else
                        class="text-xs text-slate-700 dark:text-slate-300 w-20 truncate shrink-0 cursor-text hover:text-violet-600 dark:hover:text-violet-400 transition-colors"
                        title="Double-click to rename"
                        @dblclick.stop="editingSelectOptionKey = editOptionColorsFieldId + ':' + opt; editingSelectOptionDraft = opt"
                      >{{ opt }}</span>
                      <!-- color swatches -->
                      <div class="flex items-center gap-1 flex-wrap flex-1">
                        <button
                          v-for="hex in OPTION_COLORS"
                          :key="hex"
                          type="button"
                          class="h-4 w-4 rounded-full border-2 transition-transform hover:scale-110"
                          :style="{ background: hex }"
                          :class="selectedType.fields.find(f => f.id === editOptionColorsFieldId)?.select_option_colors?.[opt] === hex ? 'border-white dark:border-slate-900 scale-110' : 'border-transparent'"
                          :title="hex"
                          @click.stop="(() => { const f = selectedType.fields.find(ff => ff.id === editOptionColorsFieldId); if (f) { if (!f.select_option_colors) f.select_option_colors = {}; f.select_option_colors = { ...f.select_option_colors, [opt]: hex }; } })()"
                        />
                        <button
                          type="button"
                          class="h-4 w-4 rounded-full border border-dashed border-slate-300 dark:border-slate-600 text-slate-300 dark:text-slate-600 hover:border-rose-400 hover:text-rose-400 transition-colors flex items-center justify-center"
                          title="Clear color"
                          @click.stop="(() => { const f = selectedType.fields.find(ff => ff.id === editOptionColorsFieldId); if (f?.select_option_colors) { const c = { ...f.select_option_colors }; delete c[opt]; f.select_option_colors = c; } })()"
                        >
                          <svg class="h-2.5 w-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                      </div>
                      <!-- rename + delete buttons — hover reveal -->
                      <button
                        type="button"
                        class="invisible group-hover/sopt:visible shrink-0 rounded p-0.5 text-slate-300 dark:text-slate-600 hover:text-violet-500 dark:hover:text-violet-400 transition-colors"
                        title="Rename option"
                        @click.stop="editingSelectOptionKey = editOptionColorsFieldId + ':' + opt; editingSelectOptionDraft = opt"
                      >
                        <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                      </button>
                      <button
                        type="button"
                        class="invisible group-hover/sopt:visible shrink-0 rounded p-0.5 text-slate-300 dark:text-slate-600 hover:text-rose-400 dark:hover:text-rose-500 transition-colors"
                        title="Remove option"
                        @click.stop="removeSelectOption(editOptionColorsFieldId!, opt)"
                      >
                        <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                      <!-- move up -->
                      <button
                        type="button"
                        class="invisible group-hover/sopt:visible shrink-0 rounded p-0.5 transition-colors"
                        :class="optIdx === 0 ? 'text-slate-200 dark:text-slate-700 cursor-not-allowed' : 'text-slate-300 dark:text-slate-600 hover:text-violet-500 dark:hover:text-violet-400'"
                        :disabled="optIdx === 0"
                        title="Move up"
                        @click.stop="reorderSelectOption(editOptionColorsFieldId!, optIdx, -1)"
                      >
                        <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M5 15l7-7 7 7" /></svg>
                      </button>
                      <!-- move down -->
                      <button
                        type="button"
                        class="invisible group-hover/sopt:visible shrink-0 rounded p-0.5 transition-colors"
                        :class="optIdx === (selectedType.fields.find(f => f.id === editOptionColorsFieldId)?.select_options ?? []).length - 1 ? 'text-slate-200 dark:text-slate-700 cursor-not-allowed' : 'text-slate-300 dark:text-slate-600 hover:text-violet-500 dark:hover:text-violet-400'"
                        :disabled="optIdx === (selectedType.fields.find(f => f.id === editOptionColorsFieldId)?.select_options ?? []).length - 1"
                        title="Move down"
                        @click.stop="reorderSelectOption(editOptionColorsFieldId!, optIdx, 1)"
                      >
                        <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M19 9l-7 7-7-7" /></svg>
                      </button>
                    </div>
                    <!-- add new option row -->
                    <div v-if="newSelectOptionFieldId === editOptionColorsFieldId" class="flex items-center gap-1.5 mt-1">
                      <input
                        :value="newSelectOptionDraft"
                        type="text"
                        placeholder="New option…"
                        class="flex-1 min-w-0 text-xs px-2 py-1 rounded-lg border border-violet-300 dark:border-violet-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white placeholder-slate-400 outline-none focus:ring-1 focus:ring-violet-400/40"
                        @input="newSelectOptionDraft = ($event.target as HTMLInputElement).value"
                        @keydown.enter.prevent="addSelectOption(editOptionColorsFieldId!)"
                        @keydown.esc.stop="newSelectOptionFieldId = null; newSelectOptionDraft = ''"
                        @click.stop
                      />
                      <button type="button" class="shrink-0 h-6 px-2 text-xs rounded-lg bg-violet-600 hover:bg-violet-500 text-white font-medium transition-colors" @click.stop="addSelectOption(editOptionColorsFieldId!)">Add</button>
                      <button type="button" class="shrink-0 h-6 w-6 rounded-lg flex items-center justify-center text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors" @click.stop="newSelectOptionFieldId = null; newSelectOptionDraft = ''">
                        <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                    </div>
                    <div class="flex items-center gap-3 pt-0.5">
                      <button
                        v-if="newSelectOptionFieldId !== editOptionColorsFieldId"
                        type="button"
                        class="flex items-center gap-1 text-xs text-violet-500 dark:text-violet-400 hover:text-violet-600 dark:hover:text-violet-300 transition-colors"
                        @click.stop="newSelectOptionFieldId = editOptionColorsFieldId; newSelectOptionDraft = ''"
                      >
                        <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4" /></svg>
                        Add option
                      </button>
                      <button type="button" class="ml-auto text-xs text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors" @click="editOptionColorsFieldId = null; newSelectOptionFieldId = null; newSelectOptionDraft = ''; editingSelectOptionKey = null">Done</button>
                    </div>
                  </div>

                  <!-- add field form -->
                  <div v-if="showAddFieldForm" class="px-5 py-4 border-t border-slate-100 dark:border-slate-800 space-y-3 bg-slate-50 dark:bg-slate-800/40">
                    <p class="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide">New field</p>
                    <div class="flex gap-2">
                      <div class="flex-1">
                        <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Label</label>
                        <input
                          v-model="newFieldDraft.label"
                          type="text"
                          placeholder="e.g. Close date"
                          class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-violet-400/50 focus:border-violet-400"
                          @keydown.enter="addFieldToCurrentType"
                        />
                      </div>
                      <div>
                        <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Type</label>
                        <select
                          v-model="newFieldDraft.data_type"
                          class="text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-violet-400/50"
                        >
                          <option value="text">Text</option>
                          <option value="number">Number</option>
                          <option value="select">Select</option>
                          <option value="multi_select">Multi-select</option>
                          <option value="rating">Rating (1-5 stars)</option>
                          <option value="date">Date</option>
                          <option value="boolean">Boolean</option>
                          <option value="email">Email</option>
                          <option value="phone">Phone</option>
                          <option value="url">URL</option>
                          <option value="formula">Formula (computed)</option>
                          <option value="rollup">Rollup (aggregated)</option>
                          <option value="checklist">Checklist</option>
                        </select>
                      </div>
                    </div>
                    <div v-if="newFieldDraft.data_type === 'formula'">
                      <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Formula expression</label>
                      <input
                        v-model="newFieldDraft.formula_expression"
                        type="text"
                        placeholder="e.g. {amount} * {probability} / 100"
                        class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-violet-400/50 focus:border-violet-400 font-mono"
                      />
                      <p class="text-[10px] text-slate-400 dark:text-slate-500 mt-1">Use {'{field_key}'} for field values. Supports +,-,*,/ and functions: IF(cond,a,b) · MIN/MAX/ABS/ROUND · CONCAT/LEN/UPPER/LOWER/TRIM · ISBLANK/CONTAINS</p>
                      <!-- live formula preview -->
                      <div v-if="formulaLivePreview" class="mt-2 flex items-center gap-2 rounded-lg border border-violet-100 dark:border-violet-900/40 bg-violet-50/60 dark:bg-violet-950/20 px-2.5 py-1.5">
                        <svg class="h-3 w-3 shrink-0 text-violet-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2">
                          <path stroke-linecap="round" stroke-linejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
                        </svg>
                        <span class="text-[10px] text-violet-400 dark:text-violet-500 shrink-0">Preview</span>
                        <span class="flex-1 text-xs font-mono font-semibold text-violet-700 dark:text-violet-300 truncate">{{ formulaLivePreview }}</span>
                        <span class="text-[10px] text-violet-300 dark:text-violet-600 shrink-0 truncate">using first record</span>
                      </div>
                      <label class="text-xs text-slate-500 dark:text-slate-400 mt-2 mb-1 block">Output format</label>
                      <select v-model="newFieldDraft.formula_format" class="text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-violet-400/50">
                        <option value="">Number</option>
                        <option value="currency">Currency ($)</option>
                        <option value="percent">Percent (%)</option>
                      </select>
                    </div>
                    <div v-if="newFieldDraft.data_type === 'rollup'" class="space-y-2">
                      <div>
                        <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Linked record type</label>
                        <select v-model="newFieldDraft.rollup_from_type" class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-violet-400/50">
                          <option value="">— choose linked type —</option>
                          <option v-for="t in schema" :key="t.key" :value="t.key">{{ t.label }}</option>
                        </select>
                      </div>
                      <div>
                        <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Aggregate function</label>
                        <select v-model="newFieldDraft.rollup_function" class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-violet-400/50">
                          <option value="count">Count (number of linked records)</option>
                          <option value="sum">Sum</option>
                          <option value="avg">Average</option>
                          <option value="min">Min</option>
                          <option value="max">Max</option>
                        </select>
                      </div>
                      <div v-if="newFieldDraft.rollup_function !== 'count' && newFieldDraft.rollup_from_type">
                        <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Field to aggregate</label>
                        <select v-model="newFieldDraft.rollup_field_key" class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-violet-400/50">
                          <option value="">— choose field —</option>
                          <option v-for="f in (schema.find(t => t.key === newFieldDraft.rollup_from_type)?.fields ?? []).filter(f => f.data_type === 'number')" :key="f.key" :value="f.key">{{ f.label }}</option>
                        </select>
                      </div>
                      <p class="text-[10px] text-slate-400 dark:text-slate-500">Rollup reads live values from linked records. Count works without selecting a field.</p>
                    </div>
                    <div v-if="newFieldDraft.data_type === 'select' || newFieldDraft.data_type === 'multi_select'">
                      <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Options (comma-separated)</label>
                      <input
                        v-model="newFieldDraft.select_options_raw"
                        type="text"
                        placeholder="Option A, Option B, Option C"
                        class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-violet-400/50 focus:border-violet-400"
                      />
                    </div>
                    <div v-if="newFieldDraft.data_type !== 'boolean' && newFieldDraft.data_type !== 'checklist' && newFieldDraft.data_type !== 'formula' && newFieldDraft.data_type !== 'rollup'">
                      <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Default value <span class="font-normal opacity-60">(optional)</span></label>
                      <select
                        v-if="(newFieldDraft.data_type === 'select' || newFieldDraft.data_type === 'multi_select') && newFieldDraft.select_options_raw.trim()"
                        v-model="newFieldDraft.default_value"
                        class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-violet-400/50"
                      >
                        <option value="">— none —</option>
                        <option v-for="opt in newFieldDraft.select_options_raw.split(',').map((s: string) => s.trim()).filter(Boolean)" :key="opt" :value="opt">{{ opt }}</option>
                      </select>
                      <input
                        v-else
                        v-model="newFieldDraft.default_value"
                        type="text"
                        :placeholder="newFieldDraft.data_type === 'number' ? 'e.g. 0' : newFieldDraft.data_type === 'date' ? 'e.g. 2026-01-01' : newFieldDraft.data_type === 'select' || newFieldDraft.data_type === 'multi_select' ? 'e.g. Option A' : newFieldDraft.data_type === 'rating' ? '1–5' : 'e.g. Default text'"
                        class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-violet-400/50 focus:border-violet-400"
                      />
                    </div>
                    <div>
                      <label class="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Help text <span class="font-normal opacity-60">(tooltip shown on ? icon)</span></label>
                      <input
                        v-model="newFieldDraft.help_text"
                        type="text"
                        placeholder="Explain what this field means or how to fill it…"
                        class="w-full text-sm px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-violet-400/50 focus:border-violet-400"
                      />
                    </div>
                    <div class="flex gap-2">
                      <button type="button" class="flex-1 h-8 rounded-lg text-sm font-medium text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors" @click="showAddFieldForm = false">Cancel</button>
                      <button type="button" class="flex-1 h-8 rounded-lg text-sm font-semibold bg-violet-500 hover:bg-violet-600 text-white transition-colors" @click="addFieldToCurrentType">Add field</button>
                    </div>
                  </div>

                  <!-- + add field trigger -->
                  <div v-if="!showAddFieldForm" class="px-5 py-3 border-t border-slate-100 dark:border-slate-800">
                    <button type="button" class="w-full flex items-center gap-2 text-sm text-slate-400 hover:text-violet-500 dark:hover:text-violet-400 transition-colors py-1" @click="showAddFieldForm = true">
                      <svg class="h-4 w-4 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4" /></svg>
                      Add field
                    </button>
                  </div>
                </div>

                <!-- danger zone footer -->
                <div class="px-5 py-4 border-t border-slate-200 dark:border-slate-700 bg-slate-50/50 dark:bg-slate-800/20">
                  <div class="flex items-center justify-between">
                    <button
                      type="button"
                      class="flex items-center gap-1.5 text-xs text-slate-400 hover:text-violet-500 dark:hover:text-violet-400 transition-colors"
                      @click="schemaEditorMode = 'new-type'; showAddFieldForm = false"
                    >
                      <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4" /></svg>
                      New type
                    </button>
                    <button
                      type="button"
                      class="flex items-center gap-1.5 text-xs text-slate-400 hover:text-violet-500 dark:hover:text-violet-400 transition-colors"
                      @click="schemaEditorMode = 'sections'; showAddFieldForm = false; sectionNameDraftId = null; sectionAddFieldId = null"
                    >
                      <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M4 6h16M4 10h16M4 14h8M4 18h8" /></svg>
                      Sections
                    </button>
                    <button
                      type="button"
                      class="flex items-center gap-1.5 text-xs transition-colors"
                      :class="(recordCountByType[selectedTypeKey] ?? 0) > 0
                        ? 'text-slate-300 dark:text-slate-600 cursor-not-allowed'
                        : 'text-red-400 hover:text-red-500'"
                      :title="(recordCountByType[selectedTypeKey] ?? 0) > 0 ? 'Remove all records first' : 'Permanently delete this type'"
                      :disabled="(recordCountByType[selectedTypeKey] ?? 0) > 0"
                      @click="deleteRecordType(selectedTypeKey)"
                    >
                      <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      Delete type
                    </button>
                  </div>
                </div>
              </template>

              <!-- SECTIONS MODE -->
              <template v-else-if="schemaEditorMode === 'sections'">
                <div class="px-5 py-4 border-b border-slate-200 dark:border-slate-700 flex items-center gap-3">
                  <h3 class="flex-1 text-sm font-semibold text-slate-900 dark:text-white">Detail panel sections — {{ selectedType?.label }}</h3>
                  <button type="button" class="h-7 w-7 rounded-lg flex items-center justify-center text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showSchemaEditor = false">
                    <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
                <div class="flex-1 overflow-y-auto px-5 py-4 space-y-3">
                  <p class="text-xs text-slate-400 dark:text-slate-500">Group fields into collapsible sections in the record detail panel. Fields not assigned to any section appear in an "Other" group.</p>
                  <!-- section cards -->
                  <div
                    v-for="section in fieldSections.filter(s => s.typeKey === selectedTypeKey)"
                    :key="section.id"
                    class="rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 overflow-hidden"
                  >
                    <!-- section header -->
                    <div class="flex items-center gap-2 px-3 py-2 bg-slate-50/80 dark:bg-slate-800/40 border-b border-slate-100 dark:border-slate-700/60">
                      <template v-if="sectionNameDraftId === section.id">
                        <input
                          v-model="sectionNameDraft"
                          type="text"
                          class="flex-1 text-xs font-semibold rounded px-1.5 py-0.5 bg-white dark:bg-slate-800 border border-violet-400 text-slate-900 dark:text-white focus:outline-none"
                          @keydown.enter.prevent="commitSectionRename"
                          @keydown.esc.stop="sectionNameDraftId = null"
                          @blur="commitSectionRename"
                          @click.stop
                        />
                      </template>
                      <span
                        v-else
                        class="flex-1 text-xs font-semibold text-slate-700 dark:text-slate-200 cursor-text hover:text-violet-600 dark:hover:text-violet-400 transition-colors"
                        title="Click to rename"
                        @click="startSectionRename(section.id)"
                      >{{ section.label }}</span>
                      <span class="text-[10px] text-slate-400 dark:text-slate-500 tabular-nums">{{ section.fieldKeys.length }} field{{ section.fieldKeys.length === 1 ? '' : 's' }}</span>
                      <button
                        type="button"
                        class="text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 transition-colors rounded p-0.5"
                        title="Delete section"
                        @click="deleteSection(section.id)"
                      >
                        <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                    </div>
                    <!-- assigned fields -->
                    <div class="px-3 py-2 space-y-1">
                      <div
                        v-for="fk in section.fieldKeys"
                        :key="fk"
                        class="flex items-center gap-2 group/sf"
                      >
                        <span class="flex-1 text-xs text-slate-600 dark:text-slate-300 truncate">{{ selectedType?.fields.find(f => f.key === fk)?.label ?? fk }}</span>
                        <button
                          type="button"
                          class="invisible group-hover/sf:visible text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 transition-colors rounded p-0.5"
                          title="Remove from section"
                          @click="removeFieldFromSection(section.id, fk)"
                        >
                          <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                      </div>
                      <p v-if="!section.fieldKeys.length" class="text-[10px] text-slate-300 dark:text-slate-600 italic">No fields assigned — add one below</p>
                      <!-- add field dropdown -->
                      <div class="relative mt-1">
                        <button
                          type="button"
                          class="flex items-center gap-1 text-[10px] text-slate-400 hover:text-violet-500 dark:hover:text-violet-400 transition-colors"
                          @click.stop="sectionAddFieldId = sectionAddFieldId === section.id ? null : section.id"
                        >
                          <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4" /></svg>
                          Add field
                        </button>
                        <div
                          v-if="sectionAddFieldId === section.id"
                          class="absolute left-0 top-full mt-1 z-20 w-48 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-lg overflow-hidden"
                          @click.stop
                        >
                          <template v-for="f in (selectedType?.fields ?? []).filter(f => !fieldSections.some(s => s.typeKey === selectedTypeKey && s.fieldKeys.includes(f.key)))" :key="f.id">
                            <button
                              type="button"
                              class="w-full text-left px-3 py-2 text-xs text-slate-700 dark:text-slate-300 hover:bg-violet-50 dark:hover:bg-violet-950/30 hover:text-violet-600 dark:hover:text-violet-400 transition-colors"
                              @click="addFieldToSection(section.id, f.key)"
                            >{{ f.label }}</button>
                          </template>
                          <p
                            v-if="!(selectedType?.fields ?? []).filter(f => !fieldSections.some(s => s.typeKey === selectedTypeKey && s.fieldKeys.includes(f.key))).length"
                            class="px-3 py-2 text-xs text-slate-400 dark:text-slate-500 italic"
                          >All fields assigned</p>
                        </div>
                      </div>
                    </div>
                  </div>
                  <!-- add section -->
                  <button
                    type="button"
                    class="w-full flex items-center justify-center gap-1.5 py-2.5 rounded-xl border-2 border-dashed border-slate-200 dark:border-slate-700 text-xs text-slate-400 hover:text-violet-500 dark:hover:text-violet-400 hover:border-violet-300 dark:hover:border-violet-700 transition-colors"
                    @click="addSection"
                  >
                    <svg class="h-3.5 w-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4" /></svg>
                    New section
                  </button>
                </div>
                <div class="px-5 py-3 border-t border-slate-200 dark:border-slate-700">
                  <button type="button" class="w-full h-9 rounded-xl text-sm font-medium text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors" @click="schemaEditorMode = 'fields'">Back to fields</button>
                </div>
              </template>

              <!-- NEW TYPE MODE -->
              <template v-else>
                <div class="px-5 py-4 border-b border-slate-200 dark:border-slate-700 flex items-center gap-3">
                  <h3 class="flex-1 text-sm font-semibold text-slate-900 dark:text-white">New record type</h3>
                  <button type="button" class="h-7 w-7 rounded-lg flex items-center justify-center text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors" @click="showSchemaEditor = false">
                    <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
                <div class="flex-1 overflow-y-auto px-5 py-5 space-y-5">
                  <div>
                    <label class="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide block mb-2">Type name</label>
                    <input
                      v-model="newTypeDraft.label"
                      type="text"
                      placeholder="e.g. Project, Event, Invoice"
                      class="w-full text-sm px-3 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-violet-400/50 focus:border-violet-400"
                      @keydown.enter="addNewRecordType"
                    />
                    <p class="text-xs text-slate-400 dark:text-slate-500 mt-1.5">
                      Key: <span class="font-mono text-slate-600 dark:text-slate-300">{{ newTypeDraft.key || (newTypeDraft.label.trim().toLowerCase().replace(/[^a-z0-9]+/g, '_') || '…') }}</span>
                    </p>
                  </div>

                  <div>
                    <label class="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide block mb-2">Icon</label>
                    <div class="grid grid-cols-5 gap-2">
                      <button
                        v-for="ico in SCHEMA_ICON_OPTIONS"
                        :key="ico"
                        type="button"
                        class="flex items-center justify-center h-10 rounded-lg border-2 transition-all"
                        :class="newTypeDraft.icon === ico
                          ? 'border-violet-400 bg-violet-50 dark:bg-violet-950/30 text-violet-600 dark:text-violet-400'
                          : 'border-slate-200 dark:border-slate-700 text-slate-400 hover:border-slate-300 dark:hover:border-slate-600 hover:text-slate-700 dark:hover:text-slate-200'"
                        @click="newTypeDraft.icon = ico"
                      >
                        <component :is="ICON_COMPONENTS[ico]" class="h-4.5 w-4.5" />
                      </button>
                    </div>
                  </div>

                  <div>
                    <label class="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide block mb-2">Color</label>
                    <div class="flex flex-wrap gap-2">
                      <button
                        v-for="c in SCHEMA_COLOR_PRESETS"
                        :key="c"
                        type="button"
                        class="h-8 w-8 rounded-lg transition-all border-2"
                        :style="{ background: c }"
                        :class="newTypeDraft.color === c ? 'border-white dark:border-slate-300 scale-110 shadow-md' : 'border-transparent hover:scale-105'"
                        :title="c"
                        @click="newTypeDraft.color = c"
                      />
                    </div>
                  </div>

                  <div class="rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/40 p-4">
                    <p class="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide mb-3">Auto-created fields</p>
                    <div class="space-y-1.5">
                      <div class="flex items-center gap-2 text-xs text-slate-600 dark:text-slate-300">
                        <span class="h-5 w-5 rounded flex items-center justify-center bg-slate-200 dark:bg-slate-700">
                          <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                        </span>
                        <span><b>Name</b> — text, title field (required)</span>
                      </div>
                      <div class="flex items-center gap-2 text-xs text-slate-600 dark:text-slate-300">
                        <span class="h-5 w-5 rounded flex items-center justify-center bg-slate-200 dark:bg-slate-700">
                          <svg class="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M4 6h16M4 10h16M4 14h16M4 18h16" /></svg>
                        </span>
                        <span><b>Status</b> — select: Active, Inactive (editable after creation)</span>
                      </div>
                    </div>
                  </div>
                </div>

                <div class="px-5 py-4 border-t border-slate-200 dark:border-slate-700 flex items-center gap-3">
                  <button type="button" class="flex-1 h-10 rounded-xl text-sm font-medium text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors" @click="schemaEditorMode = 'fields'">Back to fields</button>
                  <button
                    type="button"
                    class="flex-1 h-10 rounded-xl text-sm font-semibold transition-colors"
                    :class="newTypeDraft.label.trim()
                      ? 'bg-violet-500 hover:bg-violet-600 text-white'
                      : 'bg-slate-100 dark:bg-slate-800 text-slate-400 cursor-not-allowed'"
                    :disabled="!newTypeDraft.label.trim()"
                    @click="addNewRecordType"
                  >Create type</button>
                </div>
              </template>

            </div>
          </transition>
        </div>
      </transition>
    </Teleport>

    <!-- calendar overflow popover -->
    <Teleport to="body">
      <div
        v-if="calOverflowDate"
        class="fixed inset-0 z-50"
        @click="calOverflowDate = null"
      >
        <div
          class="absolute bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl shadow-xl p-2 min-w-[180px] max-w-[240px]"
          :style="{ top: `${Math.min(calOverflowPos.y, window.innerHeight - 240)}px`, left: `${Math.min(calOverflowPos.x + 8, window.innerWidth - 248)}px` }"
          @click.stop
        >
          <p class="text-xs font-semibold text-slate-500 dark:text-slate-400 px-1 pb-1.5">{{ calOverflowDate }}</p>
          <button
            v-for="rec in calOverflowRecords"
            :key="rec.id"
            type="button"
            class="w-full text-left text-xs px-2 py-1 rounded-lg truncate text-slate-700 dark:text-slate-200 hover:bg-sky-50 dark:hover:bg-sky-950/40 hover:text-sky-600 dark:hover:text-sky-400 transition-colors"
            @click="openRecord(rec); calOverflowDate = null"
          >{{ rec.title }}</button>
        </div>
      </div>
    </Teleport>

    <!-- score breakdown popover -->
    <Teleport to="body">
      <transition enter-active-class="transition-all duration-150" enter-from-class="opacity-0 scale-95" enter-to-class="opacity-100 scale-100" leave-active-class="transition-all duration-100" leave-from-class="opacity-100 scale-100" leave-to-class="opacity-0 scale-95">
        <div
          v-if="showScoreBreakdown && scoreBreakdownRecord && scoringRulesForType.length"
          class="fixed z-[9999] w-56 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-2xl overflow-hidden"
          :style="{ top: `${scoreBreakdownPos.top}px`, left: `${scoreBreakdownPos.left}px` }"
          @click.stop
        >
          <div class="px-3 pt-3 pb-2 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
            <span class="text-xs font-semibold text-slate-700 dark:text-slate-200">Score breakdown</span>
            <span class="tabular-nums font-bold text-sm" :class="scoreRecord(scoreBreakdownRecord) >= 70 ? 'text-emerald-600 dark:text-emerald-400' : scoreRecord(scoreBreakdownRecord) >= 40 ? 'text-amber-500 dark:text-amber-400' : 'text-slate-500 dark:text-slate-400'">{{ scoreRecord(scoreBreakdownRecord) }}<span class="text-[10px] font-normal text-slate-400 dark:text-slate-500"> / 100</span></span>
          </div>
          <div class="px-3 py-2 space-y-1 max-h-48 overflow-y-auto">
            <div
              v-for="row in scoreBreakdown(scoreBreakdownRecord)"
              :key="row.label"
              class="flex items-center gap-2"
              :class="row.triggered ? '' : 'opacity-40'"
            >
              <svg v-if="row.triggered" class="h-3 w-3 shrink-0 text-emerald-500 dark:text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M5 13l4 4L19 7" /></svg>
              <svg v-else class="h-3 w-3 shrink-0 text-slate-300 dark:text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
              <span class="flex-1 text-[10px] text-slate-600 dark:text-slate-400 truncate" :title="row.label">{{ row.label }}</span>
              <span class="text-[10px] tabular-nums font-semibold shrink-0" :class="row.triggered ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-300 dark:text-slate-600'">{{ row.triggered ? '+' : '' }}{{ row.points }}</span>
            </div>
          </div>
          <div class="px-3 py-2 border-t border-slate-100 dark:border-slate-800">
            <button type="button" class="w-full text-xs text-center text-slate-400 hover:text-violet-600 dark:hover:text-violet-400 transition-colors" @click="showScoreBreakdown = false; showScoringModal = true">Edit scoring rules</button>
          </div>
        </div>
      </transition>
    </Teleport>

    <!-- completeness breakdown popover -->
    <Teleport to="body">
      <transition enter-active-class="transition-all duration-150" enter-from-class="opacity-0 scale-95" enter-to-class="opacity-100 scale-100" leave-active-class="transition-all duration-100" leave-from-class="opacity-100 scale-100" leave-to-class="opacity-0 scale-95">
        <div
          v-if="showCompletenessBreakdown && openedRecord && recordCompleteness.total > 0"
          class="fixed z-[9999] w-56 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-2xl overflow-hidden"
          :style="{ top: `${completenessBreakdownPos.top}px`, left: `${completenessBreakdownPos.left}px` }"
          @click.stop
        >
          <div class="px-3 pt-3 pb-2 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
            <span class="text-xs font-semibold text-slate-700 dark:text-slate-200">Field completeness</span>
            <span class="tabular-nums font-bold text-sm" :class="completenessPercent >= 80 ? 'text-emerald-600 dark:text-emerald-400' : completenessPercent >= 50 ? 'text-amber-500 dark:text-amber-400' : 'text-rose-500 dark:text-rose-400'">{{ recordCompleteness.filled }}<span class="text-[10px] font-normal text-slate-400 dark:text-slate-500"> / {{ recordCompleteness.total }}</span></span>
          </div>
          <div class="px-3 py-2 space-y-0.5 max-h-52 overflow-y-auto">
            <div
              v-for="field in (selectedType?.fields ?? [])"
              :key="field.key"
              class="flex items-center gap-2 rounded px-1 py-0.5 -mx-1 transition-colors"
              :class="recordCompleteness.missing.includes(field.label)
                ? 'opacity-60 cursor-pointer hover:opacity-100 hover:bg-rose-50 dark:hover:bg-rose-950/20 group/cfmiss'
                : ''"
              :title="recordCompleteness.missing.includes(field.label) ? `Click to jump to ${field.label}` : undefined"
              @click="recordCompleteness.missing.includes(field.label) ? scrollToDetailField(field.key) : undefined"
            >
              <svg v-if="!recordCompleteness.missing.includes(field.label)" class="h-3 w-3 shrink-0 text-emerald-500 dark:text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M5 13l4 4L19 7" /></svg>
              <svg v-else class="h-3 w-3 shrink-0 text-slate-300 dark:text-slate-600 group-hover/cfmiss:text-rose-400 dark:group-hover/cfmiss:text-rose-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
              <span class="flex-1 text-[10px] text-slate-600 dark:text-slate-400 truncate" :title="field.label">{{ field.label }}</span>
              <svg v-if="recordCompleteness.missing.includes(field.label)" class="h-2.5 w-2.5 shrink-0 text-slate-300 dark:text-slate-600 group-hover/cfmiss:text-rose-400 dark:group-hover/cfmiss:text-rose-500 opacity-0 group-hover/cfmiss:opacity-100 transition-opacity" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
            </div>
          </div>
        </div>
      </transition>
    </Teleport>

    <!-- activity preview hover popover -->
    <Teleport to="body">
      <transition enter-active-class="transition-all duration-150" enter-from-class="opacity-0 scale-95" enter-to-class="opacity-100 scale-100" leave-active-class="transition-all duration-100" leave-from-class="opacity-100 scale-100" leave-to-class="opacity-0 scale-95">
        <div
          v-if="activityPreviewId && activityPreviewItems.length"
          class="fixed z-[9999] w-60 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-2xl overflow-hidden"
          :style="{ top: `${activityPreviewPos.top}px`, left: `${activityPreviewPos.left}px` }"
          @mouseenter="keepActivityPreview"
          @mouseleave="hideActivityPreview"
          @click.stop
        >
          <div class="px-3 pt-2.5 pb-1.5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
            <span class="text-[10px] font-semibold uppercase tracking-widest text-slate-400 dark:text-slate-500">Recent activity</span>
            <span class="tabular-nums text-[10px] text-slate-400 dark:text-slate-500">{{ activityCountByRecord[activityPreviewId] }} total</span>
          </div>
          <div class="py-1">
            <div
              v-for="act in activityPreviewItems"
              :key="act.id"
              class="flex items-start gap-2 px-3 py-1.5"
            >
              <span
                class="mt-0.5 h-4 w-4 rounded-full flex items-center justify-center shrink-0"
                :class="ACTIVITY_ICON_BG[act.type]"
              >
                <svg class="h-2.5 w-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="1.75">
                  <path stroke-linecap="round" stroke-linejoin="round" :d="ACTIVITY_ICONS[act.type]" />
                </svg>
              </span>
              <div class="flex-1 min-w-0">
                <p class="text-[11px] text-slate-600 dark:text-slate-300 truncate leading-tight">{{ act.content.replace(/^\[[^\]]+\]\s*/, '').slice(0, 80) }}</p>
                <p class="text-[9px] text-slate-400 dark:text-slate-500 mt-0.5">{{ act.author }} · {{ formatRelativeTime(act.created_at) }}</p>
              </div>
            </div>
          </div>
        </div>
      </transition>
    </Teleport>

    <!-- quick-note popover -->
    <teleport to="body">
      <transition
        enter-active-class="transition-all duration-150"
        enter-from-class="opacity-0 scale-95 -translate-y-1"
        enter-to-class="opacity-100 scale-100 translate-y-0"
        leave-active-class="transition-all duration-100"
        leave-from-class="opacity-100 scale-100 translate-y-0"
        leave-to-class="opacity-0 scale-95 -translate-y-1"
      >
        <div
          v-if="quickNoteRecordId"
          class="fixed z-[200] w-80 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-xl p-3 flex flex-col gap-2"
          :style="{ top: quickNotePos.top + 'px', left: quickNotePos.left + 'px' }"
          @click.stop
        >
          <!-- header: record name + type picker -->
          <div class="flex items-center gap-2">
            <p class="flex-1 min-w-0 text-xs text-slate-500 dark:text-slate-400 truncate">
              <span class="font-semibold capitalize">{{ quickNoteType }}</span> · <span>{{ mockRecords.find(r => r.id === quickNoteRecordId)?.title ?? '' }}</span>
            </p>
            <div class="shrink-0 flex items-center gap-0.5 rounded-lg bg-slate-100 dark:bg-slate-800 p-0.5">
              <button
                v-for="t in [{ key: 'note', label: 'Note' }, { key: 'call', label: 'Call' }, { key: 'email', label: 'Email' }, { key: 'meeting', label: 'Meeting' }]"
                :key="t.key"
                type="button"
                class="h-5 px-2 rounded-md text-[10px] font-medium transition-colors"
                :class="quickNoteType === t.key
                  ? 'bg-white dark:bg-slate-700 text-slate-800 dark:text-white shadow-sm'
                  : 'text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300'"
                @click="quickNoteType = t.key as 'note' | 'call' | 'email' | 'meeting'"
              >{{ t.label }}</button>
            </div>
          </div>
          <textarea
            ref="quickNoteInputEl"
            v-model="quickNoteText"
            rows="3"
            :placeholder="quickNoteType === 'call' ? 'Call notes…' : quickNoteType === 'email' ? 'Email summary…' : quickNoteType === 'meeting' ? 'Meeting notes…' : 'Add a note…'"
            class="w-full resize-none rounded-lg border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-sm text-slate-900 dark:text-white placeholder:text-slate-400 px-3 py-2 focus:outline-none focus:ring-2 focus:ring-sky-500 focus:border-transparent"
            @keydown.enter.meta.prevent="submitQuickNote"
            @keydown.escape.prevent="quickNoteRecordId = null"
          />
          <div class="flex items-center justify-between">
            <span class="text-[10px] text-slate-400 dark:text-slate-500">Cmd+Enter to save · Esc to close</span>
            <div class="flex gap-1.5">
              <button type="button" class="text-xs text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors" @click="quickNoteRecordId = null">Cancel</button>
              <button
                type="button"
                class="text-xs font-medium px-2.5 py-1 rounded-lg bg-sky-500 hover:bg-sky-600 text-white transition-colors disabled:opacity-40"
                :disabled="!quickNoteText.trim()"
                @click="submitQuickNote"
              >Save</button>
            </div>
          </div>
        </div>
      </transition>
    </teleport>

    <!-- toast notifications -->
    <div class="fixed bottom-6 left-1/2 -translate-x-1/2 z-50 flex flex-col items-center gap-2 pointer-events-none">
      <transition-group
        enter-active-class="transition-all duration-200"
        enter-from-class="opacity-0 translate-y-2 scale-95"
        enter-to-class="opacity-100 translate-y-0 scale-100"
        leave-active-class="transition-all duration-150"
        leave-from-class="opacity-100 translate-y-0 scale-100"
        leave-to-class="opacity-0 translate-y-1 scale-95"
      >
        <div
          v-for="toast in toasts"
          :key="toast.id"
          class="flex items-center gap-2 rounded-full px-4 py-2 text-sm font-medium shadow-lg bg-slate-900 dark:bg-slate-800 text-white border border-slate-700 dark:border-slate-600"
          :class="toast.action ? 'pointer-events-auto' : ''"
        >
          <svg class="h-3.5 w-3.5 text-emerald-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5">
            <path stroke-linecap="round" stroke-linejoin="round" d="M5 13l4 4L19 7" />
          </svg>
          {{ toast.message }}
          <button
            v-if="toast.action"
            class="ml-1 text-sky-400 hover:text-sky-300 font-semibold text-xs uppercase tracking-wide transition-colors"
            @click.stop="toast.action.fn(); toasts = toasts.filter(t => t.id !== toast.id)"
          >{{ toast.action.label }}</button>
        </div>
      </transition-group>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, reactive, computed, watch, nextTick, defineComponent, h, onMounted } from 'vue';
import AgentHeader from '@pkg/pages/agent/AgentHeader.vue';
import { useTheme } from '@pkg/composables/useTheme';
import DOMPurify from 'dompurify';
import { marked } from 'marked';
marked.setOptions({ gfm: true, breaks: true } as Parameters<typeof marked.setOptions>[0]);

const { isDark, toggleTheme } = useTheme();

// ── Types ──────────────────────────────────────────────────────────────────

type DataType = 'text' | 'number' | 'email' | 'phone' | 'url' | 'boolean' | 'date' | 'select' | 'multi_select' | 'rating' | 'formula' | 'checklist' | 'rollup';
interface ChecklistItem { t: string; d: boolean; }
type IconKey = 'user' | 'building' | 'chart' | 'target' | 'check' | 'folder' | 'tag' | 'list' | 'layers' | 'star';

type FieldFormat = 'currency' | 'percent' | 'progress' | undefined;

interface CrmField {
  id: string;
  key: string;
  label: string;
  data_type: DataType;
  is_title: boolean;
  is_required: boolean;
  position: number;
  select_options?: string[];
  select_option_colors?: Record<string, string>;
  format?: FieldFormat;
  default_value?: string;
  formula_expression?: string;
  visible_when?: { fieldKey: string; operator: 'eq' | 'neq' | 'empty' | 'not_empty'; value: string };
  help_text?: string;
  rollup_from_type?: string;
  rollup_field_key?: string;
  rollup_function?: 'count' | 'sum' | 'avg' | 'min' | 'max';
}

interface CrmRecordType {
  id: string;
  key: string;
  label: string;
  label_plural: string;
  icon: IconKey;
  color: string;
  fields: CrmField[];
}

interface CrmLink {
  target_id: string;
  target_type: string;
  target_title: string;
  role?: string;
}

interface CrmRecord {
  id: string;
  record_type_key: string;
  title: string;
  field_values: Record<string, string | number | boolean | string[] | null>;
  created_at: string;
  updated_at?: string;
  links?: CrmLink[];
}

interface CrmActivity {
  id: string;
  record_id: string;
  type: 'note' | 'email' | 'call' | 'meeting' | 'change';
  content: string;
  author: string;
  created_at: string;
  scheduled_at?: string;
}

interface CrmTaskComment {
  id: string;
  task_id: string;
  author: string;
  text: string;
  created_at: string;
}

interface CrmTask {
  id: string;
  record_id: string;
  text: string;
  done: boolean;
  created_at: string;
  due_date?: string;
  priority?: 'high' | 'medium' | 'low';
  parent_id?: string;
  recurrence?: 'daily' | 'weekly' | 'monthly';
  assignee?: string;
}

interface CrmTaskTemplateItem {
  text: string;
  priority?: 'high' | 'medium' | 'low';
  daysFromNow?: number;
  recurrence?: 'daily' | 'weekly' | 'monthly';
}

interface CrmTaskTemplate {
  id: string;
  name: string;
  description?: string;
  tasks: CrmTaskTemplateItem[];
}

type AutomationActionType = 'set_field' | 'create_task' | 'notify';

interface AutomationRule {
  id: string;
  name: string;
  enabled: boolean;
  trigger_type_key: string;
  trigger_field_key: string;
  trigger_value: string;
  action_type: AutomationActionType;
  action_field_key?: string;
  action_value?: string;
  action_task_text?: string;
  action_message?: string;
}

interface CrmAttachment {
  id: string;
  record_id: string;
  name: string;
  size: number;
  mime_type: string;
  uploaded_by: string;
  uploaded_at: string;
}

interface EmailTemplate {
  id: string;
  name: string;
  body: string; // supports {{name}} and {{field_key}} placeholders
}

interface CadenceStep {
  dayOffset: number;
  type: 'email' | 'call' | 'meeting' | 'note';
  content: string;
}

interface CadenceTemplate {
  id: string;
  name: string;
  description: string;
  steps: CadenceStep[];
}

interface SavedView {
  id: string;
  name: string;
  typeKey: string;
  filters: Array<{ fieldKey: string; value: string }>;
  sortField: string | null;
  sortDir: 'asc' | 'desc';
  sortField2: string | null;
  sortDir2: 'asc' | 'desc';
  viewMode: 'table' | 'kanban' | 'calendar' | 'gallery';
  hiddenCols: string[];
  showPinnedOnly: boolean;
  showWatchedOnly: boolean;
  showIncompleteOnly: boolean;
  groupByField: string | null;
  tagFilters?: string[];
  groupDateMode?: 'week' | 'month' | 'quarter';
  columnWidths?: Record<string, number>;
}

interface FilterPreset {
  id: string;
  name: string;
  typeKey: string;
  filters: Array<{ fieldKey: string; value: string; negate?: boolean }>;
  fieldTextFilters: Record<string, string>;
  numberMinFilters: Record<string, number | null>;
  numberMaxFilters: Record<string, number | null>;
  dateAfterFilters: Record<string, string | null>;
  dateBeforeFilters: Record<string, string | null>;
  showOverdueOnly: boolean;
  showDueSoonOnly: boolean;
  showPinnedOnly: boolean;
  showWatchedOnly: boolean;
  showIncompleteOnly: boolean;
}

