const scoringRulesForType = computed(() =>
  scoringRules.value.filter((r) => r.typeKey === selectedTypeKey.value),
);

function scoreRecord(record: CrmRecord): number {
  const rules = scoringRules.value.filter((r) => r.typeKey === record.record_type_key);
  if (!rules.length) return 0;
  const nowMs = new Date(DUE_TODAY_STR).getTime();
  let total = 0;
  for (const rule of rules) {
    const fv = String(record.field_values[rule.fieldKey] ?? '').trim();
    let matches = false;
    if (rule.condition === 'field_filled') {
      matches = fv.length > 0 && fv !== 'false';
    } else if (rule.condition === 'field_eq') {
      matches = fv.toLowerCase() === rule.value.toLowerCase();
    } else if (rule.condition === 'field_contains') {
      matches = rule.value.length > 0 && fv.toLowerCase().includes(rule.value.toLowerCase());
    } else if (rule.condition === 'field_gt') {
      const n = parseFloat(fv);
      matches = !isNaN(n) && n > parseFloat(rule.value);
    } else if (rule.condition === 'field_lt') {
      const n = parseFloat(fv);
      matches = !isNaN(n) && n < parseFloat(rule.value);
    } else if (rule.condition === 'stage_is') {
      const kf = kanbanField.value;
      if (kf) matches = String(record.field_values[kf.key] ?? '') === rule.value;
    } else if (rule.condition === 'activity_within_days') {
      const days = parseInt(rule.value, 10);
      const lastTs = lastActivityByRecord.value[record.id];
      matches = !!lastTs && nowMs - lastTs <= days * 86_400_000;
    }
    if (matches) total += rule.points;
  }
  return Math.max(0, Math.min(100, total));
}

function scoreBreakdown(record: CrmRecord): Array<{ label: string; points: number; triggered: boolean }> {
  const rules = scoringRules.value.filter((r) => r.typeKey === record.record_type_key);
  const nowMs = new Date(DUE_TODAY_STR).getTime();
  return rules.map((rule) => {
    const fv = String(record.field_values[rule.fieldKey] ?? '').trim();
    let triggered = false;
    if (rule.condition === 'field_filled') triggered = fv.length > 0 && fv !== 'false';
    else if (rule.condition === 'field_eq') triggered = fv.toLowerCase() === rule.value.toLowerCase();
    else if (rule.condition === 'field_contains') triggered = rule.value.length > 0 && fv.toLowerCase().includes(rule.value.toLowerCase());
    else if (rule.condition === 'field_gt') { const n = parseFloat(fv); triggered = !isNaN(n) && n > parseFloat(rule.value); }
    else if (rule.condition === 'field_lt') { const n = parseFloat(fv); triggered = !isNaN(n) && n < parseFloat(rule.value); }
    else if (rule.condition === 'stage_is') { const kf = kanbanField.value; if (kf) triggered = String(record.field_values[kf.key] ?? '') === rule.value; }
    else if (rule.condition === 'activity_within_days') { const days = parseInt(rule.value, 10); const lastTs = lastActivityByRecord.value[record.id]; triggered = !!lastTs && nowMs - lastTs <= days * 86_400_000; }
    const fieldLabel = selectedType.value?.fields.find((f) => f.key === rule.fieldKey)?.label ?? rule.fieldKey;
    const condMap: Record<string, string> = {
      field_filled: 'has a value',
      field_eq: `= "${rule.value}"`,
      field_contains: `contains "${rule.value}"`,
      field_gt: `> ${rule.value}`,
      field_lt: `< ${rule.value}`,
      stage_is: `stage = "${rule.value}"`,
      activity_within_days: `activity within ${rule.value}d`,
    };
    const condLabel = condMap[rule.condition] ?? rule.condition;
    const label = rule.condition === 'activity_within_days' || rule.condition === 'stage_is' ? condLabel : `${fieldLabel} ${condLabel}`;
    return { label, points: rule.points, triggered };
  });
}

function addScoringRule() {
  const cond = scoringDraftCondition.value;
  const pts = parseInt(scoringDraftPoints.value, 10);
  if (isNaN(pts) || pts <= 0) return;
  const needsField = cond !== 'activity_within_days' && cond !== 'stage_is';
  if (needsField && !scoringDraftFieldKey.value) return;
  const needsValue = cond !== 'field_filled';
  if (needsValue && !scoringDraftValue.value.trim()) return;
  scoringRules.value = [...scoringRules.value, {
    id: 'scr-' + Date.now(),
    typeKey: selectedTypeKey.value,
    condition: cond,
    fieldKey: scoringDraftFieldKey.value,
    value: scoringDraftValue.value.trim(),
    points: pts,
  }];
  scoringDraftCondition.value = 'field_filled';
  scoringDraftFieldKey.value = allColumns.value[0]?.key ?? '';
  scoringDraftValue.value = '';
  scoringDraftPoints.value = '10';
}

function deleteScoringRule(id: string) {
  scoringRules.value = scoringRules.value.filter((r) => r.id !== id);
  if (editingScoringRuleId.value === id) editingScoringRuleId.value = null;
}

function startEditScoringRule(rule: ScoringRule) {
  editingScoringRuleId.value = rule.id;
  editingScoringCondition.value = rule.condition;
  editingScoringFieldKey.value = rule.fieldKey;
  editingScoringValue.value = rule.value;
  editingScoringPoints.value = String(rule.points);
}

function commitEditScoringRule() {
  const id = editingScoringRuleId.value;
  if (!id) return;
  const pts = parseInt(editingScoringPoints.value, 10);
  if (isNaN(pts) || pts <= 0) return;
  scoringRules.value = scoringRules.value.map((r) =>
    r.id === id
      ? { ...r, condition: editingScoringCondition.value, fieldKey: editingScoringFieldKey.value, value: editingScoringValue.value.trim(), points: pts }
      : r,
  );
  editingScoringRuleId.value = null;
}

// ── Weekly activity quotas ─────────────────────────────────────────────────
interface ActivityQuota {
  id: string;
  activityType: 'call' | 'email' | 'meeting' | 'note';
  target: number;
}
const activityQuotas = ref<ActivityQuota[]>([
  { id: 'aq-1', activityType: 'call',    target: 20 },
  { id: 'aq-2', activityType: 'email',   target: 30 },
  { id: 'aq-3', activityType: 'meeting', target: 5  },
]);
const showActivityQuotaEditor = ref(false);

const activitiesThisPeriod = computed((): Record<'call' | 'email' | 'meeting' | 'note', { daily: number; weekly: number }> => {
  const nowMs = new Date(DUE_TODAY_STR).getTime();
  const dayAgoMs = nowMs - 86_400_000;
  const weekAgoMs = nowMs - 7 * 86_400_000;
  const counts: Record<'call' | 'email' | 'meeting' | 'note', { daily: number; weekly: number }> = {
    call:    { daily: 0, weekly: 0 },
    email:   { daily: 0, weekly: 0 },
    meeting: { daily: 0, weekly: 0 },
    note:    { daily: 0, weekly: 0 },
  };
  for (const a of mockActivities) {
    if (a.type === 'change') continue;
    const t = a.type as 'call' | 'email' | 'meeting' | 'note';
    const ts = new Date(a.created_at).getTime();
    if (ts >= weekAgoMs) {
      counts[t].weekly++;
      if (ts >= dayAgoMs) counts[t].daily++;
    }
  }
  return counts;
});

function setActivityQuota(activityType: 'call' | 'email' | 'meeting' | 'note', rawVal: string) {
  const n = parseInt(rawVal, 10);
  const existing = activityQuotas.value.find((q) => q.activityType === activityType);
  if (!rawVal || isNaN(n) || n <= 0) {
    if (existing) activityQuotas.value = activityQuotas.value.filter((q) => q.activityType !== activityType);
    return;
  }
  if (existing) {
    existing.target = n;
  } else {
    activityQuotas.value = [...activityQuotas.value, { id: 'aq-' + activityType, activityType, target: n }];
  }
}

function clearActivityQuota(activityType: 'call' | 'email' | 'meeting' | 'note') {
  activityQuotas.value = activityQuotas.value.filter((q) => q.activityType !== activityType);
}

// Cross-record activity: unified feed of activities across all records linked to openedRecord
const crossRecordActivities = computed((): Array<{
  act: CrmActivity;
  record: CrmRecord | undefined;
}> => {
  if (!openedRecord.value) return [];
  const linkedIds = new Set(openedRecord.value.links.map((l) => l.target_id));
  if (!linkedIds.size) return [];
  return mockActivities
    .filter((a) => linkedIds.has(a.record_id))
    .slice()
    .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
    .slice(0, 15)
    .map((a) => ({
      act: a,
      record: mockRecords.find((r) => r.id === a.record_id),
    }));
});

