  kanbanInlineTitle.value = '';
}

function commitKanbanInlineAdd() {
  const ia = kanbanInlineAdd.value;
  const title = kanbanInlineTitle.value.trim();
  if (!ia || !title) { cancelKanbanInlineAdd(); return; }
  const type = selectedType.value;
  const titleField = type?.fields.find((f) => f.is_title);
  const fieldKey = kanbanField.value?.key;
  const fieldValues: Record<string, string | number | boolean | string[] | null> = {};
  if (titleField) fieldValues[titleField.key] = title;
  if (fieldKey && ia.col !== KANBAN_UNASSIGNED) fieldValues[fieldKey] = ia.col;
  const newRecord: CrmRecord = {
    id: 'new-' + selectedTypeKey.value + '-' + String(mockRecords.length),
    record_type_key: selectedTypeKey.value,
    title,
    created_at: new Date().toISOString(),
    field_values: fieldValues,
    links: [],
  };
  mockRecords.push(newRecord);
  mockActivities.unshift({
    id: 'act-create-' + newRecord.id,
    record_id: newRecord.id,
    type: 'change',
    content: 'Record created',
    author: 'You',
    created_at: newRecord.created_at,
  });
  kanbanInlineTitle.value = '';
  showToast(`${type?.label ?? 'Record'} created`);
  nextTick(() => kanbanInlineInputEl.value?.focus());
}

function commitInlineAdd() {
  const title = inlineAddTitle.value.trim();
  showInlineAdd.value = false;
  inlineAddTitle.value = '';
  if (!title) return;
  const type = selectedType.value;
  const titleField = type?.fields.find((f) => f.is_title);
  const newRecord: CrmRecord = {
    id: 'new-' + selectedTypeKey.value + '-' + String(mockRecords.length),
    record_type_key: selectedTypeKey.value,
    title,
    created_at: new Date().toISOString(),
    field_values: titleField ? { [titleField.key]: title } : {},
    links: [],
  };
  mockRecords.push(newRecord);
  openRecord(newRecord);
  showToast(`${type?.label ?? 'Record'} created`);
}

function openFromPalette(record: CrmRecord) {
  showPalette.value = false;
  if (record.record_type_key !== selectedTypeKey.value) {
    selectedTypeKey.value = record.record_type_key;
    searchQuery.value = '';
    sortField.value = null;
    sortDir.value = 'asc';
    viewMode.value = 'table';
  }
  nextTick(() => openRecord(record));
}

function stripCallOutcome(content: string): string {
  return content.replace(/^\[[^\]]+\]\s*/, '');
}

function parseEmailHeader(content: string): { to?: string; subject?: string; cc?: string } | null {
  const m = content.match(/^\[To:\s*([^\]|]+?)(?:\s*\|\s*Subject:\s*([^\]|]+?))?(?:\s*\|\s*Cc:\s*([^\]]+?))?\]/);
  if (!m) return null;
  return { to: m[1]?.trim() || undefined, subject: m[2]?.trim() || undefined, cc: m[3]?.trim() || undefined };
}

function logNote(record: CrmRecord) {
  const text = noteText.value.trim();
  if (!text) return;
  const scheduledDate = noteScheduledAt.value.trim();
  const scheduledTime = noteScheduledTime.value.trim() || '09:00';
  const scheduledAt = scheduledDate ? `${scheduledDate}T${scheduledTime}:00Z` : undefined;
  let content = text;
  if (noteType.value === 'call' && callOutcome.value) {
    const badge = callDuration.value ? `${callOutcome.value} · ${callDuration.value}min` : callOutcome.value;
    content = `[${badge}] ${text}`;
    callOutcome.value = '';
    callDuration.value = '';
  } else if (noteType.value === 'email' && (emailTo.value.trim() || emailSubject.value.trim())) {
    const parts: string[] = [`To: ${emailTo.value.trim() || '—'}`];
    if (emailSubject.value.trim()) parts.push(`Subject: ${emailSubject.value.trim()}`);
    if (emailCc.value.trim()) parts.push(`Cc: ${emailCc.value.trim()}`);
    content = `[${parts.join(' | ')}] ${text}`;
    emailTo.value = '';
    emailSubject.value = '';
    emailCc.value = '';
  }
  mockActivities.unshift({
    id: 'act-' + String(mockActivities.length),
    record_id: record.id,
    type: noteType.value,
    content,
    author: 'You',
    created_at: new Date().toISOString(),
    ...(scheduledAt ? { scheduled_at: scheduledAt } : {}),
  });
  noteText.value = '';
  noteScheduledAt.value = '';
  noteScheduledTime.value = '';
  loggingNote.value = false;
  const label = scheduledDate ? `${noteType.value} scheduled for ${scheduledDate}` : `${noteType.value.charAt(0).toUpperCase() + noteType.value.slice(1)} logged`;
  showToast(label);
}

function startCadence(record: CrmRecord, cad: CadenceTemplate) {
  for (const step of cad.steps) {
    const scheduledDate = dateOffset(step.dayOffset);
    mockActivities.unshift({
      id: `cad-${cad.id}-${step.dayOffset}-${record.id}`,
      record_id: record.id,
      type: step.type,
      content: step.content,
      author: 'You',
      created_at: new Date().toISOString(),
      scheduled_at: `${scheduledDate}T09:00:00Z`,
    });
  }
  showCadencePicker.value = false;
  showToast(`${cad.name} cadence started — ${cad.steps.length} activities scheduled`);
}

function applyEmailTemplate(tpl: EmailTemplate) {
  const rec = openedRecord.value;
  if (!rec) return;
  const typeFields = schema.find((s) => s.key === rec.record_type_key)?.fields ?? [];
  let body = tpl.body.replace(/\{\{name\}\}/g, rec.title);
  for (const field of typeFields) {
    const val = String(rec.field_values[field.key] ?? '');
    body = body.replace(new RegExp(`\\{\\{${field.key}\\}\\}`, 'g'), val);
  }
  noteText.value = body;
  showEmailTemplatePicker.value = false;
  nextTick(() => activityTextareaEl.value?.focus());
}

function deleteActivity(actId: string) {
  const idx = mockActivities.findIndex((a) => a.id === actId);
  if (idx === -1) return;
  const [removed] = mockActivities.splice(idx, 1);
  showToast('Activity deleted', {
    label: 'Undo',
    fn: () => {
      mockActivities.splice(idx, 0, removed);
    },
  });
}

function markActivityHeld(actId: string) {
  const act = mockActivities.find((a) => a.id === actId);
  if (!act) return;
  const prev = act.scheduled_at;
  delete act.scheduled_at;
  showToast('Marked as held', {
    label: 'Undo',
    fn: () => { act.scheduled_at = prev; },
  });
}

function addTask() {
  const text = newTaskDraft.value.trim();
  if (!text || !openedRecord.value) return;
  const due = newTaskDueDraft.value.trim() || undefined;
  const pri = newTaskPriority.value || undefined;
  const rec = newTaskRecurrence.value || undefined;
  const asgn = newTaskAssignee.value || undefined;
  mockTasks.push({
    id: 'tk-' + String(mockTasks.length) + '-' + String(Date.now()).slice(-5),
    record_id: openedRecord.value.id,
    text,
    done: false,
    created_at: new Date().toISOString(),
    ...(due ? { due_date: due } : {}),
    ...(pri ? { priority: pri } : {}),
    ...(rec ? { recurrence: rec } : {}),
    ...(asgn ? { assignee: asgn } : {}),
  });
  newTaskDraft.value = '';
  newTaskDueDraft.value = '';
  newTaskPriority.value = '';
  newTaskRecurrence.value = '';
  newTaskAssignee.value = '';
}

function addSubtask(parentId: string) {
  const text = newSubtaskDraft.value.trim();
  if (!text || !openedRecord.value) return;
  mockTasks.push({
    id: 'stk-' + String(mockTasks.length) + '-' + String(Date.now()).slice(-5),
    record_id: openedRecord.value.id,
    text,
    done: false,
    created_at: new Date().toISOString(),
    parent_id: parentId,
  });
  newSubtaskDraft.value = '';
  addingSubtaskOf.value = null;
  // auto-expand the parent to show new subtask
  const next = new Set(expandedTaskIds.value);
  next.add(parentId);
  expandedTaskIds.value = next;
}

function startTaskEdit(task: CrmTask) {
  editingTaskId.value = task.id;
  editingTaskText.value = task.text;
  editingTaskDue.value = task.due_date ?? '';
  editingTaskPriority.value = task.priority ?? '';
  editingTaskRecurrence.value = task.recurrence ?? '';
  editingTaskAssignee.value = task.assignee ?? '';
}

function saveTaskEdit() {
  const id = editingTaskId.value;
  if (!id) return;
  const task = mockTasks.find((t) => t.id === id);
  if (task) {
    const text = editingTaskText.value.trim();
    if (text) task.text = text;
    task.due_date = editingTaskDue.value.trim() || undefined;
    task.priority = (editingTaskPriority.value as 'high' | 'medium' | 'low') || undefined;
    task.recurrence = (editingTaskRecurrence.value as 'daily' | 'weekly' | 'monthly') || undefined;
    task.assignee = editingTaskAssignee.value || undefined;
  }
  editingTaskId.value = null;
}

function cancelTaskEdit() {
  editingTaskId.value = null;
}

function toggleTask(id: string) {
  const task = mockTasks.find((t) => t.id === id);
  if (!task) return;
  if (!task.done && task.recurrence) {
    // recurring task: mark done momentarily then advance due_date
    task.done = true;
    const advanceDays = task.recurrence === 'daily' ? 1 : task.recurrence === 'weekly' ? 7 : 30;
    const base = task.due_date ?? DUE_TODAY_STR;
    const d = new Date(base);
    d.setDate(d.getDate() + advanceDays);
    const nextDue = d.toISOString().slice(0, 10);
    showToast(`Recurring task rescheduled to ${nextDue}`, { label: 'Undo', fn: () => { task.done = false; task.due_date = base; } });
    setTimeout(() => {
      task.done = false;
      task.due_date = nextDue;
    }, 600);
  } else {
    task.done = !task.done;
  }
}

function deleteTask(id: string) {
  // collect parent + all its subtasks
  const toRemove = mockTasks.reduce<Array<{ idx: number; task: CrmTask }>>((acc, t, i) => {
    if (t.id === id || t.parent_id === id) acc.push({ idx: i, task: t });
    return acc;
  }, []);
  if (!toRemove.length) return;
  const removed = toRemove.map((r) => r.task);
  // splice from highest idx down to preserve indices
  toRemove.slice().reverse().forEach((r) => mockTasks.splice(r.idx, 1));
  showToast(`Task deleted${removed.length > 1 ? ` (+ ${removed.length - 1} subtask${removed.length - 1 === 1 ? '' : 's'})` : ''}`, {
    label: 'Undo',
    fn: () => { removed.forEach((t) => mockTasks.push(t)); },
  });
}

function addTaskComment(taskId: string) {
  const text = (newCommentDraft.value[taskId] ?? '').trim();
  if (!text) return;
  mockTaskComments.push({
    id: `tc-${taskId}-${mockTaskComments.length}`,
    task_id: taskId,
    author: 'You',
    text,
    created_at: new Date().toISOString(),
  });
  newCommentDraft.value = { ...newCommentDraft.value, [taskId]: '' };
}

function deleteTaskComment(commentId: string) {
  const idx = mockTaskComments.findIndex((c) => c.id === commentId);
  if (idx >= 0) mockTaskComments.splice(idx, 1);
}

function toggleTaskComments(taskId: string) {
  const next = new Set(expandedCommentTaskIds.value);
  if (next.has(taskId)) {
    next.delete(taskId);
  } else {
    next.add(taskId);
    nextTick(() => newCommentInputEls.value[taskId]?.focus());
  }
  expandedCommentTaskIds.value = next;
}

function applyTaskTemplate(template: CrmTaskTemplate) {
  if (!openedRecord.value) return;
  const rid = openedRecord.value.id;
  template.tasks.forEach((t) => {
    let due: string | undefined;
    if (t.daysFromNow !== undefined) {
      const d = new Date(DUE_TODAY_STR);
      d.setDate(d.getDate() + t.daysFromNow);
      due = d.toISOString().slice(0, 10);
    }
    const uid = `tpl${rid}${mockTasks.length}${Math.random().toString(36).slice(2, 5)}`;
    mockTasks.push({
      id: uid,
      record_id: rid,
      text: t.text,
      done: false,
      created_at: new Date().toISOString(),
      due_date: due,
      priority: t.priority,
      recurrence: t.recurrence,
    });
  });
  showToast(`"${template.name}" applied — ${template.tasks.length} task${template.tasks.length === 1 ? '' : 's'} created`);
  showTaskTemplateDropdown.value = false;
}

function highlightText(text: string, query: string): Array<{ text: string; match: boolean }> {
  if (!query) return [{ text, match: false }];
  const q = query.toLowerCase();
  const idx = text.toLowerCase().indexOf(q);
  if (idx === -1) return [{ text, match: false }];
  return [
    text.slice(0, idx) ? { text: text.slice(0, idx), match: false } : null,
    { text: text.slice(idx, idx + q.length), match: true },
    text.slice(idx + q.length) ? { text: text.slice(idx + q.length), match: false } : null,
  ].filter((p): p is { text: string; match: boolean } => p !== null);
}

function toggleWatch(id: string) {
  const next = new Set(watchedIds.value);
  if (next.has(id)) {
    next.delete(id);
    showToast('Stopped watching record');
  } else {
    next.add(id);
    showToast('Watching record');
  }
  watchedIds.value = next;
}

function bulkWatch(watch: boolean) {
  const ids = [...selectedIds.value];
  if (!ids.length) return;
  const next = new Set(watchedIds.value);
  for (const id of ids) { if (watch) next.add(id); else next.delete(id); }
  watchedIds.value = next;
  showToast(watch
    ? `Watching ${ids.length} record${ids.length === 1 ? '' : 's'}`
    : `Stopped watching ${ids.length} record${ids.length === 1 ? '' : 's'}`);
}

function setColorLabel(recordId: string, color: string) {
  if (color) { colorLabels.value = { ...colorLabels.value, [recordId]: color }; }
  else { const next = { ...colorLabels.value }; delete next[recordId]; colorLabels.value = next; }
}

function parseChecklist(val: unknown): ChecklistItem[] {
  if (!val || typeof val !== 'string') return [];
  try { return JSON.parse(val) as ChecklistItem[]; } catch { return []; }
}

function serializeChecklist(items: ChecklistItem[]): string {
  return JSON.stringify(items);
}

function toggleChecklistItem(record: CrmRecord, fieldKey: string, idx: number) {
  const items = parseChecklist(record.field_values[fieldKey]);
  if (!items[idx]) return;
  items[idx] = { ...items[idx], d: !items[idx].d };
  record.field_values[fieldKey] = serializeChecklist(items);
}

function addChecklistItem(record: CrmRecord, fieldKey: string) {
  const key = `${record.id}|${fieldKey}`;
  const text = (checklistAddText.value[key] ?? '').trim();
  if (!text) return;
  const items = parseChecklist(record.field_values[fieldKey]);
  items.push({ t: text, d: false });
  record.field_values[fieldKey] = serializeChecklist(items);
  checklistAddText.value = { ...checklistAddText.value, [key]: '' };
}

function removeChecklistItem(record: CrmRecord, fieldKey: string, idx: number) {
  const items = parseChecklist(record.field_values[fieldKey]);
  items.splice(idx, 1);
  record.field_values[fieldKey] = serializeChecklist(items);
}

function commitChecklistItemRename(record: CrmRecord, fieldKey: string, idx: number) {
  const key = `${record.id}|${fieldKey}|${idx}`;
  if (editingChecklistItemKey.value !== key) return;
  editingChecklistItemKey.value = null;
  const draft = editingChecklistItemDraft.value.trim();
  if (!draft) return;
  const items = parseChecklist(record.field_values[fieldKey]);
  if (!items[idx] || items[idx].t === draft) return;
  items[idx] = { ...items[idx], t: draft };
  record.field_values[fieldKey] = serializeChecklist(items);
}

function addTag(recordId: string, tag: string) {
  const t = tag.trim().toLowerCase();
  if (!t) return;
  const existing = recordTags.value[recordId] ?? [];
  if (existing.includes(t)) return;
  recordTags.value = { ...recordTags.value, [recordId]: [...existing, t] };
}

function removeTag(recordId: string, tag: string) {
  const existing = recordTags.value[recordId] ?? [];
  const next = existing.filter((x) => x !== tag);
  recordTags.value = { ...recordTags.value, [recordId]: next };
}

function openTagColorPicker(tag: string, evt: MouseEvent) {
  const rect = (evt.currentTarget as HTMLElement).getBoundingClientRect();
  tagColorPickerPos.value = { top: rect.bottom + 4, left: Math.min(rect.left, window.innerWidth - 160) };
  if (tagColorPickerTag.value === tag) { tagColorPickerTag.value = null; return; }
  tagColorPickerTag.value = tag;
  renamingTagDraft.value = tag;
}

function renameTag(oldName: string, newName: string) {
  const trimmed = newName.trim();
  if (!trimmed || trimmed === oldName) return;
  const next: Record<string, string[]> = {};
  for (const [id, tags] of Object.entries(recordTags.value)) {
    next[id] = tags.map((t) => (t === oldName ? trimmed : t));
  }
  recordTags.value = next;
  if (tagColors.value[oldName]) {
    const nc = { ...tagColors.value, [trimmed]: tagColors.value[oldName] };
    delete nc[oldName];
    tagColors.value = nc;
  }
  showToast(`Tag renamed to "${trimmed}"`);
}

function setTagColor(tag: string, colorId: TagColorId | null) {
  if (!colorId) {
    const next = { ...tagColors.value };
    delete next[tag];
    tagColors.value = next;
  } else {
    tagColors.value = { ...tagColors.value, [tag]: colorId };
  }
  tagColorPickerTag.value = null;
}

function tagStyle(tag: string): Record<string, string> {
  const colorId = tagColors.value[tag];
  const palette = colorId ? TAG_COLOR_PALETTE.find((c) => c.id === colorId) : null;
  if (!palette) return {};
  return { backgroundColor: palette.bg, color: palette.text };
}

const allTags = computed((): string[] => {
  const set = new Set<string>();
  for (const tags of Object.values(recordTags.value)) {
    for (const t of tags) set.add(t);
  }
  return Array.from(set).sort();
});

const sharedSelectedTags = computed((): string[] => {
  const ids = [...selectedIds.value];
  if (!ids.length) return [];
  const sets = ids.map((id) => new Set(recordTags.value[id] ?? []));
  return Array.from(sets[0]).filter((t) => sets.every((s) => s.has(t))).sort();
});

const tagSuggestions = computed((): string[] => {
  if (!tagInput.value.trim() || !openedRecord.value) return [];
  const q = tagInput.value.toLowerCase();
  const existing = new Set(recordTags.value[openedRecord.value.id] ?? []);
  return allTags.value.filter((t) => t !== q && t.includes(q) && !existing.has(t)).slice(0, 5);
});

function addBulkTag(tag: string) {
  const t = tag.trim();
  if (!t) return;
  for (const id of selectedIds.value) {
    addTag(id, t);
  }
  bulkTagInput.value = '';
  showToast(`Tag "${t}" added to ${selectedIds.value.size} record${selectedIds.value.size === 1 ? '' : 's'}`);
}

function removeBulkTag(tag: string) {
  for (const id of selectedIds.value) {
    removeTag(id, tag);
  }
  showToast(`Tag "${tag}" removed from ${selectedIds.value.size} record${selectedIds.value.size === 1 ? '' : 's'}`);
}

function moveCardStage(record: CrmRecord, dir: 1 | -1) {
  const fieldKey = kanbanField.value?.key;
  if (!fieldKey) return;
  const cols = kanbanColumns.value.filter((c) => c !== KANBAN_UNASSIGNED);
  const currentVal = String(record.field_values[fieldKey] ?? '');
  const idx = cols.indexOf(currentVal);
  const nextIdx = idx + dir;
  if (nextIdx < 0 || nextIdx >= cols.length) return;
  record.field_values[fieldKey] = cols[nextIdx];
  showToast(`Stage: ${cols[nextIdx]}`);
}

function dropCardToColumn(targetCol: string) {
  const id = kanbanDragCardId.value;
  kanbanDragCardId.value = null;
  kanbanDragOverCol.value = null;
  if (!id) return;
  const fieldKey = kanbanField.value?.key;
  if (!fieldKey) return;
  const record = mockRecords.find((r) => r.id === id);
  if (!record) return;
  const newVal = targetCol === KANBAN_UNASSIGNED ? null : targetCol;
  if (record.field_values[fieldKey] === newVal) return;
  const prevVal = record.field_values[fieldKey];
  record.field_values[fieldKey] = newVal;
  record.updated_at = new Date().toISOString();
  const label = targetCol === KANBAN_UNASSIGNED ? 'Moved to Unassigned' : `Moved to ${targetCol}`;
  showToast(label, {
    label: 'Undo',
    fn: () => { record.field_values[fieldKey] = prevVal; showToast('Move undone'); },
  });
}

function addLink(record: CrmRecord, target: CrmRecord) {
  if (!record.links) record.links = [];
  if (record.links.some((l) => l.target_id === target.id)) return;
  record.links.push({
    target_id: target.id,
    target_title: target.title,
    target_type: target.record_type_key,
  });
  linkQuery.value = '';
  linkDropdownOpen.value = false;
  showToast(`Linked to ${target.title}`);
}

function removeLink(record: CrmRecord, targetId: string) {
  if (!record.links) return;
  record.links = record.links.filter((l) => l.target_id !== targetId);
  showToast('Link removed');
}

function startEditLinkRole(targetId: string, currentRole?: string) {
  editingLinkRoleId.value = targetId;
  linkRoleDraft.value = currentRole ?? '';
}

function commitLinkRole(record: CrmRecord) {
  const id = editingLinkRoleId.value;
  if (!id || !record.links) { editingLinkRoleId.value = null; return; }
  const link = record.links.find((l) => l.target_id === id);
  if (link) link.role = linkRoleDraft.value.trim() || undefined;
  editingLinkRoleId.value = null;
  linkRoleDraft.value = '';
}

function commitCreateAndLink(record: CrmRecord) {
  const title = createLinkTitle.value.trim();
  const typeKey = createLinkTypeKey.value || schema[0]?.key;
  if (!title || !typeKey) return;
  const type = schema.find((t) => t.key === typeKey);
  if (!type) return;
  const titleField = type.fields.find((f) => f.is_title);
  const fieldValues: Record<string, string | number | boolean | string[] | null> = {};
  if (titleField) fieldValues[titleField.key] = title;
  const newRecord: CrmRecord = {
    id: 'new-' + typeKey + '-' + String(mockRecords.length),
    record_type_key: typeKey,
    title,
    created_at: new Date().toISOString(),
    field_values: fieldValues,
    links: [],
  };
  mockRecords.push(newRecord);
  addLink(record, newRecord);
  createLinkTitle.value = '';
  showCreateLinkForm.value = false;
  showToast(`Created & linked ${type.label}: ${title}`);
}

function startAnnotate(fieldKey: string, recordId: string) {
  annotatingField.value = fieldKey;
  annotationDraft.value = fieldAnnotations.value[`${recordId}|${fieldKey}`] ?? '';
}

function commitAnnotation(recordId: string, fieldKey: string) {
  const text = annotationDraft.value.trim();
  const key = `${recordId}|${fieldKey}`;
  if (text) {
    fieldAnnotations.value = { ...fieldAnnotations.value, [key]: text };
  } else {
    const copy = { ...fieldAnnotations.value };
    delete copy[key];
    fieldAnnotations.value = copy;
  }
  annotatingField.value = null;
  annotationDraft.value = '';
}

function cancelAnnotation() {
  annotatingField.value = null;
  annotationDraft.value = '';
}

async function copyFieldValue(value: unknown) {
  const text = value == null ? '' : String(value).trim();
  if (!text) return;
  try {
    await navigator.clipboard.writeText(text);
    showToast('Copied');
  } catch {
    // clipboard unavailable in non-secure context — silent fail
  }
}

async function copyRecordLink(record: CrmRecord) {
  try {
    await navigator.clipboard.writeText(`crm://record/${record.id}`);
    showToast('Link copied');
  } catch {
    // silent fail in non-secure context
  }
}

function onRowDragStart(e: DragEvent, id: string) {
  dragSrcId.value = id;
  if (e.dataTransfer) { e.dataTransfer.effectAllowed = 'move'; e.dataTransfer.setData('text/plain', id); }
}

function onRowDragOver(e: DragEvent, id: string) {
  e.preventDefault();
  if (e.dataTransfer) e.dataTransfer.dropEffect = 'move';
  dragOverId.value = id;
}

function onRowDrop(e: DragEvent, targetId: string) {
  e.preventDefault();
  const srcId = dragSrcId.value;
  dragSrcId.value = null;
  dragOverId.value = null;
  if (!srcId || srcId === targetId) return;
  const ids = filteredRecords.value.map((r) => r.id);
  const order = customOrder.value.length ? [...customOrder.value] : [...ids];
  const srcIdx = order.indexOf(srcId);
  const tgtIdx = order.indexOf(targetId);
  if (srcIdx === -1 || tgtIdx === -1) return;
  order.splice(srcIdx, 1);
  order.splice(tgtIdx, 0, srcId);
  customOrder.value = order;
}

function onRowDragEnd() {
  dragSrcId.value = null;
  dragOverId.value = null;
}

async function copyRecordAsText(record: CrmRecord) {
  const fields = selectedType.value?.fields ?? [];
  const lines: string[] = [record.title, ''];
  for (const f of fields) {
    const v = record.field_values[f.key];
    if (v != null && String(v).trim()) lines.push(`${f.label}: ${String(v)}`);
  }
  try {
    await navigator.clipboard.writeText(lines.join('\n'));
    showToast('Copied as text');
  } catch { /* silent fail */ }
}

function recordCompleteness(record: CrmRecord): number {
  const fields = selectedType.value?.fields ?? [];
  if (!fields.length) return 100;
  const filled = fields.filter((f) => {
    const v = record.field_values[f.key];
    if (Array.isArray(v)) return v.length > 0;
    return v != null && String(v).trim() !== '';
  }).length;
  return Math.round((filled / fields.length) * 100);
}

function fieldIsVisible(field: CrmField, record: CrmRecord): boolean {
  const cond = field.visible_when;
  if (!cond) return true;
  const rawVal = record.field_values[cond.fieldKey];
  const strVal = rawVal == null ? '' : String(rawVal);
  if (cond.operator === 'empty') return strVal === '';
  if (cond.operator === 'not_empty') return strVal !== '';
  if (cond.operator === 'eq') return strVal === cond.value;
  if (cond.operator === 'neq') return strVal !== cond.value;
  return true;
}

function cycleSelectField(record: CrmRecord, field: CrmField) {
  const opts = field.select_options ?? [];
  if (!opts.length) return;
  const cur = String(record.field_values[field.key] ?? '');
  const idx = opts.indexOf(cur);
  record.field_values[field.key] = opts[(idx + 1) % opts.length];
}

function deleteRecord(record: CrmRecord) {
  if (pendingDeleteTimer) clearTimeout(pendingDeleteTimer);
  pendingDeleteId.value = null;
  const idx = mockRecords.indexOf(record);
  const wasPinned = pinnedIds.value.has(record.id);
  const wasWatched = watchedIds.value.has(record.id);
  // Snapshot for undo
  if (deletedSnapshotTimer) clearTimeout(deletedSnapshotTimer);
  deletedSnapshot.value = { record, idx: Math.max(0, idx), wasPinned, wasWatched };
  deletedSnapshotTimer = setTimeout(() => { deletedSnapshot.value = null; }, 5000);
  if (idx >= 0) mockRecords.splice(idx, 1);
  // soft-delete: keep in trash for recovery
  trashedRecords.unshift({ record, idx: Math.max(0, idx), deletedAt: new Date().toISOString() });
  if (openedRecord.value?.id === record.id) closePanel();
  const nextPinned = new Set(pinnedIds.value); nextPinned.delete(record.id); pinnedIds.value = nextPinned;
  const nextWatched = new Set(watchedIds.value); nextWatched.delete(record.id); watchedIds.value = nextWatched;
  const nextSelected = new Set(selectedIds.value); nextSelected.delete(record.id); selectedIds.value = nextSelected;
  recentRecords.value = recentRecords.value.filter((r) => r.id !== record.id);
  closeContextMenu();
  showToast('Record deleted', { label: 'Undo', fn: restoreDeletedRecord });
}

function restoreDeletedRecord() {
  const snap = deletedSnapshot.value;
  if (!snap) return;
  if (deletedSnapshotTimer) clearTimeout(deletedSnapshotTimer);
  deletedSnapshot.value = null;
  const insertIdx = Math.min(snap.idx, mockRecords.length);
  mockRecords.splice(insertIdx, 0, snap.record);
  // also remove from trash
  const ti = trashedRecords.findIndex((t) => t.record.id === snap.record.id);
  if (ti >= 0) trashedRecords.splice(ti, 1);
  if (snap.wasPinned) { const next = new Set(pinnedIds.value); next.add(snap.record.id); pinnedIds.value = next; }
  if (snap.wasWatched) { const next = new Set(watchedIds.value); next.add(snap.record.id); watchedIds.value = next; }
  showToast('Delete undone');
}

function submitBulkFieldFill() {
  const key = bulkFieldKey.value;
  if (!key) return;
  const ids = [...selectedIds.value];
  const field = allColumns.value.find((c) => c.key === key);
  const now = new Date().toISOString();
  for (const id of ids) {
    const rec = mockRecords.find((r) => r.id === id);
    if (!rec) continue;
    const prev = rec.field_values[key];
    rec.field_values[key] = bulkFieldValue.value;
    rec.updated_at = now;
    if (String(prev ?? '') !== String(bulkFieldValue.value ?? '')) {
      mockActivities.unshift({
        id: 'act-bff-' + id + '-' + String(mockActivities.length),
        record_id: id,
        type: 'change',
        content: `${field?.label ?? key}: ${prev ?? '—'} → ${bulkFieldValue.value ?? '—'}`,
        author: 'You',
        created_at: now,
      });
    }
  }
  showBulkFieldModal.value = false;
  showToast(`${field?.label ?? key} updated for ${ids.length} record${ids.length === 1 ? '' : 's'}`);
}

function submitBulkNote() {
  const text = bulkNoteText.value.trim();
  if (!text) return;
  const ids = [...selectedIds.value];
  const now = new Date().toISOString();
  for (const id of ids) {
    mockActivities.unshift({
      id: 'act-bulk-' + id + '-' + String(mockActivities.length),
      record_id: id,
      type: 'note',
      content: text,
      author: 'You',
      created_at: now,
    });
  }
  showBulkNoteModal.value = false;
  showToast(`Note logged for ${ids.length} record${ids.length === 1 ? '' : 's'}`);
}

function submitBulkTask() {
  const text = bulkTaskText.value.trim();
  if (!text) return;
  const ids = [...selectedIds.value];
  const now = new Date().toISOString();
  for (const id of ids) {
    mockTasks.push({
      id: `btask-${id}-${mockTasks.length}`,
      record_id: id,
      text,
      done: false,
      created_at: now,
      due_date: bulkTaskDue.value || undefined,
      priority: (bulkTaskPriority.value as 'high' | 'medium' | 'low') || undefined,
    });
  }
  showBulkTaskModal.value = false;
  showToast(`Task added to ${ids.length} record${ids.length === 1 ? '' : 's'}`);
}

function saveCurrentView() {
  const name = saveViewName.value.trim();
  if (!name) return;
  const view: SavedView = {
    id: 'sv-' + String(Date.now()) + '-' + String(savedViews.value.length),
    name,
    typeKey: selectedTypeKey.value,
    filters: activeFilters.value.slice(),
    sortField: sortField.value,
    sortDir: sortDir.value,
    sortField2: sortField2.value,
    sortDir2: sortDir2.value,
    viewMode: viewMode.value,
    hiddenCols: [...hiddenColumnKeys.value],
    showPinnedOnly: showPinnedOnly.value,
    showWatchedOnly: showWatchedOnly.value,
    showIncompleteOnly: showIncompleteOnly.value,
    groupByField: groupByField.value,
    tagFilters: [...tagFilters.value],
    groupDateMode: groupDateMode.value,
    columnWidths: { ...columnWidths.value },
  };
  savedViews.value = [...savedViews.value, view];
  showSaveViewPopover.value = false;
  showToast('View saved');
}

function applySavedView(view: SavedView) {
  selectedTypeKey.value = view.typeKey;
  activeFilters.value = view.filters.slice();
  sortField.value = view.sortField;
  sortDir.value = view.sortDir;
  sortField2.value = view.sortField2 ?? null;
  sortDir2.value = view.sortDir2 ?? 'asc';
  viewMode.value = view.viewMode;
  hiddenColumnKeys.value = new Set(view.hiddenCols);
  showPinnedOnly.value = view.showPinnedOnly;
  showWatchedOnly.value = view.showWatchedOnly;
  showIncompleteOnly.value = view.showIncompleteOnly ?? false;
  groupByField.value = view.groupByField ?? null;
  tagFilters.value = new Set(view.tagFilters ?? []);
  groupDateMode.value = view.groupDateMode ?? 'month';
  if (view.columnWidths) columnWidths.value = { ...view.columnWidths };
  searchQuery.value = '';
  closePanel();
}

function deleteSavedView(id: string) {
  savedViews.value = savedViews.value.filter((v) => v.id !== id);
}

function duplicateSavedView(sv: SavedView) {
  const copy: SavedView = {
    ...JSON.parse(JSON.stringify(sv)),
    id: 'sv-' + String(Date.now()) + '-' + String(savedViews.value.length),
    name: sv.name + ' (copy)',
  };
  savedViews.value = [...savedViews.value, copy];
  showToast(`View duplicated as "${copy.name}"`);
}

function startRenameView(sv: SavedView) {
  renamingViewId.value = sv.id;
  renameViewDraft.value = sv.name;
}

function commitRenameView() {
  const id = renamingViewId.value;
  const name = renameViewDraft.value.trim();
  if (id && name) {
    savedViews.value = savedViews.value.map(v => v.id === id ? { ...v, name } : v);
  }
  renamingViewId.value = null;
}

function openTypeContextMenu(typeKey: string, e: MouseEvent) {
  typeContextMenu.value = { key: typeKey, x: e.clientX, y: e.clientY };
}

function startTypeRename(typeKey: string) {
  const type = schema.find((t) => t.key === typeKey);
  if (!type) return;
  renamingTypeKey.value = typeKey;
  renameTypeDraft.value = type.label;
}

function commitTypeRename() {
  const typeKey = renamingTypeKey.value;
  renamingTypeKey.value = null;
  if (!typeKey) return;
  const draft = renameTypeDraft.value.trim();
  if (!draft) return;
  const type = schema.find((t) => t.key === typeKey);
  if (!type) return;
  const oldLabel = type.label;
  type.label = draft;
  if (type.label_plural === oldLabel + 's' || type.label_plural === oldLabel) {
    type.label_plural = draft.endsWith('s') ? draft : draft + 's';
  }
  showToast(`Type renamed to "${draft}"`);
}

function duplicateRecord(record: CrmRecord) {
  const newRecord: CrmRecord = {
    id: 'dup-' + record.id + '-' + String(mockRecords.length),
    record_type_key: record.record_type_key,
    title: 'Copy of ' + record.title,
    created_at: new Date().toISOString(),
    field_values: { ...record.field_values },
    links: [],
  };
  mockRecords.push(newRecord);
  openRecord(newRecord);
  showToast('Record duplicated');
}

function goBack() {
  const prev = navigationStack.value[navigationStack.value.length - 1];
  if (!prev) return;
  navigationStack.value = navigationStack.value.slice(0, -1);
  if (prev.typeKey !== selectedTypeKey.value) {
    selectedTypeKey.value = prev.typeKey;
    searchQuery.value = '';
    sortField.value = null;
    sortDir.value = 'asc';
    viewMode.value = 'table';
  }
  openedRecord.value = prev.record;
  editingRecord.value = false;
  creatingRecord.value = false;
}

function openLinkedRecord(link: CrmLink) {
  const record = mockRecords.find((r) => r.id === link.target_id);
  if (!record) return;
  if (openedRecord.value) {
    navigationStack.value = [...navigationStack.value, { record: openedRecord.value, typeKey: selectedTypeKey.value }];
  }
  if (link.target_type !== selectedTypeKey.value) {
    selectedTypeKey.value = link.target_type;
    searchQuery.value = '';
    sortField.value = null;
    sortDir.value = 'asc';
    viewMode.value = 'table';
  }
  openedRecord.value = record;
  editingRecord.value = false;
  creatingRecord.value = false;
  detailTab.value = 'details';
}

function onKeyEsc() {
  if (showShortcuts.value) { showShortcuts.value = false; return; }
  if (searchInputEl.value && document.activeElement === searchInputEl.value && searchQuery.value) {
    searchQuery.value = '';
    return;
  }
  closePanel();
}

function onGlobalKeydown(e: KeyboardEvent) {
  const tag = (e.target as HTMLElement)?.tagName ?? '';
  const inField = ['INPUT', 'SELECT', 'TEXTAREA'].includes(tag);
  if (e.key === '?' && !inField) {
    showShortcuts.value = !showShortcuts.value;
    return;
  }
  if (e.key === '/' && !inField) {
    e.preventDefault();
    searchInputEl.value?.focus();
    return;
  }
  if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
    e.preventDefault();
    showPalette.value = !showPalette.value;
    return;
  }
  if ((e.metaKey || e.ctrlKey) && e.key === 'a' && !inField && viewMode.value === 'table' && !openedRecord.value && !editingRecord.value && !creatingRecord.value) {
    e.preventDefault();
    toggleAll();
    return;
  }
  if (!inField && openedRecord.value && !editingRecord.value) {
    if (e.key === '1') { detailTab.value = 'details'; e.preventDefault(); return; }
    if (e.key === '2') { detailTab.value = 'activity'; e.preventDefault(); return; }
    if (e.key === '3') { detailTab.value = 'related'; e.preventDefault(); return; }
    if (e.key === '4') { detailTab.value = 'tasks'; e.preventDefault(); return; }
    if (e.key === '5') { detailTab.value = 'files'; e.preventDefault(); return; }
    if (e.key === '6') { detailTab.value = 'notes'; e.preventDefault(); return; }
    if (e.key === '[' && openedRecordIndex.value > 0) { openRecord(filteredRecords.value[openedRecordIndex.value - 1]); e.preventDefault(); return; }
    if (e.key === ']' && openedRecordIndex.value < filteredRecords.value.length - 1) { openRecord(filteredRecords.value[openedRecordIndex.value + 1]); e.preventDefault(); return; }
    if (e.key === 'c' && !e.metaKey && !e.ctrlKey) { copyRecordLink(openedRecord.value); e.preventDefault(); return; }
    if (e.key === 'a' && !e.metaKey && !e.ctrlKey) {
      detailTab.value = 'activity';
      loggingNote.value = true;
      e.preventDefault();
      return;
    }
    if ((e.key === 'Delete' || e.key === 'Backspace') && !e.metaKey && !e.ctrlKey) {
      deleteRecord(openedRecord.value);
      e.preventDefault();
      return;
    }
  }
  if (!inField && !openedRecord.value && !editingRecord.value && !creatingRecord.value) {
    const idx = parseInt(e.key, 10) - 1;
    if (idx >= 0 && idx < schema.length) {
      selectType(schema[idx].key);
      e.preventDefault();
    }
  }
}

function onKeyN(e: KeyboardEvent) {
  const tag = (e.target as HTMLElement)?.tagName ?? '';
  if (['INPUT', 'SELECT', 'TEXTAREA'].includes(tag)) return;
  if (selectedIds.value.size > 0 && !openedRecord.value && !creatingRecord.value) {
    showBulkNoteModal.value = true;
    return;
