function startEditing(record: CrmRecord) {
  preEditSnapshot.value = { ...record.field_values };
  editingRecord.value = true;
}

function validateFieldValue(field: CrmField, value: unknown): string | null {
  if (value == null || String(value).trim() === '') return null;
  const s = String(value).trim();
  if (field.data_type === 'email') {
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(s)) return 'Invalid email format';
  } else if (field.data_type === 'url') {
    try { new URL(s.startsWith('http') ? s : 'https://' + s); } catch { return 'Invalid URL'; }
  } else if (field.data_type === 'phone') {
    if (!/^[\d\s\-+().]{6,}$/.test(s)) return 'Invalid phone number';
  }
  return null;
}

function saveEditing(record: CrmRecord) {
  const fields = selectedType.value?.fields ?? [];
  // Validate required + format
  const errors = new Map<string, string>();
  for (const f of fields) {
    const v = record.field_values[f.key];
    if (f.is_required && (v == null || (typeof v === 'string' && v.trim() === ''))) {
      errors.set(f.key, 'This field is required.');
      continue;
    }
    const fmtErr = validateFieldValue(f, v);
    if (fmtErr) errors.set(f.key, fmtErr);
  }
  if (errors.size > 0) {
    editFormErrors.value = errors;
    return;
  }
  editFormErrors.value = new Map();
  for (const f of fields) {
    const before = preEditSnapshot.value[f.key];
    const after = record.field_values[f.key];
    const beforeStr = before == null ? '' : String(before);
    const afterStr = after == null ? '' : String(after);
    if (beforeStr !== afterStr) {
      mockActivities.unshift({
        id: 'act-chg-' + String(mockActivities.length),
        record_id: record.id,
        type: 'change',
        content: `${f.label}: ${beforeStr || '—'} → ${afterStr || '—'}`,
        author: 'You',
        created_at: new Date().toISOString(),
      });
      runAutomations(record, f.key, record.field_values[f.key]);
    }
  }
  preEditSnapshot.value = {};
  editingRecord.value = false;
  record.updated_at = new Date().toISOString();
}

function onKeyE(e: KeyboardEvent) {
  const tag = (e.target as HTMLElement)?.tagName ?? '';
  if (['INPUT', 'SELECT', 'TEXTAREA'].includes(tag)) return;
  if (openedRecord.value && !editingRecord.value && !creatingRecord.value) {
    startEditing(openedRecord.value);
  }
}

function onKeyP(e: KeyboardEvent) {
  const tag = (e.target as HTMLElement)?.tagName ?? '';
  if (['INPUT', 'SELECT', 'TEXTAREA'].includes(tag)) return;
  if (pinnedCountForType.value > 0) {
    showPinnedOnly.value = !showPinnedOnly.value;
  }
}

function onKeyW(e: KeyboardEvent) {
  const tag = (e.target as HTMLElement)?.tagName ?? '';
  if (['INPUT', 'SELECT', 'TEXTAREA'].includes(tag)) return;
  if (openedRecord.value && !editingRecord.value && !creatingRecord.value) {
    toggleWatch(openedRecord.value.id);
  }
}

function onKeyU(e: KeyboardEvent) {
  const tag = (e.target as HTMLElement)?.tagName ?? '';
  if (['INPUT', 'SELECT', 'TEXTAREA'].includes(tag)) return;
  if (openedRecord.value && !editingRecord.value && !creatingRecord.value) {
    const id = openedRecord.value.id;
    archivedIds.value.has(id) ? unarchiveRecord(id) : archiveRecord(id);
  }
}

function onKeySave() {
  if (creatingRecord.value) { saveNewRecord(); return; }
  if (editingRecord.value && openedRecord.value) { saveEditing(openedRecord.value); }
}

function onKeyArrow(dir: 1 | -1) {
  const tag = document.activeElement?.tagName ?? '';
  if (['INPUT', 'SELECT', 'TEXTAREA'].includes(tag)) return;
  if (viewMode.value === 'gallery' && !groupedGalleryGroups.value) {
    const records = filteredRecords.value;
    const step = dir * galleryColCount.value;
    const cur = galleryFocusIdx.value < 0 ? 0 : galleryFocusIdx.value;
    const next = Math.max(0, Math.min(records.length - 1, cur + step));
    galleryFocusIdx.value = next;
    nextTick(() => {
      (document.querySelector(`[data-gallery-idx="${next}"]`) as HTMLElement | null)?.focus();
    });
    return;
  }
  if (!openedRecord.value || viewMode.value !== 'table') return;
  const records = filteredRecords.value;
  const idx = records.findIndex((r) => r.id === openedRecord.value?.id);
  const next = records[idx + dir];
  if (next) {
    openRecord(next);
    nextTick(() => {
      const el = document.querySelector(`[data-record-id="${next.id}"]`);
      el?.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    });
  }
}

function onKeyArrowLR(dir: 1 | -1, e: KeyboardEvent) {
  const tag = (e.target as HTMLElement)?.tagName ?? '';
  if (['INPUT', 'SELECT', 'TEXTAREA'].includes(tag)) return;
  if (viewMode.value !== 'gallery' || groupedGalleryGroups.value) return;
  e.preventDefault();
  const records = filteredRecords.value;
  const cur = galleryFocusIdx.value < 0 ? 0 : galleryFocusIdx.value;
  const next = Math.max(0, Math.min(records.length - 1, cur + dir));
  galleryFocusIdx.value = next;
  nextTick(() => {
    (document.querySelector(`[data-gallery-idx="${next}"]`) as HTMLElement | null)?.focus();
  });
}

function onKeyHome() {
  if (!openedRecord.value || viewMode.value !== 'table') return;
  const tag = document.activeElement?.tagName ?? '';
  if (['INPUT', 'SELECT', 'TEXTAREA'].includes(tag)) return;
  const first = filteredRecords.value[0];
  if (first && first.id !== openedRecord.value?.id) {
    openRecord(first);
    nextTick(() => {
      document.querySelector(`[data-record-id="${first.id}"]`)?.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    });
  }
}

function onKeyEnd() {
  if (!openedRecord.value || viewMode.value !== 'table') return;
  const tag = document.activeElement?.tagName ?? '';
  if (['INPUT', 'SELECT', 'TEXTAREA'].includes(tag)) return;
  const last = filteredRecords.value[filteredRecords.value.length - 1];
  if (last && last.id !== openedRecord.value?.id) {
    openRecord(last);
    nextTick(() => {
      document.querySelector(`[data-record-id="${last.id}"]`)?.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    });
  }
}

// ── Helpers ────────────────────────────────────────────────────────────────

function showToast(message: string, action?: { label: string; fn: () => void }) {
  const id = 'toast-' + String(toasts.value.length) + '-' + String(Math.floor(Math.random() * 99999));
  toasts.value.push({ id, message, action });
  setTimeout(() => {
    toasts.value = toasts.value.filter((t) => t.id !== id);
  }, action ? 5000 : 2500);
}

// ── Schema editor actions ──────────────────────────────────────────────────

function openSchemaEditor(mode: 'fields' | 'new-type' | 'sections' = 'fields') {
  schemaEditorMode.value = mode;
  showAddFieldForm.value = false;
  newFieldDraft.value = { label: '', key: '', data_type: 'text', select_options_raw: '', default_value: '', formula_expression: '', formula_format: '', help_text: '', rollup_from_type: '', rollup_field_key: '', rollup_function: 'count' };
  newTypeDraft.value = { label: '', key: '', icon: 'folder', color: '#6366f1' };
  showSchemaEditor.value = true;
}

function startSchemaTypeRename() {
  const type = schema.find((t) => t.key === selectedTypeKey.value);
  if (!type) return;
  schemaTypeLabelDraft.value = type.label;
  nextTick(() => { schemaTypeLabelInputEl.value?.select(); });
}

function commitSchemaTypeRename() {
  const draft = schemaTypeLabelDraft.value?.trim();
  schemaTypeLabelDraft.value = null;
  if (!draft) return;
  const type = schema.find((t) => t.key === selectedTypeKey.value);
  if (!type) return;
  const prev = type.label;
  type.label = draft;
  if (!type.label_plural || type.label_plural === prev + 's' || type.label_plural === prev) {
    type.label_plural = draft.endsWith('s') ? draft : draft + 's';
  }
  showToast(`Renamed to "${draft}"`);
}

function startFieldLabelRename(field: CrmField) {
  fieldLabelDraftId.value = field.id;
  fieldLabelDraft.value = field.label;
  nextTick(() => { fieldLabelInputEl.value?.select(); });
}

function commitFieldLabelRename() {
  const id = fieldLabelDraftId.value;
  const draft = fieldLabelDraft.value.trim();
  fieldLabelDraftId.value = null;
  if (!id || !draft) return;
  const field = (selectedType.value?.fields ?? []).find((f) => f.id === id);
  if (!field || field.label === draft) return;
  field.label = draft;
  showToast(`Field renamed to "${draft}"`);
}

function addFieldToCurrentType() {
  const draft = newFieldDraft.value;
  const label = draft.label.trim();
  if (!label) return;
  const key = draft.key.trim() || label.toLowerCase().replace(/[^a-z0-9]+/g, '_');
  const type = schema.find((t) => t.key === selectedTypeKey.value);
  if (!type) return;
  if (type.fields.some((f) => f.key === key)) { showToast('A field with that key already exists'); return; }
  const opts = (draft.data_type === 'select' || draft.data_type === 'multi_select')
    ? draft.select_options_raw.split(',').map((s) => s.trim()).filter(Boolean)
    : undefined;
  type.fields.push({
    id: 'f_custom_' + String(type.fields.length) + '_' + String(Date.now()).slice(-6),
    key,
    label,
    data_type: draft.data_type,
    is_title: false,
    is_required: false,
    position: type.fields.length,
    ...(opts?.length ? { select_options: opts } : {}),
    ...(draft.default_value.trim() ? { default_value: draft.default_value.trim() } : {}),
    ...(draft.data_type === 'formula' && draft.formula_expression.trim() ? { formula_expression: draft.formula_expression.trim() } : {}),
    ...(draft.data_type === 'formula' && draft.formula_format ? { format: draft.formula_format as FieldFormat } : {}),
    ...(draft.data_type === 'rollup' && draft.rollup_from_type ? { rollup_from_type: draft.rollup_from_type } : {}),
    ...(draft.data_type === 'rollup' && draft.rollup_field_key && draft.rollup_function !== 'count' ? { rollup_field_key: draft.rollup_field_key } : {}),
    ...(draft.data_type === 'rollup' ? { rollup_function: draft.rollup_function } : {}),
    ...(draft.help_text.trim() ? { help_text: draft.help_text.trim() } : {}),
  });
  newFieldDraft.value = { label: '', key: '', data_type: 'text', select_options_raw: '', default_value: '', formula_expression: '', formula_format: '', help_text: '', rollup_from_type: '', rollup_field_key: '', rollup_function: 'count' };
  showAddFieldForm.value = false;
  showToast(`Field "${label}" added to ${type.label}`);
}

function removeFieldFromType(typeKey: string, fieldId: string) {
  const type = schema.find((t) => t.key === typeKey);
  if (!type) return;
  const field = type.fields.find((f) => f.id === fieldId);
  if (!field || field.is_title || field.is_required) { showToast('Cannot remove required or title fields'); return; }
  const idx = type.fields.findIndex((f) => f.id === fieldId);
  if (idx !== -1) type.fields.splice(idx, 1);
  showToast('Field removed');
}

function addSelectOption(fieldId: string) {
  const val = newSelectOptionDraft.value.trim();
  if (!val) return;
  for (const type of schema) {
    const field = type.fields.find((f) => f.id === fieldId);
    if (!field) continue;
    if ((field.select_options ?? []).includes(val)) { showToast('Option already exists'); return; }
    field.select_options = [...(field.select_options ?? []), val];
    newSelectOptionDraft.value = '';
    newSelectOptionFieldId.value = null;
    return;
  }
}

function removeSelectOption(fieldId: string, val: string) {
  for (const type of schema) {
    const field = type.fields.find((f) => f.id === fieldId);
    if (!field) continue;
    field.select_options = (field.select_options ?? []).filter((o) => o !== val);
    if (field.select_option_colors) {
      const c = { ...field.select_option_colors };
      delete c[val];
      field.select_option_colors = c;
    }
    for (const rec of mockRecords) {
      if (rec.field_values[field.key] === val) rec.field_values[field.key] = null;
    }
    showToast(`Option "${val}" removed`);
    return;
  }
}

function commitRenameSelectOption(fieldId: string, oldVal: string) {
  const newVal = editingSelectOptionDraft.value.trim();
  editingSelectOptionKey.value = null;
  if (!newVal || newVal === oldVal) return;
  for (const type of schema) {
    const field = type.fields.find((f) => f.id === fieldId);
    if (!field) continue;
    if ((field.select_options ?? []).includes(newVal)) { showToast('Option already exists'); return; }
    field.select_options = (field.select_options ?? []).map((o) => (o === oldVal ? newVal : o));
    if (field.select_option_colors?.[oldVal]) {
      field.select_option_colors = { ...field.select_option_colors, [newVal]: field.select_option_colors[oldVal] };
      const c = { ...field.select_option_colors };
      delete c[oldVal];
      field.select_option_colors = c;
    }
    for (const rec of mockRecords) {
      if (rec.field_values[field.key] === oldVal) rec.field_values[field.key] = newVal;
    }
    return;
  }
}

function reorderSelectOption(fieldId: string, fromIdx: number, dir: -1 | 1) {
  for (const type of schema) {
    const field = type.fields.find((f) => f.id === fieldId);
    if (!field) continue;
    const opts = [...(field.select_options ?? [])];
    const toIdx = fromIdx + dir;
    if (toIdx < 0 || toIdx >= opts.length) return;
    [opts[fromIdx], opts[toIdx]] = [opts[toIdx], opts[fromIdx]];
    field.select_options = opts;
    return;
  }
}

function addNewRecordType() {
  const draft = newTypeDraft.value;
  const label = draft.label.trim();
  if (!label) return;
  const key = draft.key.trim() || label.toLowerCase().replace(/[^a-z0-9]+/g, '_');
  if (schema.some((t) => t.key === key)) { showToast('A type with that key already exists'); return; }
  const plural = label.endsWith('s') ? label : label + 's';
  schema.push({
    id: 'rt_' + key + '_' + String(Date.now()).slice(-6),
    key,
    label,
    label_plural: plural,
    icon: draft.icon,
    color: draft.color,
    fields: [
      { id: 'f_' + key + '_title', key: 'name', label: 'Name', data_type: 'text', is_title: true, is_required: true, position: 0 },
      { id: 'f_' + key + '_status', key: 'status', label: 'Status', data_type: 'select', is_title: false, is_required: false, position: 1, select_options: ['Active', 'Inactive'] },
    ],
  });
  newTypeDraft.value = { label: '', key: '', icon: 'folder', color: '#6366f1' };
  schemaEditorMode.value = 'fields';
  selectType(key);
  showToast(`Type "${label}" created`);
}

function duplicateRecordType(typeKey: string) {
  const src = schema.find((t) => t.key === typeKey);
  if (!src) return;
  const baseKey = src.key + '_copy';
  let newKey = baseKey;
  let n = 2;
  while (schema.some((t) => t.key === newKey)) newKey = baseKey + n++;
  const newId = 'rt_' + newKey + '_' + String(Date.now()).slice(-6);
  schema.push({
    id: newId,
    key: newKey,
    label: src.label + ' (copy)',
    label_plural: src.label_plural + ' (copy)',
    icon: src.icon,
    color: src.color,
    fields: src.fields.map((f) => ({ ...f, id: f.id + '_dup' })),
    sections: src.sections ? src.sections.map((s) => ({ ...s, id: s.id + '_dup' })) : undefined,
  });
  showToast(`Duplicated "${src.label}"`);
}

function deleteRecordType(typeKey: string) {
  if (mockRecords.some((r) => r.record_type_key === typeKey)) {
    showToast('Cannot delete a type that has records — remove all records first');
    return;
  }
  const idx = schema.findIndex((t) => t.key === typeKey);
  if (idx === -1) return;
  const label = schema[idx].label;
  schema.splice(idx, 1);
  if (selectedTypeKey.value === typeKey) selectedTypeKey.value = schema[0]?.key ?? '';
  showSchemaEditor.value = false;
  showToast(`Type "${label}" deleted`);
}

function openImportModal() {
  importStep.value = 'paste';
  importCsvText.value = '';
  importParsed.value = [];
  importMapping.value = {};
  importHeaderRow.value = true;
  showImportModal.value = true;
}

function parseCsvLine(line: string): string[] {
  const result: string[] = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') { inQuotes = !inQuotes; continue; }
    if (ch === ',' && !inQuotes) { result.push(current); current = ''; continue; }
    current += ch;
  }
  result.push(current);
  return result;
}

function parseImportCsv() {
  const lines = importCsvText.value.trim().split('\n').filter((l) => l.trim());
  importParsed.value = lines.map(parseCsvLine);
  if (!importParsed.value.length) return;
  importMapping.value = {};
  const headers = importHeaderRow.value ? importParsed.value[0] : [];
  const fields = selectedType.value?.fields ?? [];
  for (let i = 0; i < importParsed.value[0].length; i++) {
    const hdr = (headers[i] ?? '').trim().toLowerCase();
    const matched = fields.find((f) => f.label.toLowerCase() === hdr || f.key === hdr);
    if (matched) { importMapping.value[i] = matched.key; }
    else if (/^name|^title|^full.?name/.test(hdr)) { importMapping.value[i] = '__title__'; }
    else { importMapping.value[i] = ''; }
  }
  importStep.value = 'map';
}

function commitImport() {
  const type = selectedType.value;
  const titleField = type?.fields.find((f) => f.is_title);
  let created = 0;
  for (const row of importPreviewRows.value) {
    const rawTitle = row['__title__'] ?? (titleField ? row[titleField.key] : '') ?? '';
    const title = rawTitle.trim() || `Imported ${type?.label ?? 'record'} ${String(mockRecords.length + 1)}`;
    const fieldVals: Record<string, string | number | boolean | null> = {};
    for (const [k, v] of Object.entries(row)) {
      if (k === '__title__') { if (titleField) fieldVals[titleField.key] = v; continue; }
      fieldVals[k] = v;
    }
    mockRecords.push({
      id: 'import-' + selectedTypeKey.value + '-' + String(mockRecords.length),
      record_type_key: selectedTypeKey.value,
      title,
      created_at: new Date().toISOString(),
      field_values: fieldVals,
      links: [],
    });
    created++;
  }
  showImportModal.value = false;
  showToast(`Imported ${created} record${created === 1 ? '' : 's'}`);
}

function exportCsv(records?: CrmRecord[]) {
  const recs = records ?? filteredRecords.value;
  const cols = allColumns.value;
  const headers = [...cols.map((c) => c.label), 'Created'];
  const escape = (v: unknown) => {
    const s = Array.isArray(v) ? v.join('; ') : (v == null ? '' : String(v));
    return s.includes(',') || s.includes('"') || s.includes('\n') ? `"${s.replace(/"/g, '""')}"` : s;
  };
  const rows = recs.map((r) => [
    ...cols.map((c) => escape(r.field_values[c.key])),
    escape(formatDate(r.created_at)),
  ]);
  const csv = [headers.join(','), ...rows.map((r) => r.join(','))].join('\n');
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${selectedType.value?.label_plural ?? 'records'}.csv`;
  a.click();
  URL.revokeObjectURL(url);
  showToast(`Exported ${recs.length} record${recs.length === 1 ? '' : 's'}`);
}

function exportFeedCsv() {
  const acts = feedRows.value
    .filter((r): r is { kind: 'activity'; act: CrmActivity } => r.kind === 'activity')
    .map((r) => r.act);
  const escape = (v: unknown) => {
    const s = v == null ? '' : String(v);
    return s.includes(',') || s.includes('"') || s.includes('\n') ? `"${s.replace(/"/g, '""')}"` : s;
  };
  const header = ['Date', 'Time', 'Type', 'Record', 'Author', 'Content', 'Scheduled'].join(',');
  const rows = acts.map((a) => {
    const d = new Date(a.created_at);
    const rec = mockRecords.find((r) => r.id === a.record_id);
    return [
      escape(d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })),
      escape(d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })),
      escape(a.type),
      escape(rec?.title ?? a.record_id),
      escape(a.author),
      escape(a.content),
      escape(a.scheduled_at ? new Date(a.scheduled_at).toLocaleString('en-US', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' }) : ''),
    ].join(',');
  });
  const csv = [header, ...rows].join('\n');
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${selectedType.value?.label_plural ?? 'records'}-activity.csv`;
  a.click();
  URL.revokeObjectURL(url);
  showToast(`Exported ${acts.length} activit${acts.length === 1 ? 'y' : 'ies'}`);
}

function exportRecordActivitiesCsv() {
  const rec = openedRecord.value;
  if (!rec) return;
  const acts = visibleActivities.value;
  const escape = (v: unknown) => {
    const s = v == null ? '' : String(v);
    return s.includes(',') || s.includes('"') || s.includes('\n') ? `"${s.replace(/"/g, '""')}"` : s;
  };
  const header = ['Date', 'Time', 'Type', 'Author', 'Content', 'Scheduled'].join(',');
  const rows = acts.map((a) => {
    const d = new Date(a.created_at);
    return [
      escape(d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })),
      escape(d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })),
      escape(a.type),
      escape(a.author),
      escape(a.content),
      escape(a.scheduled_at ? new Date(a.scheduled_at).toLocaleString('en-US', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' }) : ''),
    ].join(',');
  });
  const csv = [header, ...rows].join('\n');
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${rec.title.replace(/[^a-z0-9]/gi, '-').toLowerCase()}-activity.csv`;
  a.click();
  URL.revokeObjectURL(url);
  showToast(`Exported ${acts.length} activit${acts.length === 1 ? 'y' : 'ies'}`);
}

function recordInitials(title: string): string {
  const words = title.trim().split(/\s+/).filter(Boolean);
  if (words.length === 0) return '?';
  if (words.length === 1) return words[0].slice(0, 2).toUpperCase();
  return (words[0][0] + words[words.length - 1][0]).toUpperCase();
}

function formatDate(iso: string): string {
  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function formatFileSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(0)} KB`;
  if (bytes < 1024 * 1024 * 1024) return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  return `${(bytes / (1024 * 1024 * 1024)).toFixed(1)} GB`;
}

function attachmentExtIcon(name: string): string {
  const ext = name.split('.').pop()?.toLowerCase() ?? '';
  if (ext === 'pdf') return '#e84242';
  if (['doc', 'docx'].includes(ext)) return '#2b7cd3';
  if (['xls', 'xlsx', 'csv'].includes(ext)) return '#1e7e44';
  if (['png', 'jpg', 'jpeg', 'gif', 'webp', 'svg'].includes(ext)) return '#9333ea';
  if (['mp4', 'mov', 'avi', 'mkv'].includes(ext)) return '#f97316';
  if (['zip', 'gz', 'tar', 'rar'].includes(ext)) return '#64748b';
  return '#6366f1';
}

function deleteAttachment(id: string) {
  const idx = mockAttachments.findIndex((a) => a.id === id);
  if (idx === -1) return;
  const [removed] = mockAttachments.splice(idx, 1);
  showToast('File removed', { label: 'Undo', fn: () => { mockAttachments.splice(idx, 0, removed); } });
}

function startRenameAttachment(id: string) {
  const att = mockAttachments.find((a) => a.id === id);
  if (!att) return;
  renamingAttachmentId.value = id;
  renameAttachmentDraft.value = att.name;
}

function saveRenameAttachment() {
  const id = renamingAttachmentId.value;
  if (!id) return;
  const att = mockAttachments.find((a) => a.id === id);
  const name = renameAttachmentDraft.value.trim();
  if (att && name) att.name = name;
  renamingAttachmentId.value = null;
}

function cancelRenameAttachment() {
  renamingAttachmentId.value = null;
}

function dropFiles(e: DragEvent) {
  filesDragOver.value = false;
  if (!openedRecord.value || !e.dataTransfer?.files.length) return;
  const now = new Date().toISOString();
  Array.from(e.dataTransfer.files).forEach((f, i) => {
    mockAttachments.push({
      id: 'af-drop-' + String(Date.now()) + '-' + String(i),
      record_id: openedRecord.value!.id,
      name: f.name,
      size: f.size,
      mime_type: f.type || 'application/octet-stream',
      uploaded_by: 'JB',
      uploaded_at: now,
    });
  });
  showToast(`${e.dataTransfer.files.length} file${e.dataTransfer.files.length === 1 ? '' : 's'} attached`);
}

function handleAttachFileInput(e: Event) {
  const input = e.target as HTMLInputElement;
  if (!openedRecord.value || !input.files?.length) return;
  const now = new Date().toISOString();
  const count = input.files.length;
  Array.from(input.files).forEach((f, i) => {
    mockAttachments.push({
      id: 'af-browse-' + String(Date.now()) + '-' + String(i),
      record_id: openedRecord.value!.id,
      name: f.name,
      size: f.size,
      mime_type: f.type || 'application/octet-stream',
      uploaded_by: 'JB',
      uploaded_at: now,
    });
  });
  showToast(`${count} file${count === 1 ? '' : 's'} attached`);
  input.value = '';
}

function formatAge(iso: string): string {
  const ms = Date.now() - new Date(iso).getTime();
  const mins = Math.floor(ms / 60000);
  if (mins < 1) return 'now';
  if (mins < 60) return `${mins}m`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h`;
  const days = Math.floor(hrs / 24);
  if (days < 7) return `${days}d`;
  if (days < 30) return `${Math.floor(days / 7)}w`;
  if (days < 365) return `${Math.floor(days / 30)}mo`;
  return `${Math.floor(days / 365)}y`;
}

function formatRelativeTime(iso: string): string {
  const ms = Date.now() - new Date(iso).getTime();
  const mins = Math.floor(ms / 60000);
  if (mins < 2) return 'just now';
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  if (days < 7) return `${days}d ago`;
  return formatDate(iso);
}

function formatCardValue(val: string | number | boolean | string[] | null | undefined, dataType: DataType, format?: FieldFormat): string {
  if (val == null || val === '') return '—';
  if (Array.isArray(val)) return val.length ? val.join(', ') : '—';
  if (dataType === 'number') {
    const n = Number(val);
    if (format === 'currency') {
      if (n >= 1_000_000) return '$' + (n / 1_000_000).toFixed(1).replace(/\.0$/, '') + 'M';
      if (n >= 1_000) return '$' + Math.round(n / 1_000) + 'k';
      return '$' + n;
    }
    if (format === 'percent') return n + '%';
    if (format === 'progress') return n + '%';
    return n.toLocaleString();
  }
  if (dataType === 'rating') {
    const n = Number(val);
    if (!n) return '—';
    return '★'.repeat(Math.max(0, Math.min(5, n))) + '☆'.repeat(Math.max(0, 5 - Math.min(5, n)));
  }
  if (dataType === 'date') return new Date(String(val)).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  return String(val);
}

// ── Formula evaluator (recursive-descent parser) ─────────────────────────────
// Supports: arithmetic (+,-,*,/), comparison (<,>,<=,>=,==,!=), AND/OR,
// string literals, and built-in functions: IF, ROUND, ABS, MIN, MAX, SUM,
// CONCAT, LEN, UPPER, LOWER, TRIM, LEFT, RIGHT, ISBLANK, COALESCE, CONTAINS.
// Field values are substituted as {field_key} before parsing.
type FVal = number | string;
interface FCtx { s: string; i: number }
function fSkip(c: FCtx) { while (c.i < c.s.length && /\s/.test(c.s[c.i])) c.i++; }
function fOr(c: FCtx): FVal {
  let l = fAnd(c); fSkip(c);
  while (c.s.slice(c.i, c.i + 2).toUpperCase() === 'OR') { c.i += 2; l = (!!l || !!fAnd(c)) ? 1 : 0; fSkip(c); }
  return l;
}
function fAnd(c: FCtx): FVal {
  let l = fCmp(c); fSkip(c);
  while (c.s.slice(c.i, c.i + 3).toUpperCase() === 'AND') { c.i += 3; l = (!!l && !!fCmp(c)) ? 1 : 0; fSkip(c); }
  return l;
}
function fCmp(c: FCtx): FVal {
  const l = fAdd(c); fSkip(c);
  const op2 = c.s.slice(c.i, c.i + 2); const op1 = c.s[c.i];
  let op = '';
  if (op2 === '<=' || op2 === '>=' || op2 === '==' || op2 === '!=') { op = op2; c.i += 2; }
  else if (op1 === '<' || op1 === '>') { op = op1; c.i++; }
  else if (op1 === '=') { op = '=='; c.i++; }
  if (!op) return l;
  fSkip(c);
  const r = fAdd(c);
  const ln = typeof l === 'number' ? l : Number(l); const rn = typeof r === 'number' ? r : Number(r);
  if (op === '<') return ln < rn ? 1 : 0; if (op === '>') return ln > rn ? 1 : 0;
  if (op === '<=') return ln <= rn ? 1 : 0; if (op === '>=') return ln >= rn ? 1 : 0;
  if (op === '==' || op === '=') return l == r ? 1 : 0;
  if (op === '!=') return l != r ? 1 : 0;
  return l;
}
function fAdd(c: FCtx): FVal {
  let l = fMul(c); fSkip(c);
  while (c.i < c.s.length && (c.s[c.i] === '+' || c.s[c.i] === '-')) {
    const op = c.s[c.i++]; fSkip(c); const r = fMul(c);
    l = op === '+' ? (typeof l === 'string' || typeof r === 'string' ? String(l) + String(r) : l + r)
      : (typeof l === 'number' ? l : Number(l)) - (typeof r === 'number' ? r : Number(r));
    fSkip(c);
  }
  return l;
}
function fMul(c: FCtx): FVal {
  let l = fUnary(c); fSkip(c);
  while (c.i < c.s.length && (c.s[c.i] === '*' || c.s[c.i] === '/')) {
    const op = c.s[c.i++]; fSkip(c); const r = fUnary(c);
    const ln = typeof l === 'number' ? l : Number(l); const rn = typeof r === 'number' ? r : Number(r);
    l = op === '*' ? ln * rn : (rn !== 0 ? ln / rn : 0); fSkip(c);
  }
  return l;
}
function fUnary(c: FCtx): FVal {
  fSkip(c);
  if (c.s[c.i] === '-') { c.i++; return -(Number(fAtom(c))); }
  if (c.s[c.i] === '!') { c.i++; return fAtom(c) ? 0 : 1; }
  return fAtom(c);
}
function fAtom(c: FCtx): FVal {
  fSkip(c); const s = c.s;
  if (s[c.i] === '"') {
    c.i++; let str = '';
    while (c.i < s.length && s[c.i] !== '"') { if (s[c.i] === '\\' && c.i + 1 < s.length) c.i++; str += s[c.i++]; }
    if (s[c.i] === '"') c.i++;
    return str;
  }
  if (s[c.i] === '(') {
    c.i++; const v = fOr(c); fSkip(c); if (s[c.i] === ')') c.i++;
    return v;
  }
  const idm = s.slice(c.i).match(/^[A-Za-z_][A-Za-z0-9_]*/);
  if (idm) {
    const name = idm[0].toUpperCase(); c.i += idm[0].length; fSkip(c);
    if (s[c.i] === '(') {
      c.i++;
      const args: FVal[] = [];
      while (c.i < s.length && s[c.i] !== ')') {
        fSkip(c); if (s[c.i] === ')') break;
        args.push(fOr(c)); fSkip(c); if (s[c.i] === ',') c.i++;
      }
      if (s[c.i] === ')') c.i++;
      return fCall(name, args);
    }
    if (name === 'TRUE') return 1; if (name === 'FALSE') return 0;
    return 0;
  }
  const nm = s.slice(c.i).match(/^[\d]+(?:\.[\d]+)?/);
  if (nm) { c.i += nm[0].length; return parseFloat(nm[0]); }
  return 0;
}
function fCall(name: string, args: FVal[]): FVal {
  const ns = args.map((a) => typeof a === 'number' ? a : Number(a));
  switch (name) {
    case 'IF': return args[0] ? (args[1] ?? 0) : (args[2] ?? 0);
    case 'AND': return args.every(Boolean) ? 1 : 0;
    case 'OR': return args.some(Boolean) ? 1 : 0;
    case 'NOT': return args[0] ? 0 : 1;
    case 'ROUND': return Math.round(ns[0] * 10 ** (ns[1] ?? 0)) / 10 ** (ns[1] ?? 0);
    case 'ABS': return Math.abs(ns[0]);
    case 'FLOOR': return Math.floor(ns[0]);
    case 'CEIL': return Math.ceil(ns[0]);
    case 'SQRT': return Math.sqrt(ns[0]);
    case 'MIN': return Math.min(...ns);
    case 'MAX': return Math.max(...ns);
    case 'SUM': return ns.reduce((a, b) => a + b, 0);
    case 'CONCAT': return args.map(String).join('');
    case 'LEN': return String(args[0] ?? '').length;
    case 'UPPER': return String(args[0] ?? '').toUpperCase();
    case 'LOWER': return String(args[0] ?? '').toLowerCase();
    case 'TRIM': return String(args[0] ?? '').trim();
    case 'LEFT': return String(args[0] ?? '').slice(0, ns[1] ?? 0);
    case 'RIGHT': { const sv = String(args[0] ?? ''); return sv.slice(Math.max(0, sv.length - (ns[1] ?? 0))); }
    case 'MID': return String(args[0] ?? '').slice(ns[1] ? ns[1] - 1 : 0, ns[1] ? ns[1] - 1 + (ns[2] ?? 0) : undefined);
    case 'SUBSTITUTE': return String(args[0] ?? '').split(String(args[1] ?? '')).join(String(args[2] ?? ''));
    case 'CONTAINS': return String(args[0] ?? '').toLowerCase().includes(String(args[1] ?? '').toLowerCase()) ? 1 : 0;
    case 'ISBLANK': return (args[0] == null || args[0] === '' || args[0] === 0) ? 1 : 0;
    case 'COALESCE': return args.find((a) => a != null && a !== '') ?? 0;
    default: return 0;
  }
}

function evaluateFormula(record: { field_values: Record<string, unknown> }, field: CrmField): number | string {
  const expr = (field.formula_expression ?? '').trim();
  if (!expr) return '—';
  // Substitute {field_key} → number or quoted string literal
  const sub = expr.replace(/\{([^}]+)\}/g, (_m, key: string) => {
    const v = record.field_values[key.trim()];
    if (v == null || v === '') return '0';
    const n = Number(v);
    return !isNaN(n) ? String(n) : `"${String(v).replace(/\\/g, '\\\\').replace(/"/g, '\\"')}"`;
  });
  try {
    const ctx: FCtx = { s: sub, i: 0 };
    const result = fOr(ctx);
    return typeof result === 'number' ? Math.round(result * 10000) / 10000 : result;
  } catch {
    return '?';
  }
}

function evaluateRollup(record: CrmRecord, field: CrmField): number | string {
  if (!field.rollup_from_type || !field.rollup_function) return '';
  const links = record.links?.filter((l) => l.target_type === field.rollup_from_type) ?? [];
  const linkedRecs = links.map((l) => mockRecords.find((r) => r.id === l.target_id)).filter((r): r is CrmRecord => Boolean(r));
  if (field.rollup_function === 'count') return linkedRecs.length;
  if (!field.rollup_field_key) return '';
  const vals = linkedRecs
    .map((r) => r.field_values[field.rollup_field_key!])
    .filter((v): v is string | number => v !== undefined && v !== null && v !== '')
    .map((v) => Number(v))
    .filter((n) => !isNaN(n));
  if (!vals.length) return '';
  if (field.rollup_function === 'sum') return vals.reduce((a, b) => a + b, 0);
  if (field.rollup_function === 'avg') return Math.round((vals.reduce((a, b) => a + b, 0) / vals.length) * 100) / 100;
  if (field.rollup_function === 'min') return Math.min(...vals);
  if (field.rollup_function === 'max') return Math.max(...vals);
  return '';
}

// ── Inline sub-components ──────────────────────────────────────────────────

const CrmCellValue = defineComponent({
  props: {
    value: { type: [String, Number, Boolean, Array, null] as unknown as () => string | number | boolean | string[] | null, default: null },
    dataType: { type: String as () => DataType, required: true },
    format: { type: String as () => FieldFormat, default: undefined },
    onTagClick: { type: Function as unknown as () => ((tag: string) => void) | undefined, default: undefined },
  },
  setup(props) {
    return () => {
      if (props.dataType === 'rating') {
        const n = props.value != null ? Number(props.value) : 0;
        if (!n) return h('span', { class: 'text-slate-300 dark:text-slate-600' }, '—');
        return h('span', { class: 'flex items-center gap-0.5 leading-none' },
          [1,2,3,4,5].map((i) => h('span', {
            key: i,
            class: 'text-base ' + (i <= n ? 'text-amber-400' : 'text-slate-200 dark:text-slate-700'),
          }, '★')),
        );
      }
      if (props.dataType === 'multi_select') {
        const arr = Array.isArray(props.value) ? props.value : (props.value ? [String(props.value)] : []);
        if (!arr.length) return h('span', { class: 'text-slate-300 dark:text-slate-600' }, '—');
        return h('span', { class: 'flex flex-wrap gap-0.5' },
          arr.map((tag) => h('span', {
            key: tag,
            class: 'inline-flex items-center rounded-full px-1.5 py-0 text-xs font-medium bg-sky-50 dark:bg-sky-950/40 text-sky-700 dark:text-sky-300 border border-sky-200 dark:border-sky-800' + (props.onTagClick ? ' cursor-pointer hover:bg-sky-100 dark:hover:bg-sky-900/60 transition-colors' : ''),
            title: props.onTagClick ? `Filter by "${tag}"` : undefined,
            onClick: props.onTagClick ? (e: Event) => { e.stopPropagation(); props.onTagClick!(tag); } : undefined,
          }, tag)),
        );
      }
      if (props.dataType === 'checklist') {
        const items: ChecklistItem[] = (() => { try { return props.value ? (JSON.parse(String(props.value)) as ChecklistItem[]) : []; } catch { return []; } })();
        if (!items.length) return h('span', { class: 'text-slate-300 dark:text-slate-600' }, '—');
        const done = items.filter((i) => i.d).length;
        const total = items.length;
        const pct = Math.round((done / total) * 100);
        const color = pct === 100 ? '#10b981' : pct >= 50 ? '#f59e0b' : '#64748b';
        return h('span', { class: 'flex items-center gap-1.5 min-w-0' }, [
          h('span', { class: 'flex-1 h-1.5 rounded-full bg-slate-100 dark:bg-slate-800 overflow-hidden', style: 'max-width:64px' }, [
            h('span', { class: 'h-full rounded-full block transition-all', style: `width:${pct}%;background:${color}` }),
          ]),
          h('span', { class: 'tabular-nums text-xs shrink-0', style: `color:${color}` }, `${done}/${total}`),
        ]);
      }
      if (props.value == null || props.value === '') {
        return h('span', { class: 'text-slate-300 dark:text-slate-600' }, '—');
      }
      if (props.dataType === 'boolean') {
        return h('span', {
          class: props.value
            ? 'inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium bg-emerald-50 dark:bg-emerald-950/40 text-emerald-700 dark:text-emerald-400'
            : 'inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400',
        }, props.value ? 'Yes' : 'No');
      }
      if (props.dataType === 'number') {
        const n = Number(props.value);
        if (props.format === 'progress') {
          const pct = Math.max(0, Math.min(100, n));
          const color = pct >= 70 ? '#10b981' : pct >= 40 ? '#f59e0b' : '#ef4444';
          return h('span', { class: 'flex items-center gap-1.5 w-full max-w-[120px]' }, [
            h('span', { class: 'flex-1 h-1.5 rounded-full bg-slate-100 dark:bg-slate-800 overflow-hidden' }, [
              h('span', { class: 'h-full rounded-full block', style: `width:${pct}%;background:${color}` }),
            ]),
            h('span', { class: 'tabular-nums text-xs w-8 text-right shrink-0', style: `color:${color}` }, pct + '%'),
          ]);
        }
        let display: string;
        if (props.format === 'currency') {
          display = '$' + n.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
        } else if (props.format === 'percent') {
          display = n + '%';
        } else {
          display = n.toLocaleString();
        }
        return h('span', { class: 'tabular-nums' }, display);
      }
      if (props.dataType === 'email') {
        return h('a', {
          href: 'mailto:' + String(props.value),
          class: 'text-sky-600 dark:text-sky-400 hover:underline truncate max-w-[180px] block',
          onClick: (e: Event) => e.stopPropagation(),
        }, String(props.value));
      }
      if (props.dataType === 'url') {
        const href = String(props.value).startsWith('http') ? String(props.value) : 'https://' + String(props.value);
        return h('a', {
          href,
          target: '_blank',
          rel: 'noopener noreferrer',
          class: 'text-sky-600 dark:text-sky-400 hover:underline truncate max-w-[180px] block',
          onClick: (e: Event) => e.stopPropagation(),
        }, String(props.value));
      }
      if (props.dataType === 'phone') {
        return h('a', {
          href: 'tel:' + String(props.value),
          class: 'text-sky-600 dark:text-sky-400 hover:underline tabular-nums',
          onClick: (e: Event) => e.stopPropagation(),
        }, String(props.value));
      }
      if (props.dataType === 'select') {
        const optStyle = getOptionStyle({ select_option_colors: props.optionColors } as CrmField, String(props.value));
        return h('span', {
          class: optStyle ? 'inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium' : 'inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ' + selectBadgeClass(String(props.value)),
          style: optStyle,
        }, String(props.value));
      }
      if (props.dataType === 'date') {
        const d = new Date(String(props.value));
        const now = new Date();
        const diffMs = d.getTime() - now.getTime();
        const diffDays = diffMs / (1000 * 60 * 60 * 24);
        // Strip time component for comparison (treat as date-only)
        const isOverdue = diffDays < -0.5;
        const isDueSoon = !isOverdue && diffDays <= 7;
        const fmt = d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: d.getFullYear() !== now.getFullYear() ? 'numeric' : undefined });
        const colorClass = isOverdue
          ? 'text-red-500 dark:text-red-400'
          : isDueSoon
            ? 'text-amber-500 dark:text-amber-400'
            : '';
        const titleStr = isOverdue
          ? `Overdue — ${Math.round(-diffDays)} day${Math.round(-diffDays) === 1 ? '' : 's'} ago`
          : isDueSoon
            ? diffDays < 1 ? 'Due today' : `Due in ${Math.round(diffDays)} day${Math.round(diffDays) === 1 ? '' : 's'}`
            : fmt;
        return h('span', { class: 'tabular-nums ' + colorClass, title: titleStr }, fmt);
      }
      return h('span', { class: 'truncate max-w-[180px] block' }, String(props.value));
    };
  },
});

const CrmCellEditor = defineComponent({
  props: {
    value: { type: [String, Number, Boolean, Array, null] as unknown as () => string | number | boolean | string[] | null, default: null },
    dataType: { type: String as () => DataType, required: true },
    selectOptions: { type: Array as () => string[], default: () => [] },
    optionColors: { type: Object as () => Record<string, string>, default: () => ({}) },
  },
  emits: ['commit', 'cancel', 'tab', 'shift-tab'],
  setup(props, { emit }) {
    const elRef = ref<HTMLInputElement | HTMLSelectElement | null>(null);
    const hoverStar = ref(0);
    onMounted(() => (elRef.value as HTMLElement | null)?.focus());
    return () => {
      const cellClass = 'w-full rounded px-1.5 py-0.5 text-sm bg-white dark:bg-slate-950 border border-sky-400 dark:border-sky-500 text-slate-900 dark:text-slate-100 outline-none focus:ring-1 focus:ring-sky-400/40';
      const val = props.value;
      function emitCommit() {
        const el = elRef.value;
        if (!el) { emit('commit', null); return; }
        const raw = (el as HTMLInputElement | HTMLSelectElement).value;
        if (props.dataType === 'multi_select') {
          const parts = raw.split(',').map((s) => s.trim()).filter(Boolean);
          emit('commit', parts.length ? parts : null);
        } else if (props.dataType === 'number') {
          const n = parseFloat(raw);
          emit('commit', raw === '' ? null : (isNaN(n) ? null : n));
        } else {
          emit('commit', raw === '' ? null : raw);
        }
      }
      const common = {
        ref: elRef,
        onKeydown: (e: KeyboardEvent) => {
          if (e.key === 'Enter') { e.preventDefault(); emitCommit(); }
          if (e.key === 'Escape') { e.stopPropagation(); emit('cancel'); }
          if (e.key === 'Tab') {
            e.preventDefault();
            emitCommit();
            if (e.shiftKey) emit('shift-tab'); else emit('tab');
          }
        },
        onBlur: emitCommit,
      };
      if (props.dataType === 'select') {
        return h('select', { ...common, class: cellClass + ' cursor-pointer appearance-none' }, [
          h('option', { value: '' }, '— select —'),
          ...props.selectOptions.map((o: string) => h('option', { value: o, selected: String(val) === o }, o)),
        ]);
      }
      if (props.dataType === 'multi_select') {
        const current = Array.isArray(val) ? val : (val ? String(val).split(',').map((s) => s.trim()) : []);
        return h('input', {
          ...common,
          type: 'text',
          value: current.join(', '),
          placeholder: 'Comma-separated values',
          class: cellClass,
          title: 'Enter values separated by commas',
        });
      }
      if (props.dataType === 'rating') {
        const cur = val ? Number(val) : 0;
        const display = hoverStar.value || cur;
        return h('span', {
          class: 'inline-flex items-center gap-0.5 px-1 leading-none outline-none',
          tabIndex: 0,
          onKeydown: (e: KeyboardEvent) => { if (e.key === 'Escape') { e.stopPropagation(); emit('cancel'); } },
          onMouseleave: () => { hoverStar.value = 0; },
        }, [1,2,3,4,5].map((i) => h('button', {
          key: i,
          type: 'button',
          class: 'text-xl leading-none transition-colors focus:outline-none ' + (i <= display ? 'text-amber-400' : 'text-slate-200 dark:text-slate-700'),
          onMouseenter: () => { hoverStar.value = i; },
          onMousedown: (e: MouseEvent) => e.preventDefault(),
          onClick: () => emit('commit', i === cur ? null : i),
        }, '★')));
      }
      const inputType = props.dataType === 'number' ? 'number'
        : props.dataType === 'date' ? 'date'
        : props.dataType === 'email' ? 'email'
        : props.dataType === 'phone' ? 'tel'
        : props.dataType === 'url' ? 'url'
        : 'text';
      return h('input', { ...common, type: inputType, value: val != null ? String(val) : '', class: cellClass });
    };
  },
});

const CrmFieldInput = defineComponent({
  props: {
    value: { type: [String, Number, Boolean, Array, null] as unknown as () => string | number | boolean | string[] | null, default: null },
    dataType: { type: String as () => DataType, required: true },
    readOnly: { type: Boolean, default: false },
    selectOptions: { type: Array as () => string[], default: () => [] },
    optionColors: { type: Object as () => Record<string, string>, default: () => ({}) },
    format: { type: String as () => FieldFormat, default: undefined },
  },
  emits: ['update:value'],
  setup(props, { emit }) {
    return () => {
      const baseClass = 'w-full rounded-lg px-3 py-2 text-sm border bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-900 dark:text-slate-100';
      const val = props.value;
      if (props.dataType === 'rating') {
        const cur = val ? Number(val) : 0;
        return h('div', { class: 'flex items-center gap-1 py-1' },
          [1,2,3,4,5].map((i) => h('button', {
            key: i,
            type: 'button',
            class: 'text-2xl leading-none transition-colors focus:outline-none ' + (i <= cur ? 'text-amber-400' : 'text-slate-200 dark:text-slate-700')
              + (props.readOnly ? ' cursor-default' : ' hover:text-amber-300 cursor-pointer'),
            disabled: props.readOnly,
            onClick: props.readOnly ? undefined : () => emit('update:value', i === cur ? null : i),
          }, '★')),
        );
      }
      if (props.dataType === 'multi_select') {
        const current: string[] = Array.isArray(val) ? val : (val ? String(val).split(',').map((s) => s.trim()).filter(Boolean) : []);
        if (props.readOnly) {
          if (!current.length) return h('span', { class: 'text-slate-300 dark:text-slate-600 text-sm' }, '—');
          return h('span', { class: 'flex flex-wrap gap-1' },
            current.map((tag) => {
              const hex = props.optionColors[tag];
              return h('span', {
                key: tag,
                class: hex ? 'inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium' : 'inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium bg-sky-50 dark:bg-sky-950/40 text-sky-700 dark:text-sky-300 border border-sky-200 dark:border-sky-800',
                style: hex ? { background: hex + '26', color: hex } : undefined,
              }, tag);
            }),
          );
        }
        return h('div', { class: 'flex flex-wrap gap-1.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 px-3 py-2' }, [
          ...props.selectOptions.map((opt) => {
            const checked = current.includes(opt);
            return h('label', {
              key: opt,
              class: 'inline-flex items-center gap-1.5 cursor-pointer select-none',
            }, [
              h('div', {
                class: `h-4 w-4 rounded border-2 flex-shrink-0 flex items-center justify-center ${checked ? 'bg-sky-500 border-sky-500' : 'border-slate-300 dark:border-slate-600'}`,
                onClick: () => {
                  const next = checked ? current.filter((x) => x !== opt) : [...current, opt];
                  emit('update:value', next.length ? next : null);
                },
              }, checked ? h('svg', { class: 'h-2.5 w-2.5 text-white', fill: 'none', stroke: 'currentColor', viewBox: '0 0 24 24', 'stroke-width': '3' },
                [h('path', { 'stroke-linecap': 'round', 'stroke-linejoin': 'round', d: 'M5 13l4 4L19 7' })]) : null),
              h('span', { class: 'text-sm text-slate-700 dark:text-slate-300' }, opt),
            ]);
          }),
        ]);
      }
      if (props.dataType === 'boolean') {
        return h('div', {
          class: 'flex items-center gap-2 py-1' + (props.readOnly ? '' : ' cursor-pointer select-none'),
          onClick: props.readOnly ? undefined : () => emit('update:value', !val),
        }, [
          h('div', {
            class: `h-5 w-5 rounded border-2 flex items-center justify-center ${val ? 'bg-sky-500 border-sky-500' : 'border-slate-300 dark:border-slate-600'}`,
          }, val ? h('svg', { class: 'h-3 w-3 text-white', fill: 'none', stroke: 'currentColor', viewBox: '0 0 24 24', 'stroke-width': '3' },
            [h('path', { 'stroke-linecap': 'round', 'stroke-linejoin': 'round', d: 'M5 13l4 4L19 7' })]) : null),
          h('span', { class: 'text-sm text-slate-700 dark:text-slate-300' }, val ? 'Yes' : 'No'),
        ]);
      }
      if (props.dataType === 'select') {
        const opts = props.selectOptions;
        if (props.readOnly) {
          if (val == null || val === '') {
            return h('span', { class: 'text-slate-300 dark:text-slate-600 text-sm' }, '—');
          }
          const optStyle2 = getOptionStyle({ select_option_colors: props.optionColors } as CrmField, String(val));
          return h('span', {
            class: optStyle2 ? 'inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium' : 'inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ' + selectBadgeClass(String(val)),
            style: optStyle2,
          }, String(val));
        }
        return h('select', {
          class: baseClass + ' appearance-none cursor-pointer',
          onChange: (e: Event) => emit('update:value', (e.target as HTMLSelectElement).value || null),
        }, [
          h('option', { value: '' }, '— select —'),
          ...opts.map((o) => h('option', { value: o, selected: String(val) === o }, o)),
        ]);
      }
      if (props.readOnly && (props.dataType === 'email' || props.dataType === 'phone' || props.dataType === 'url')) {
        if (val == null || val === '') {
          return h('span', { class: baseClass + ' opacity-60 cursor-default inline-flex items-center' }, '—');
        }
        const href = props.dataType === 'email' ? 'mailto:' + String(val)
          : props.dataType === 'phone' ? 'tel:' + String(val)
          : String(val).startsWith('http') ? String(val) : 'https://' + String(val);
        return h('a', {
          href,
          target: props.dataType === 'url' ? '_blank' : undefined,
          rel: props.dataType === 'url' ? 'noopener noreferrer' : undefined,
          class: baseClass + ' text-sky-600 dark:text-sky-400 hover:underline inline-flex items-center opacity-90',
        }, String(val));
      }
      if (props.readOnly && props.dataType === 'date') {
        const fmt = val != null && val !== ''
          ? new Date(String(val)).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
          : '';
        return h('input', {
          type: 'text',
          value: fmt,
          readonly: true,
          class: baseClass + ' opacity-80 cursor-default',
        });
      }
      if (props.readOnly && props.dataType === 'number' && props.format) {
        if (props.format === 'progress') {
          const pct = val != null ? Math.max(0, Math.min(100, Number(val))) : 0;
          const color = pct >= 70 ? '#10b981' : pct >= 40 ? '#f59e0b' : '#ef4444';
          return h('div', { class: 'space-y-1.5 py-1' }, [
            h('div', { class: 'flex items-center justify-between text-xs' }, [
              h('span', { class: 'text-slate-400 dark:text-slate-500' }, val == null ? '—' : ''),
              h('span', { class: 'font-semibold tabular-nums', style: `color:${color}` }, val != null ? pct + '%' : '—'),
            ]),
            val != null ? h('div', { class: 'h-2 rounded-full bg-slate-100 dark:bg-slate-800 overflow-hidden' }, [
              h('div', { class: 'h-full rounded-full transition-all', style: `width:${pct}%;background:${color}` }),
            ]) : null,
          ]);
        }
        let displayVal = '';
        if (val != null && val !== '') {
          const n = Number(val);
          if (props.format === 'currency') {
            displayVal = '$' + n.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
          } else if (props.format === 'percent') {
            displayVal = n + '%';
          }
        }
        return h('input', {
          type: 'text',
          value: displayVal,
          readonly: true,
          class: baseClass + ' opacity-80 cursor-default tabular-nums',
        });
      }
      if (!props.readOnly && props.dataType === 'number' && props.format === 'progress') {
        const pct = val != null ? Math.max(0, Math.min(100, Number(val))) : 0;
        const color = pct >= 70 ? '#10b981' : pct >= 40 ? '#f59e0b' : '#ef4444';
        return h('div', { class: 'space-y-2' }, [
          h('div', { class: 'flex items-center gap-3' }, [
            h('input', {
              type: 'range', min: 0, max: 100, step: 1,
              value: pct,
              class: 'flex-1 accent-sky-500 cursor-pointer',
              onInput: (e: Event) => emit('update:value', Number((e.target as HTMLInputElement).value)),
            }),
            h('span', { class: 'text-sm font-semibold tabular-nums w-10 text-right shrink-0', style: `color:${color}` }, pct + '%'),
          ]),
          h('div', { class: 'h-1.5 rounded-full bg-slate-100 dark:bg-slate-800 overflow-hidden' }, [
            h('div', { class: 'h-full rounded-full transition-all', style: `width:${pct}%;background:${color}` }),
          ]),
        ]);
      }
      if (props.dataType === 'date' && !props.readOnly) {
        const datePresets = [
          { label: 'Today', v: DUE_TODAY_STR },
          { label: 'Tomorrow', v: dateOffset(1) },
          { label: '+1 wk', v: dateOffset(7) },
          { label: '+1 mo', v: dateOffset(30) },
        ];
        const curDateStr = val != null ? String(val) : '';
        return h('div', { class: 'space-y-1.5' }, [
          h('div', { class: 'flex gap-1 flex-wrap' },
            datePresets.map((p) => h('button', {
              key: p.label,
              type: 'button',
              class: 'text-[10px] px-1.5 py-0.5 rounded border transition-colors '
                + (curDateStr === p.v
                  ? 'bg-sky-500 border-sky-500 text-white'
                  : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:border-sky-400 hover:text-sky-600 dark:hover:text-sky-400'),
              onClick: () => emit('update:value', curDateStr === p.v ? null : p.v),
            }, p.label)),
          ),
          h('input', {
            type: 'date',
            value: curDateStr,
            class: baseClass,
            onInput: (e: Event) => {
              const raw = (e.target as HTMLInputElement).value;
              emit('update:value', raw === '' ? null : raw);
            },
          }),
        ]);
      }
      const inputType = props.dataType === 'number' ? 'number'
        : props.dataType === 'date' ? 'date'
        : props.dataType === 'email' ? 'email'
        : props.dataType === 'phone' ? 'tel'
        : props.dataType === 'url' ? 'url'
        : 'text';
      return h('input', {
        type: inputType,
        value: val != null ? String(val) : '',
        readonly: props.readOnly,
        class: baseClass + (props.readOnly ? ' opacity-80 cursor-default' : ''),
        onInput: props.readOnly ? undefined : (e: Event) => {
          const raw = (e.target as HTMLInputElement).value;
          emit('update:value', props.dataType === 'number' ? (raw === '' ? null : Number(raw)) : raw);
        },
      });
    };
  },
});
</script>
